import { SpacesClient } from './spaces-client'
import {
  type BehaviourEvent,
  BehaviourEventType,
  type SessionSummary,
} from './types'

export interface DailyAnalysis {
  date: string
  totalSessions: number
  totalEvents: number
  intentsByCount: Record<string, number>
  modesByCount: Record<string, number>
  appsByCount: Record<string, number>
  /** Hours (0ÔÇô23) with the maximum event count; sorted ascending. */
  peakHours: number[]
}

export class BehaviourAnalyser {
  private readonly spaces: SpacesClient

  constructor(spaces: SpacesClient) {
    this.spaces = spaces
  }

  /**
   * Fetch and parse all BehaviourEvent JSONL files for a given date.
   * @param date "YYYY-MM-DD"
   */
  async loadEventsForDate(date: string): Promise<BehaviourEvent[]> {
    if (!this.spaces.isEnabled()) {
      return []
    }

    const prefix = `behaviour/${date}/`
    let keys: string[] = []
    try {
      keys = await this.spaces.listObjectKeys(prefix)
    } catch (err) {
      console.warn('[BehaviourAnalyser] listObjectKeys failed', err)
      return []
    }

    const jsonlKeys = keys.filter((k) => k.endsWith('.jsonl'))
    const all: BehaviourEvent[] = []

    for (const key of jsonlKeys) {
      let body: string | null = null
      try {
        body = await this.spaces.getObjectString(key)
      } catch (err) {
        console.warn('[BehaviourAnalyser] getObjectString failed', key, err)
        continue
      }
      if (body === null || body === '') {
        continue
      }
      const lines = body.split('\n')
      for (const line of lines) {
        const trimmed = line.trim()
        if (!trimmed) {
          continue
        }
        try {
          const ev = JSON.parse(trimmed) as BehaviourEvent
          all.push(ev)
        } catch (err) {
          console.warn('[BehaviourAnalyser] JSON parse error', key, err)
        }
      }
    }

    return all
  }

  /**
   * Compute a DailyAnalysis object from a list of BehaviourEvent.
   */
  computeDailyAnalysis(date: string, events: BehaviourEvent[]): DailyAnalysis {
    const sessionIds = new Set<string>()
    for (const e of events) {
      if (e.sessionId) {
        sessionIds.add(e.sessionId)
      }
    }

    const intentsByCount: Record<string, number> = {}
    for (const e of events) {
      if (e.eventType === BehaviourEventType.INTENT_RESOLVED && e.intent) {
        const k = e.intent
        intentsByCount[k] = (intentsByCount[k] ?? 0) + 1
      }
    }

    const modesByCount: Record<string, number> = {}
    for (const e of events) {
      if (e.agentMode) {
        const k = e.agentMode
        modesByCount[k] = (modesByCount[k] ?? 0) + 1
      }
    }

    const appsByCount: Record<string, number> = {}
    for (const e of events) {
      if (e.app) {
        const k = e.app
        appsByCount[k] = (appsByCount[k] ?? 0) + 1
      }
    }

    const hourCounts = new Array<number>(24).fill(0)
    for (const e of events) {
      const h = new Date(e.timestamp).getHours()
      if (h >= 0 && h <= 23) {
        hourCounts[h] += 1
      }
    }

    let peakHours: number[] = []
    if (events.length > 0) {
      const max = Math.max(...hourCounts)
      for (let h = 0; h < 24; h += 1) {
        if (hourCounts[h] === max) {
          peakHours.push(h)
        }
      }
    }

    return {
      date,
      totalSessions: sessionIds.size,
      totalEvents: events.length,
      intentsByCount,
      modesByCount,
      appsByCount,
      peakHours,
    }
  }

  /**
   * Recompute a SessionSummary from events (same rules as BehaviourLogger.endSession).
   */
  computeSessionSummary(
    _sessionId: string,
    startTime: number,
    endTime: number,
    events: BehaviourEvent[],
  ): SessionSummary {
    const intentsResolved = Array.from(
      new Set(
        events
          .filter((e) => e.eventType === BehaviourEventType.INTENT_RESOLVED && e.intent)
          .map((e) => e.intent as string),
      ),
    )
    const modesUsed = Array.from(
      new Set(events.filter((e) => e.agentMode).map((e) => e.agentMode as string)),
    )
    const goalsCompleted = events.filter((e) => e.eventType === BehaviourEventType.GOAL_COMPLETED)
      .length
    const goalsFailed = events.filter((e) => e.eventType === BehaviourEventType.GOAL_FAILED).length

    let mostActiveApp: string | null = null
    if (events.length) {
      const counts = new Map<string, number>()
      for (const e of events) {
        if (!e.app) {
          continue
        }
        counts.set(e.app, (counts.get(e.app) ?? 0) + 1)
      }
      let topApp: string | null = null
      let topCount = 0
      for (const [app, count] of counts.entries()) {
        if (count > topCount) {
          topCount = count
          topApp = app
        }
      }
      mostActiveApp = topApp
    }

    return {
      totalEvents: events.length,
      intentsResolved,
      modesUsed,
      goalsCompleted,
      goalsFailed,
      mostActiveApp,
      durationMinutes: (endTime - startTime) / 60_000,
    }
  }

  /**
   * Save the daily analysis to Spaces.
   * Key: `analysis/daily/{date}.json`
   */
  async saveDailyAnalysis(analysis: DailyAnalysis): Promise<void> {
    if (!this.spaces.isEnabled()) {
      return
    }
    const key = `analysis/daily/${analysis.date}.json`
    await this.spaces.upload(key, JSON.stringify(analysis, null, 2))
  }

  /**
   * Load events for the date, compute daily analysis, save, return.
   */
  async analyseDate(date: string): Promise<DailyAnalysis> {
    const events = await this.loadEventsForDate(date)
    const analysis = this.computeDailyAnalysis(date, events)
    await this.saveDailyAnalysis(analysis)
    return analysis
  }
}

import { v4 as uuidv4 } from 'uuid'

import { SpacesClient } from './spaces-client'
import {
  type BehaviourEvent,
  BehaviourEventType,
  type BehaviourSession,
  type SessionSummary,
} from './types'

/** Minimal bus surface: Node `EventEmitter`, `eventemitter3`, or any compatible implementation. */
export interface BehaviourBus {
  on(event: string, listener: (...args: unknown[]) => void): void
  off(event: string, listener: (...args: unknown[]) => void): void
}

/**
 * Records orchestrator events to a buffer, flushes JSONL to Spaces, and uploads a session summary on end.
 */
export class BehaviourLogger {
  private readonly emitter: BehaviourBus
  private readonly spaces: SpacesClient
  private readonly sessionId: string
  private readonly sessionStart: number
  private lastEventTime: number
  private buffer: BehaviourEvent[]
  /** Full session history (survives periodic {@link flush}). */
  private readonly allSessionEvents: BehaviourEvent[] = []
  private flushTimer: ReturnType<typeof setInterval> | null
  private closed: boolean
  private listenersAttached = false

  constructor(emitter: BehaviourBus, spaces: SpacesClient) {
    this.emitter = emitter
    this.spaces = spaces
    this.sessionId = uuidv4()
    this.sessionStart = Date.now()
    this.lastEventTime = this.sessionStart
    this.buffer = []
    this.flushTimer = null
    this.closed = false
  }

  init(): void {
    if (this.listenersAttached) {
      return
    }

    this.record({
      eventType: BehaviourEventType.SESSION_START,
      app: null,
      intent: null,
      rawText: null,
      agentMode: null,
      outcome: null,
      metadata: {},
    })

    this.emitter.on('intent:resolved', this.onIntentResolved)
    this.emitter.on('jarvis:speak', this.onJarvisSpeak)
    this.emitter.on('screen:change', this.onScreenChange)
    this.emitter.on('screen:mode_changed', this.onScreenModeChanged)
    this.emitter.on('goal:started', this.onGoalStarted)
    this.emitter.on('goal:completed', this.onGoalCompleted)
    this.emitter.on('goal:failed', this.onGoalFailed)

    this.listenersAttached = true

    this.flushTimer = setInterval(() => {
      void this.flush()
    }, 60_000)
  }

  private detachListeners(): void {
    if (!this.listenersAttached) {
      return
    }
    this.emitter.off('intent:resolved', this.onIntentResolved)
    this.emitter.off('jarvis:speak', this.onJarvisSpeak)
    this.emitter.off('screen:change', this.onScreenChange)
    this.emitter.off('screen:mode_changed', this.onScreenModeChanged)
    this.emitter.off('goal:started', this.onGoalStarted)
    this.emitter.off('goal:completed', this.onGoalCompleted)
    this.emitter.off('goal:failed', this.onGoalFailed)
    this.listenersAttached = false
  }

  private readonly onIntentResolved = (payload: unknown): void => {
    const p = payload as {
      intent?: string
      rawText?: string
      utterance?: string
      entities?: Record<string, unknown>
    }
    this.record({
      eventType: BehaviourEventType.INTENT_RESOLVED,
      intent: p?.intent ?? null,
      rawText: p?.rawText ?? p?.utterance ?? null,
      agentMode: null,
      app: null,
      outcome: null,
      metadata: { entities: p?.entities ?? {} },
    })
  }

  private readonly onJarvisSpeak = (payload: unknown): void => {
    const p = payload as { text?: string; priority?: string }
    this.record({
      eventType: BehaviourEventType.ADVICE_GIVEN,
      intent: null,
      rawText: null,
      agentMode: null,
      app: null,
      outcome: null,
      metadata: {
        text: p?.text ?? '',
        priority: p?.priority ?? 'normal',
      },
    })
  }

  private readonly onScreenChange = (event: unknown): void => {
    const ev = event as {
      windowTitle?: string | null
      activeApp?: string | null
      context?: { windowTitle?: string | null }
      significance?: number | null
    }
    const fromTitle = ev?.windowTitle || ev?.context?.windowTitle || null
    const fromActive =
      typeof ev?.activeApp === 'string' && ev.activeApp.length > 0 ? ev.activeApp : null
    const app = fromTitle || fromActive
    this.record({
      eventType: BehaviourEventType.SCREEN_CHANGE,
      app: typeof app === 'string' && app.length > 0 ? app : null,
      intent: null,
      rawText: null,
      agentMode: null,
      outcome: null,
      metadata: { significance: ev?.significance ?? null },
    })
  }

  private readonly onScreenModeChanged = (mode: unknown): void => {
    let agentMode: string | null = null
    if (typeof mode === 'string') {
      agentMode = mode
    } else if (mode !== null && typeof mode === 'object') {
      const o = mode as { newMode?: string; mode?: string }
      if (typeof o.newMode === 'string') {
        agentMode = o.newMode
      } else if (typeof o.mode === 'string') {
        agentMode = o.mode
      }
    }
    this.record({
      eventType: BehaviourEventType.MODE_CHANGED,
      app: null,
      intent: null,
      rawText: null,
      agentMode,
      outcome: null,
      metadata: {},
    })
  }

  private readonly onGoalStarted = (payload: unknown): void => {
    const p = payload as { goal?: string }
    this.record({
      eventType: BehaviourEventType.GOAL_STARTED,
      app: null,
      intent: 'jarvis.screen.act',
      rawText: null,
      agentMode: 'ACT',
      outcome: 'pending',
      metadata: { goal: p?.goal ?? null },
    })
  }

  private readonly onGoalCompleted = (payload: unknown): void => {
    const p = payload as { stepsCompleted?: number }
    this.record({
      eventType: BehaviourEventType.GOAL_COMPLETED,
      app: null,
      intent: 'jarvis.screen.act',
      rawText: null,
      agentMode: 'ACT',
      outcome: 'success',
      metadata: { stepsCompleted: p?.stepsCompleted ?? null },
    })
  }

  private readonly onGoalFailed = (payload: unknown): void => {
    const p = payload as { reason?: string; failureReason?: string; stepsCompleted?: number }
    const reason = p?.reason ?? p?.failureReason ?? null
    this.record({
      eventType: BehaviourEventType.GOAL_FAILED,
      app: null,
      intent: 'jarvis.screen.act',
      rawText: null,
      agentMode: 'ACT',
      outcome: 'failure',
      metadata: {
        reason,
        stepsCompleted: p?.stepsCompleted ?? null,
      },
    })
  }

  private buildEvent(partial: Partial<BehaviourEvent>): BehaviourEvent {
    const now = Date.now()
    const duration = now - this.lastEventTime

    const d = new Date(now)
    const hh = String(d.getHours()).padStart(2, '0')
    const mm = String(d.getMinutes()).padStart(2, '0')

    const event: BehaviourEvent = {
      sessionId: this.sessionId,
      timestamp: now,
      timeOfDay: `${hh}:${mm}`,
      dayOfWeek: d.getDay(),
      app: partial.app ?? null,
      eventType: partial.eventType!,
      intent: partial.intent ?? null,
      rawText: partial.rawText ?? null,
      agentMode: partial.agentMode ?? null,
      durationMs: partial.durationMs ?? duration,
      outcome: partial.outcome ?? null,
      metadata: partial.metadata ?? {},
    }

    this.lastEventTime = now
    return event
  }

  record(partial: Partial<BehaviourEvent>): void {
    if (this.closed) {
      return
    }
    if (!partial.eventType) {
      return
    }
    const evt = this.buildEvent(partial)
    this.buffer.push(evt)
    this.allSessionEvents.push(evt)
  }

  async flush(): Promise<void> {
    if (!this.buffer.length) {
      return
    }
    const events = [...this.buffer]
    this.buffer = []

    const day = new Date(this.sessionStart)
    const yyyy = day.getFullYear()
    const mm = String(day.getMonth() + 1).padStart(2, '0')
    const dd = String(day.getDate()).padStart(2, '0')

    const key = `behaviour/${yyyy}-${mm}-${dd}/${this.sessionId}.jsonl`
    const lines = events.map((e) => JSON.stringify(e)).join('\n')

    await this.spaces.append(key, lines)
  }

  async endSession(): Promise<void> {
    if (this.closed) {
      return
    }

    if (this.flushTimer !== null) {
      clearInterval(this.flushTimer)
      this.flushTimer = null
    }

    this.detachListeners()

    this.record({
      eventType: BehaviourEventType.SESSION_END,
      app: null,
      intent: null,
      rawText: null,
      agentMode: null,
      outcome: null,
      metadata: {},
    })

    this.closed = true

    const endTime = Date.now()
    const allEvents = [...this.allSessionEvents]

    const summary: SessionSummary = {
      totalEvents: allEvents.length,
      intentsResolved: Array.from(
        new Set(
          allEvents
            .filter((e) => e.eventType === BehaviourEventType.INTENT_RESOLVED && e.intent)
            .map((e) => e.intent as string),
        ),
      ),
      modesUsed: Array.from(
        new Set(allEvents.filter((e) => e.agentMode).map((e) => e.agentMode as string)),
      ),
      goalsCompleted: allEvents.filter((e) => e.eventType === BehaviourEventType.GOAL_COMPLETED)
        .length,
      goalsFailed: allEvents.filter((e) => e.eventType === BehaviourEventType.GOAL_FAILED).length,
      mostActiveApp: null,
      durationMinutes: (endTime - this.sessionStart) / 60_000,
    }

    if (allEvents.length) {
      const counts = new Map<string, number>()
      for (const e of allEvents) {
        if (!e.app) {
          continue
        }
        counts.set(e.app, (counts.get(e.app) ?? 0) + 1)
      }
      let topApp: string | null = null
      let topCount = 0
      for (const [app, count] of counts.entries()) {
        if (count > topCount) {
          topCount = count
          topApp = app
        }
      }
      summary.mostActiveApp = topApp
    }

    const session: BehaviourSession = {
      sessionId: this.sessionId,
      startTime: this.sessionStart,
      endTime,
      events: allEvents,
      summary,
    }

    const day = new Date(this.sessionStart)
    const yyyy = day.getFullYear()
    const mm = String(day.getMonth() + 1).padStart(2, '0')
    const dd = String(day.getDate()).padStart(2, '0')

    const summaryKey = `behaviour/sessions/${yyyy}-${mm}-${dd}/${this.sessionId}-summary.json`

    await this.spaces.upload(summaryKey, JSON.stringify(session, null, 2))
    await this.flush()
  }

  getSessionId(): string {
    return this.sessionId
  }
}

import type { DailyAnalysis } from './behaviour-analyser'
import { BehaviourAnalyser } from './behaviour-analyser'
import { SpacesClient } from './spaces-client'
import { type BehaviourEvent, BehaviourEventType } from './types'

export interface PredictContext {
  recentIntents: string[]
  activeApp?: string | null
  timeOfDay: 'morning' | 'afternoon' | 'evening' | 'night'
  dayOfWeek: number
}

export interface PredictResult {
  predictedIntent: string | null
  confidence: number
  reasons: string[]
}

export interface IntentPredictorConfig {
  maxRecentIntents: number
  weightSingleTransition: number
  weightPairTransition: number
  weightTimePrior: number
  weightAppPrior: number
  minConfidence: number
  maxConfidence: number
  daysToLoad: number
}

/** Map hour 0ÔÇô23 to coarse bucket (local time of event timestamps). */
export function hourToTimeOfDay(hour: number): PredictContext['timeOfDay'] {
  if (hour >= 5 && hour < 12) {
    return 'morning'
  }
  if (hour >= 12 && hour < 18) {
    return 'afternoon'
  }
  if (hour >= 18 && hour < 22) {
    return 'evening'
  }
  return 'night'
}

function addCount(m: Map<string, number>, k: string, n = 1): void {
  m.set(k, (m.get(k) ?? 0) + n)
}

function normalizeSubMap(m: Map<string, number>, key: string): number {
  let t = 0
  for (const v of m.values()) {
    t += v
  }
  if (t === 0) {
    return 0
  }
  return (m.get(key) ?? 0) / t
}

function datesLastNDays(n: number): string[] {
  const out: string[] = []
  const now = new Date()
  for (let i = 0; i < n; i += 1) {
    const d = new Date(now)
    d.setUTCDate(d.getUTCDate() - i)
    const y = d.getUTCFullYear()
    const m = String(d.getUTCMonth() + 1).padStart(2, '0')
    const day = String(d.getUTCDate()).padStart(2, '0')
    out.push(`${y}-${m}-${day}`)
  }
  return out
}

export class IntentPredictor {
  private readonly spaces: SpacesClient
  private readonly config: IntentPredictorConfig

  private dailyAnalyses: DailyAnalysis[] = []
  private singleTransitions: Map<string, Map<string, number>> = new Map()
  private pairTransitions: Map<string, Map<string, number>> = new Map()
  /** timeOfDay bucket -> intent -> count */
  private timeBucketIntentCounts: Map<PredictContext['timeOfDay'], Map<string, number>> = new Map()
  /** app label -> intent -> count (intent seen while app was last active from screen:change) */
  private appIntentCounts: Map<string, Map<string, number>> = new Map()

  constructor(spaces: SpacesClient, config: IntentPredictorConfig) {
    this.spaces = spaces
    this.config = config
  }

  async refresh(): Promise<void> {
    if (!this.spaces.isEnabled()) {
      return
    }

    this.dailyAnalyses = []
    this.singleTransitions = new Map()
    this.pairTransitions = new Map()
    this.timeBucketIntentCounts = new Map()
    this.appIntentCounts = new Map()

    const dates = datesLastNDays(this.config.daysToLoad)
    const analyser = new BehaviourAnalyser(this.spaces)

    for (const date of dates) {
      try {
        const body = await this.spaces.getObjectString(`analysis/daily/${date}.json`)
        if (body) {
          const da = JSON.parse(body) as DailyAnalysis
          this.dailyAnalyses.push(da)
        }
      } catch (err) {
        console.warn('[IntentPredictor] failed to parse daily analysis', date, err)
      }

      let events: BehaviourEvent[] = []
      try {
        events = await analyser.loadEventsForDate(date)
      } catch (err) {
        console.warn('[IntentPredictor] loadEventsForDate failed', date, err)
        continue
      }

      this.ingestEventsForModels(events)
    }
  }

  /** Build transition maps and priors from chronological session streams. */
  private ingestEventsForModels(events: BehaviourEvent[]): void {
    const bySession = new Map<string, BehaviourEvent[]>()
    for (const e of events) {
      const sid = e.sessionId
      if (!bySession.has(sid)) {
        bySession.set(sid, [])
      }
      bySession.get(sid)!.push(e)
    }

    for (const list of bySession.values()) {
      list.sort((a, b) => a.timestamp - b.timestamp)

      const intents: string[] = []
      let lastApp: string | null = null

      for (const e of list) {
        if (e.eventType === BehaviourEventType.SCREEN_CHANGE && e.app) {
          lastApp = e.app
        }
        if (e.eventType === BehaviourEventType.INTENT_RESOLVED && e.intent) {
          const intent = e.intent
          const hour = new Date(e.timestamp).getHours()
          const bucket = hourToTimeOfDay(hour)
          if (!this.timeBucketIntentCounts.has(bucket)) {
            this.timeBucketIntentCounts.set(bucket, new Map())
          }
          addCount(this.timeBucketIntentCounts.get(bucket)!, intent)

          if (lastApp) {
            if (!this.appIntentCounts.has(lastApp)) {
              this.appIntentCounts.set(lastApp, new Map())
            }
            addCount(this.appIntentCounts.get(lastApp)!, intent)
          }

          intents.push(intent)
        }
      }

      for (let i = 0; i < intents.length - 1; i += 1) {
        const a = intents[i]!
        const b = intents[i + 1]!
        if (!this.singleTransitions.has(a)) {
          this.singleTransitions.set(a, new Map())
        }
        addCount(this.singleTransitions.get(a)!, b)
      }

      for (let i = 0; i < intents.length - 2; i += 1) {
        const a = intents[i]!
        const b = intents[i + 1]!
        const c = intents[i + 2]!
        const pairKey = `${a}|${b}`
        if (!this.pairTransitions.has(pairKey)) {
          this.pairTransitions.set(pairKey, new Map())
        }
        addCount(this.pairTransitions.get(pairKey)!, c)
      }
    }
  }

  predict(context: PredictContext): PredictResult {
    if (!this.spaces.isEnabled()) {
      return {
        predictedIntent: null,
        confidence: 0,
        reasons: ['Spaces disabled'],
      }
    }

    const all = context.recentIntents ?? []
    const recent = all.slice(-this.config.maxRecentIntents)

    const hasAnyPrior =
      this.singleTransitions.size > 0 ||
      this.pairTransitions.size > 0 ||
      this.timeBucketIntentCounts.size > 0 ||
      this.appIntentCounts.size > 0 ||
      this.dailyAnalyses.length > 0

    if (recent.length === 0 || !hasAnyPrior) {
      return {
        predictedIntent: null,
        confidence: 0,
        reasons: ['Not enough history'],
      }
    }

    const last = recent[recent.length - 1]!
    const prev = recent.length >= 2 ? recent[recent.length - 2]! : null
    const pairKey = prev !== null ? `${prev}|${last}` : null
    const activeApp = context.activeApp

    const candidates = new Set<string>()
    const singleMap = this.singleTransitions.get(last)
    if (singleMap) {
      for (const k of singleMap.keys()) {
        candidates.add(k)
      }
    }
    if (pairKey) {
      const pairMap = this.pairTransitions.get(pairKey)
      if (pairMap) {
        for (const k of pairMap.keys()) {
          candidates.add(k)
        }
      }
    }
    for (const da of this.dailyAnalyses) {
      for (const k of Object.keys(da.intentsByCount)) {
        candidates.add(k)
      }
    }

    const tbCandidates = this.timeBucketIntentCounts.get(context.timeOfDay)
    if (tbCandidates) {
      for (const k of tbCandidates.keys()) {
        candidates.add(k)
      }
    }
    if (activeApp) {
      const appMap = this.appIntentCounts.get(activeApp)
      if (appMap) {
        for (const k of appMap.keys()) {
          candidates.add(k)
        }
      }
    }

    if (candidates.size === 0) {
      return {
        predictedIntent: null,
        confidence: 0,
        reasons: ['No signal'],
      }
    }

    const w1 = this.config.weightSingleTransition
    const w2 = this.config.weightPairTransition
    const w3 = this.config.weightTimePrior
    const w4 = this.config.weightAppPrior

    const scored: { intent: string; score: number; trans1: number; trans2: number; timeP: number; appP: number }[] = []

    for (const candidate of candidates) {
      const trans1 = singleMap ? normalizeSubMap(singleMap, candidate) : 0

      let trans2 = 0
      if (pairKey) {
        const pm = this.pairTransitions.get(pairKey)
        if (pm) {
          trans2 = normalizeSubMap(pm, candidate)
        }
      }

      const tb = this.timeBucketIntentCounts.get(context.timeOfDay)
      const timePrior = tb ? normalizeSubMap(tb, candidate) : 0

      let appPrior = 0
      if (activeApp) {
        const am = this.appIntentCounts.get(activeApp)
        if (am) {
          appPrior = normalizeSubMap(am, candidate)
        }
      }

      const score = w1 * trans1 + w2 * trans2 + w3 * timePrior + w4 * appPrior
      scored.push({ intent: candidate, score, trans1, trans2, timeP: timePrior, appP: appPrior })
    }

    scored.sort((a, b) => b.score - a.score)
    const best = scored[0]!
    if (best.score <= 0 || !Number.isFinite(best.score)) {
      return {
        predictedIntent: null,
        confidence: 0,
        reasons: ['No signal'],
      }
    }

    const sumOtherScores = scored.slice(1).reduce((s, x) => s + x.score, 0)
    const denom = best.score + sumOtherScores
    const confidenceRaw = denom > 0 ? best.score / denom : 0

    const c = Math.max(
      this.config.minConfidence,
      Math.min(this.config.maxConfidence, confidenceRaw),
    )

    const reasons: string[] = []
    const t = (n: number) => n > 0.001
    if (t(best.trans1)) {
      reasons.push(`Often follows last intent (${last})`)
    }
    if (t(best.trans2) && pairKey) {
      reasons.push('Often follows the last two intents')
    }
    if (t(best.timeP)) {
      reasons.push('Common at this time of day')
    }
    if (t(best.appP) && activeApp) {
      reasons.push(`Common when ${activeApp} is active`)
    }
    if (reasons.length === 0) {
      reasons.push('Weak aggregate signal')
    }

    return {
      predictedIntent: best.intent,
      confidence: c,
      reasons,
    }
  }
}

/**
 * Coordinates {@link ManagerAgent}, {@link WorkerAgent}, and {@link ReflexionController} for the Jarvis ManagerÔÇôWorker flow.
 */

import ManagerAgent from './managerAgent'
import WorkerAgent, { type WorkerResult } from './workerAgent'
import type { TaskState, TaskType } from './taskState'
import type { RouteResult } from '@/lib/router/semanticRouter'
import SessionIndex from '@/memory/sessionIndex'
import { telemetry } from '@/lib/observability/telemetryCollector'
import ReflexionController, { MAX_REFLEXION_ITERATIONS } from '@/reasoning/reflexionController'
import ComplexityDetector from '@/reasoning/complexityDetector'
import { lessonsStore } from '@/reasoning/lessonsStore'
import ReActLoopController from '@/reasoning/reactLoopController'
import type { ReActTrace } from '@/reasoning/reactTypes'
import ConfidenceElicitor from '@/reasoning/confidenceElicitor'
import type { PreTaskEstimate } from '@/reasoning/confidenceTypes'
import { confidenceMemoryStore } from '@/reasoning/confidenceMemoryStore'
import { confidenceOrchestrator } from '@/reasoning/confidenceOrchestrator'
import type { ReflexionResult } from '@/reasoning/reflexionController'

const LOG = '[MWOrchestrator]'
const PRE_TASK_LOG = '[Orchestrator]'

// NOTE: These routes use ReAct (planning) + Reflexion (quality).
      }

      const briefInitial = managerDecision.brief
      if (briefInitial === undefined || briefInitial.trim().length === 0) {
        console.error(`${LOG} brief_worker action without brief`)
        return {
          type: 'standard',
          response: 'Something went wrong...',
          action: 'error',
          success: false,
          taskType,
          iterationCount: 0,
        }
      }

      let effectiveBrief = briefInitial

      // ÔöÇÔöÇÔöÇ EXECUTION ORDER ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
      // 1. Pre-task confidence gate (HERE)
      //    Fires before any API spend. shouldProceed=false exits immediately.
      //    Low confidence (<0.60) enriches the brief before continuing.
      //
      // 2. Tree of Thoughts (inside ReActEngine on first step)
      //    Selects best approach from the (possibly enriched) brief.
      //    If pre-task injected a hint, ToT still runs independently ÔÇö
      //    ToT has more context and its selection takes priority.
      //
      // 3. Worker.execute()
      //    Executes with: enriched brief + ToT-selected approach +
      //    CoT scratchpad context + Reflexion lessons
      //
      // 4. Reflexion critique (post-Worker)
      // 5. Confidence evaluation (post-Worker)
      // ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
      const preTaskEstimate = await this.runPreTaskEstimate(
        effectiveBrief,
        taskType,
        this.sessionId,
      )

      if (!preTaskEstimate.shouldProceed) {
        console.log(
          `${PRE_TASK_LOG} Pre-task gate: BLOCKED (${String(preTaskEstimate.missingInfo.length)} critical gaps)`,
        )
        // ÔöÇÔöÇ NAMING NOTE ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
        // Internal shape:  { action: 'clarified', response: '...' }
        // Frontend shape:  { metadata: { type: 'clarification_required' } }
        //
        // The orchestrator uses 'action: clarified' ÔÇö past tense, describes
        // what the system decided to do (clarify rather than execute).
        //
        // The API layer maps this to metadata.type: 'clarification_required'
        // for the frontend, which is present tense and UI-intent focused.
        //
        // Neither name is wrong ÔÇö they serve different audiences:
        //   'clarified'              ÔåÆ orchestration logic layer
        //   'clarification_required' ÔåÆ frontend rendering layer
        // ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
        const q =
          preTaskEstimate.clarifyingQuestions[0] ??
          'Could you provide more detail about the task?'
        return {
          type: 'clarification_required',
          question: q,
          response: q,
          action: 'clarified',
          success: false,
          taskType,
          iterationCount: 0,
          preTaskEstimate,
        }
      }

      if (preTaskEstimate.confidence < 0.6) {
        console.log(
          `${PRE_TASK_LOG} Pre-task confidence low (${String(preTaskEstimate.confidence)}) ÔÇö proceeding with flag`,
        )
        const missing = preTaskEstimate.missingInfo.slice(0, 2).join(', ')
        const approachHint = preTaskEstimate.suggestedApproach.length > 0 ? ` Suggested approach: ${preTaskEstimate.suggestedApproach}` : ''
        effectiveBrief += `\n\nÔÜá Pre-task note: Proceeding with limited information. Missing: ${missing}.${approachHint}`
      }

      if (preTaskEstimate.confidence >= 0.8 && preTaskEstimate.suggestedApproach.length > 0) {
        effectiveBrief += `\n\nPre-task approach hint: ${preTaskEstimate.suggestedApproach}`
      }

      const complexityAssessment = await this.complexityDetector.assess(
        `${userMessage}\n\n${effectiveBrief}`.trim().slice(0, 4000),
        taskType,
      )
      const complexityScore = complexityAssessment.score

      if (FULL_REACT_ROUTES.has(taskType)) {
        return await this._processReActRoute(userMessage, intentResult, ragContent, managerDecision, { effectiveBrief, activeBasePrompt, complexityScore, taskType })
      }
      return await this._processReflexionLoop(effectiveBrief, userMessage, activeBasePrompt, managerDecision, complexityScore, taskType)
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : String(err)
      telemetry.record(
        'error',
        this.sessionId,
        { message: msg, context: 'managerWorkerOrchestrator.process' },
        undefined,
        msg,
      )
      console.error(`${LOG} process failed`, err)
      return {
        type: 'standard',
        response: 'Something went wrong...',
        action: 'error',
        success: false,
        taskType: 'unknown',
        iterationCount: 0,
      }
    }
  }

  private async _processReActRoute(
    userMessage: string,
    intentResult: RouteResult,
    ragContent: string[],
    managerDecision: Awaited<ReturnType<ManagerAgent['processTurn']>>,
    config: { effectiveBrief: string; activeBasePrompt: string; complexityScore: number; taskType: TaskType },
  ): Promise<MWOrchestratorResult> {
    const { effectiveBrief, activeBasePrompt, complexityScore, taskType } = config
    this.reflexionController.reset()
    this._pendingConfidenceClarification = undefined

    let reActWorkerBrief = effectiveBrief

    const loopController = new ReActLoopController({
      taskType: intentResult.route,
      sessionId: this.sessionId,
      model: 'gpt-4o',
      complexityScore,
    })

    const loopResult = await loopController.run(
      {
        userMessage,
        taskType: intentResult.route,
        priorSteps: [],
        ragContent,
        taskBrief: effectiveBrief,
        iterationCount: 0,
      },
      async (decision) => {
        if (decision.action === 'execute_task') {
          const phase = await this._executeWithWorker(
            managerDecision,
            {
              brief: reActWorkerBrief,
              userMessage,
              activeBasePrompt,
              complexityScore,
              taskType: managerDecision.taskState.taskType,
            },
            0,
          )
          if (!phase.ok) {
            this._pendingConfidenceClarification = phase.clarificationQuestion
            return {
              actionType: 'execute_task',
              rawOutput: '',
              success: false,
              error: 'confidence_clarification',
            }
          }
          const workerResult = phase.workerResult
          if (!workerResult.success) {
            return {
              actionType: 'execute_task',
              rawOutput: workerResult.content,
              success: false,
              tokensUsed: workerResult.tokensUsed,
              error: workerResult.error,
            }
          }
          const reflexionResult = phase.reflexionResult
          if (reflexionResult === undefined) {
            return {
              actionType: 'execute_task',
              rawOutput: workerResult.content,
              success: true,
              tokensUsed: workerResult.tokensUsed,
            }
          }
          if (reflexionResult.shouldRetry) {
            reActWorkerBrief = reflexionResult.enrichedBrief
            return {
              actionType: 'execute_task',
              rawOutput: reflexionResult.enrichedBrief,
              success: false,
              tokensUsed: workerResult.tokensUsed,
              error: `Reflexion: ${reflexionResult.retryInstruction}`,
            }
          }

          return {
            actionType: 'execute_task',
            rawOutput: workerResult.content,
            success: true,
            tokensUsed: workerResult.tokensUsed,
          }
        }
        return {
          actionType: decision.action,
          rawOutput: '',
          success: true,
        }
      },
    )

    this.manager.ingestReActLoopResult(loopResult)

    if (this._pendingConfidenceClarification !== undefined) {
      const q = this._pendingConfidenceClarification
      this._pendingConfidenceClarification = undefined
      return {
        type: 'clarification_required',
        question: q,
        response: q,
        action: 'clarified',
        success: false,
        taskType,
        iterationCount: loopResult.trace.steps.length,
        reActTrace: loopResult.trace,
        reasoningSummary: loopResult.reasoningSummary,
      }
    }

    if (loopResult.shouldRequestClarification) {
      const q = loopResult.finalDecision.thought.content
      return {
        type: 'clarification_required',
        question: q,
        response: q,
        action: 'clarified',
        success: false,
        taskType,
        iterationCount: loopResult.trace.steps.length,
        reActTrace: loopResult.trace,
        reasoningSummary: loopResult.reasoningSummary,
      }
    }

    let lastExecuteStep: (typeof loopResult.trace.steps)[number] | undefined
    for (let i = loopResult.trace.steps.length - 1; i >= 0; i--) {
      const step = loopResult.trace.steps[i]
      if (step.action.type === 'execute_task') {
        lastExecuteStep = step
        break
      }
    }
    const lastWorkerOutput =
      lastExecuteStep?.observation.content ??
      loopResult.finalDecision.finalAnswer ??
      ''

    return {
      type: 'standard',
      response: lastWorkerOutput,
      action: 'briefed_worker',
      success: true,
      taskType,
      iterationCount: loopResult.trace.steps.length,
      reActTrace: loopResult.trace,
      reasoningSummary: loopResult.reasoningSummary,
      verificationPassed: true,
    }
  }

  private async _runReflexionIterations(
    initialBrief: string,
    userMessage: string,
    activeBasePrompt: string,
    managerDecision: Awaited<ReturnType<ManagerAgent['processTurn']>>,
    complexityScore: number,
    taskType: TaskType,
  ): Promise<{
    earlyReturn?: MWOrchestratorClarificationRequired
    bestOutput: string
    bestScore: number
    finalVerificationPassed: boolean
    totalIterations: number
    workerResult: WorkerResult | null
    allOutputs: string[]
  }> {
    let brief = initialBrief
    let bestOutput = ''
    let bestScore = 0
    let finalVerificationPassed = false
    let totalIterations = 0
    let workerResult: WorkerResult | null = null
    const allOutputs: string[] = []

    for (let iteration = 1; iteration <= MAX_REFLEXION_ITERATIONS; iteration++) {
      totalIterations = iteration
      const phase = await this._executeWithWorker(
        managerDecision,
        { brief, userMessage, activeBasePrompt, complexityScore, taskType },
        0,
      )

      if (!phase.ok) {
        const q = phase.clarificationQuestion
        return {
          earlyReturn: { type: 'clarification_required', question: q, response: q, action: 'clarified', success: false, taskType, iterationCount: totalIterations },
          bestOutput, bestScore, finalVerificationPassed, totalIterations, workerResult, allOutputs,
        }
      }

      workerResult = phase.workerResult
      if (!workerResult.success) break

      const reflexionResult = phase.reflexionResult
      if (reflexionResult === undefined) break

      allOutputs.push(workerResult.content)
      this.manager.recordAssistantTurn(workerResult.content)

      if (reflexionResult.critique.overallScore > bestScore) {
        bestScore = reflexionResult.critique.overallScore
        bestOutput = workerResult.content
      }

      if (reflexionResult.critique.passed) {
        finalVerificationPassed = true
        break
      }

      if (!reflexionResult.shouldRetry) break

      brief = reflexionResult.enrichedBrief
      console.log(
        `${LOG} Reflexion retry ${String(iteration + 1)}: ${reflexionResult.retryInstruction.slice(0, 80)}`,
      )
    }

    return { bestOutput, bestScore, finalVerificationPassed, totalIterations, workerResult, allOutputs }
  }

  private async _markEffectiveLessons(): Promise<void> {
    for (const c of this.reflexionController.getIterationHistory()) {
      for (const l of c.lessonsForFuture) {
        const lesson = await lessonsStore.findLessonByExactContent(this.sessionId, l)
        if (lesson !== undefined) {
          await lessonsStore.markEffective(lesson.id, this.sessionId, true)
        }
      }
    }
  }

  private async _processReflexionLoop(
    effectiveBrief: string,
    userMessage: string,
    activeBasePrompt: string,
    managerDecision: Awaited<ReturnType<ManagerAgent['processTurn']>>,
    complexityScore: number,
    taskType: TaskType,
  ): Promise<MWOrchestratorResult> {
    this.reflexionController.reset()
    const iter = await this._runReflexionIterations(effectiveBrief, userMessage, activeBasePrompt, managerDecision, complexityScore, taskType)
    if (iter.earlyReturn !== undefined) return iter.earlyReturn

    const { bestOutput, bestScore, finalVerificationPassed, totalIterations, allOutputs } = iter
    const { workerResult } = iter

    if (bestScore < 0.5 && !finalVerificationPassed) {
      console.warn(
        `${LOG} All iterations failed critique ÔÇö returning best attempt (score: ${String(bestScore)})`,
      )
    }

    const finalOutput = finalVerificationPassed
      ? (workerResult?.content ?? '')
      : this.reflexionController.getBestOutput(allOutputs) || bestOutput || workerResult?.content || ''

    if (finalVerificationPassed) {
      await this._markEffectiveLessons()
    }

    const reflexionSummary = {
      totalIterations,
      finalScore: bestScore,
      lessonsLearned: this.reflexionController.getIterationHistory().flatMap((c) => c.lessonsForFuture),
    }

    if (!workerResult?.success) {
      return {
        type: 'standard',
        response: 'I encountered an error completing that task. Could you try again?',
        action: 'error',
        success: false,
        taskType,
        workerResult: workerResult ?? undefined,
        verificationPassed: false,
        iterationCount: totalIterations,
        reflexionSummary,
      }
    }

    const mergedWorker: WorkerResult = {
      ...workerResult,
      content: finalOutput,
      iterationCount: totalIterations,
    }

    if (!finalVerificationPassed) {
      console.warn(`${LOG} Max reflexion iterations reached, returning best attempt`)
      return {
        type: 'standard',
        response: finalOutput,
        action: 'verification_failed',
        success: false,
        taskType,
        workerResult: mergedWorker,
        verificationPassed: false,
        iterationCount: totalIterations,
        reflexionSummary,
      }
    }

    return {
      type: 'standard',
      response: finalOutput,
      action: 'briefed_worker',
      success: true,
      taskType,
      workerResult: mergedWorker,
      verificationPassed: true,
      iterationCount: totalIterations,
      reflexionSummary,
    }
  }

  /**
   * Worker ÔåÆ Reflexion ÔåÆ confidence (with {@link WorkerResult.critiqueScore}) ÔåÆ hard-block, tier escalation, or proceed.
   */
  private async _executeWithWorker(
    managerDecision: Awaited<ReturnType<ManagerAgent['processTurn']>>,
    config: {
      brief: string
      userMessage: string
      activeBasePrompt: string
      complexityScore: number
      taskType: TaskType
    },
    iterationCount = 0,
  ): Promise<
    | { ok: false; clarificationQuestion: string }
    | { ok: true; workerResult: WorkerResult; reflexionResult?: ReflexionResult }
  > {
    const escalationPass = iterationCount

    const workerResult = await this.worker.execute(
      config.brief,
      config.taskType,
      'gpt-4o',
      this.sessionId,
      {
        orchestratorBasePrompt: config.activeBasePrompt,
        complexityScore: config.complexityScore,
        skipConfidenceEvaluation: true,
      },
    )

    telemetry.record('worker_executed', this.sessionId, {
      taskType: config.taskType,
      iteration: escalationPass,
      tokensUsed: workerResult.tokensUsed,
      success: workerResult.success,
    })

    if (!workerResult.success) {
      return { ok: true, workerResult }
    }

    const reflexionResult = await this.reflexionController.reflect(config.brief, workerResult.content, {
      originalRequest: config.userMessage,
      taskType: config.taskType,
      output: workerResult.content,
      requirements: managerDecision.taskState.activeRequirements.map((r) => r.description),
      scratchpadSummary: this.manager.getScratchpadSummary() ?? undefined,
    })

    workerResult.critiqueScore = reflexionResult.critique?.overallScore ?? undefined

    const confidenceResult = await confidenceOrchestrator.evaluate(
      workerResult.content,
      {
        sessionId: this.sessionId,
        taskType: config.taskType,
        taskDescription: config.brief.slice(0, 300),
        turnIndex: 0,
        complexityScore: config.complexityScore,
        iterationNumber: escalationPass,
      },
      { critiqueScore: workerResult.critiqueScore },
    )

    if (
      confidenceResult.uarResult?.resolvedContent !== undefined &&
      confidenceResult.uarResult.resolvedContent.length > 0
    ) {
      workerResult.content = confidenceResult.uarResult.resolvedContent
      console.log(
        `${LOG} UAR improved output (confidence: ${confidenceResult.uarResult.originalScore.toFixed(2)} ÔåÆ ${confidenceResult.uarResult.resolvedScore.toFixed(2)})`,
      )
    }

    if (confidenceResult.uncertaintyNotice !== undefined) {
      workerResult.content += `\n\n${confidenceResult.uncertaintyNotice}`
    }

    workerResult.confidenceScore = confidenceResult.score.scalar
    workerResult.confidenceLevel = confidenceResult.score.level

    if (confidenceResult.shouldBlock) {
      console.log(`${PRE_TASK_LOG} Confidence hard-block ÔÇö returning clarification`)
      return {
        ok: false,
        clarificationQuestion:
          confidenceResult.uarResult?.clarificationQuestion ??
          'Could you provide more detail? I need more context to answer accurately.',
      }
    }

    if (confidenceResult.shouldEscalate && escalationPass < 2) {
      const escalatedComplexity = Math.min((config.complexityScore ?? 0.5) + 0.25, 1)
      console.log(
        `${PRE_TASK_LOG} Confidence escalation ÔÇö retrying with complexityScore: ${String(escalatedComplexity)}`,
      )
      return await this._executeWithWorker(
        managerDecision,
        { ...config, complexityScore: escalatedComplexity },
        escalationPass + 1,
      )
    }

    if (confidenceResult.shouldEscalate && escalationPass >= 2) {
      console.log(`${PRE_TASK_LOG} Escalation limit reached ÔÇö using current output`)
    }

    return { ok: true, workerResult, reflexionResult }
  }

  private collectRecentUncertaintyFactors(sessionId: string): string[] {
    const memory = confidenceMemoryStore.getMemory(sessionId)
    if (memory === null || memory.entries.length === 0) return []
    const last3 = memory.entries.slice(-3)
    const seen = new Set<string>()
    const out: string[] = []
    for (const e of last3) {
      for (const f of e.uncertaintyFactors) {
        const t = f.trim()
        if (t.length === 0 || seen.has(t)) continue
        seen.add(t)
        out.push(t)
        if (out.length >= 10) return out
      }
    }
    return out
  }

  private async runPreTaskEstimate(
    taskDescription: string,
    taskType: TaskType,
    sessionId: string,
  ): Promise<PreTaskEstimate> {
    const scratchpadSummary = this.manager.getScratchpadSummary() ?? undefined
    const recentUncertaintyFactors = this.collectRecentUncertaintyFactors(sessionId)
    const relevantLessonRows = await lessonsStore.getRelevantLessons({
      sessionId,
      taskType,
      currentOutput: taskDescription.slice(0, 500),
    })
    const relevantLessons = relevantLessonRows.map((l) => l.lesson)

    const estimate = await this.preTaskElicitor.estimatePreTask(taskDescription, taskType, sessionId, {
      scratchpadSummary,
      recentUncertaintyFactors,
      relevantLessons,
    })

    telemetry.record('pre_task_confidence', sessionId, {
      confidence: estimate.confidence,
      shouldProceed: estimate.shouldProceed,
      missingInfoCount: estimate.missingInfo.length,
      taskType,
    })

    console.log(
      `${PRE_TASK_LOG} Pre-task confidence: ${estimate.confidence.toFixed(2)} shouldProceed: ${String(estimate.shouldProceed)}`,
    )

    return estimate
  }

  /**
   * Lightweight snapshot for debugging or admin panels.
   */
  getStats(): { sessionId: string; currentTaskState: TaskState | null; maxIterations: number } {
    return {
      sessionId: this.sessionId,
      currentTaskState: this.manager.getTaskState(),
      maxIterations: MAX_REFLEXION_ITERATIONS,
    }
  }
}

