async function flushPromises(): Promise<void> {
  await new Promise<void>((r) => setImmediate(r))
  await new Promise<void>((r) => setImmediate(r))
}

function listTsFilesRecursive(dir: string): string[] {
  const out: string[] = []
  for (const name of readdirSync(dir, { withFileTypes: true })) {
    if (name.isDirectory() && name.name === '__tests__') {
      continue
    }
    const p = join(dir, name.name)
    if (name.isDirectory()) {
      out.push(...listTsFilesRecursive(p))
    } else if (name.name.endsWith('.ts')) {
      out.push(p)
    }
  }
  return out
}

import EventEmitter from 'eventemitter3'

import { BaseAgent } from '../base-agent'

import { AdviceGenerator, type JarvisAdviceLlm } from './advice-generator'
import { DEFAULT_CONFIG } from './config'
import { GoalExecutor } from './goal-executor'
import { PythonBridge } from './python-bridge'
import { SafetyGate } from './safety-gate'
import { SignificanceDetector } from './significance-detector'
import { StateManager, type JarvisMemoryClient } from './state-manager'
import { AgentMode, type ScreenAgentConfig, type ScreenAgentEvents, type ScreenState } from './types'

function normalizeTimestamp(raw: unknown): number {
  if (typeof raw !== 'number' || Number.isNaN(raw)) {
    return Date.now()
  }
  if (raw < 1e12) {
    return Math.round(raw * 1000)
  }
  return raw
}

function isScreenStateLike(r: object): r is ScreenState {
  return (
    'frameId' in r &&
    'timestamp' in r &&
    'elements' in r &&
    typeof (r as ScreenState).frameId === 'string'
  )
}

export interface ScreenAgentDeps {
  memoryClient?: JarvisMemoryClient | null
  bridge?: PythonBridge
  llmClient?: JarvisAdviceLlm
  adviceGenerator?: AdviceGenerator
  significanceDetector?: SignificanceDetector
  safetyGate?: SafetyGate
  goalExecutor?: GoalExecutor
  /** Orchestrator bus for BehaviourLogger (`goal:*`, `screen:mode_changed`). */
  globalBehaviourBus?: EventEmitter
}

/**
 * Isolated screen-observation agent: WebSocket bridge to Python, significance, advice, goals.
 * Emits typed `ScreenAgentEvents` only ÔÇö never imports audio capture or playback pipelines.
 */
export class ScreenAgent extends BaseAgent {
  readonly id = 'jarvis-screen-agent'

  private readonly config: ScreenAgentConfig
  private readonly bridge: PythonBridge
  private readonly stateManager: StateManager
  private readonly emitter = new EventEmitter<ScreenAgentEvents>()
  private mode: AgentMode
  private currentState: ScreenState | null = null
  private prevState: ScreenState | null = null
  private readonly significanceDetector: SignificanceDetector
  private readonly adviceGenerator: AdviceGenerator
  private readonly safetyGate: SafetyGate
  private readonly goalExecutor: GoalExecutor
  private readonly globalBehaviourBus: EventEmitter | undefined

  private readonly onUserConfirmed = (): void => {
    this.goalExecutor.notifyUserApproval(true)
  }

  private readonly onUserCancelled = (): void => {
    this.goalExecutor.notifyUserApproval(false)
  }

  private readonly onBridgeConnected = (): void => {
    console.info('Screen agent connected')
  }

  private readonly onBridgeDisconnected = (): void => {
    console.info('Screen agent disconnected')
  }

  private readonly handleScreenChange = async (raw: Record<string, unknown>): Promise<void> => {
    const frameId = raw.frame_id
    const description =
      typeof raw.description === 'string'
        ? raw.description
        : typeof raw.windowTitle === 'string' && raw.windowTitle
          ? raw.windowTitle
          : ''
    const w = raw.width
    const h = raw.height
    const width = typeof w === 'number' && Number.isFinite(w) ? w : 0
    const height = typeof h === 'number' && Number.isFinite(h) ? h : 0
    const state: ScreenState = {
      frameId:
        typeof frameId === 'number' || typeof frameId === 'string' ? String(frameId) : '0',
      timestamp: normalizeTimestamp(raw.timestamp),
      activeApp: typeof raw.app === 'string' ? raw.app : null,
      windowTitle:
        typeof raw.window === 'string'
          ? raw.window
          : typeof raw.windowTitle === 'string'
            ? raw.windowTitle
            : null,
      fullText: description,
      errorDetected: Boolean(raw.error_detected),
      url: null,
      elements: [],
      resolution: { width, height },
      heartbeat: raw.heartbeat === true,
    }
    await this.stateManager.store(state)
    this.currentState = state
    this.emit('screen:change', state)
    if (state.errorDetected) {
      const app = state.activeApp ?? 'unknown'
      this.emit('screen:error', { state, errorText: `Error detected in ${app}` })
    }
    console.debug('[ScreenAgent] screen_change', {
      frame_id: raw.frame_id,
      app: raw.app,
      error_detected: raw.error_detected,
    })

    if (this.mode === AgentMode.ADVISE && !state.heartbeat) {
      const significance = this.significanceDetector.detect(state, this.prevState)
      if (significance.shouldSpeak) {
        const advice = await this.adviceGenerator.generate(state, significance.reason)
        if (advice) {
          this.emit('jarvis:speak', {
            text: advice,
            priority: significance.score >= 0.85 ? 'high' : 'normal',
          })
          this.emit('screen:advice_ready', { advice })
          console.info(
            `Advice emitted ÔÇö reason: ${significance.reason}, score: ${String(significance.score)}`,
          )
        }
      }
    }

    this.prevState = state
  }

  constructor(config: Partial<ScreenAgentConfig> = {}, deps: ScreenAgentDeps = {}) {
    super()
    this.config = { ...DEFAULT_CONFIG, ...config }
    this.mode = AgentMode.WATCH
    this.bridge = deps.bridge ?? new PythonBridge(this.config.wsPort)
    this.stateManager = new StateManager(deps.memoryClient)
    this.significanceDetector = deps.significanceDetector ?? new SignificanceDetector()
    this.adviceGenerator = deps.adviceGenerator ?? new AdviceGenerator(deps.llmClient)
    this.safetyGate = deps.safetyGate ?? new SafetyGate()
    this.globalBehaviourBus = deps.globalBehaviourBus
    this.goalExecutor =
      deps.goalExecutor ??
      new GoalExecutor(this.bridge, this.emitter, this.safetyGate, this.globalBehaviourBus)
  }

  private emitBehaviourMode(mode: AgentMode): void {
    this.globalBehaviourBus?.emit('screen:mode_changed', { newMode: mode })
  }

  emit<K extends keyof ScreenAgentEvents>(event: K, ...args: ScreenAgentEvents[K]): boolean {
    return (this.emitter.emit as (e: K, ...a: ScreenAgentEvents[K]) => boolean)(event, ...args)
  }

  on<K extends keyof ScreenAgentEvents>(
    event: K,
    fn: (...args: ScreenAgentEvents[K]) => void,
    context?: unknown
  ): this {
    this.emitter.on(event, fn as never, context)
    return this
  }

  once<K extends keyof ScreenAgentEvents>(
    event: K,
    fn: (...args: ScreenAgentEvents[K]) => void,
    context?: unknown
  ): this {
    this.emitter.once(event, fn as never, context)
    return this
  }

  off<K extends keyof ScreenAgentEvents>(
    event: K,
    fn?: (...args: ScreenAgentEvents[K]) => void,
    context?: unknown,
    once?: boolean
  ): this {
    this.emitter.off(event, fn as never, context, once)
    return this
  }

  async initialize(): Promise<void> {
    this.on('user:confirmed', this.onUserConfirmed)
    this.on('user:cancelled', this.onUserCancelled)
    this.bridge.on('screen_change', this.handleScreenChange)
    this.bridge.on('connected', this.onBridgeConnected)
    this.bridge.on('disconnected', this.onBridgeDisconnected)
    await this.bridge.connect()
    console.info('Screen agent initialized in WATCH mode')
  }

  async setMode(mode: AgentMode, goal?: string): Promise<void> {
    if (mode === AgentMode.ACT) {
      const g = goal?.trim() ?? ''
      if (g.length === 0) {
        console.warn('ACT mode requires a goal ÔÇö staying in current mode')
        return
      }
      const previous = this.mode
      if (previous === AgentMode.ADVISE) {
        console.info('Leaving ADVISE mode')
      }
      this.prevState = null
      this.mode = AgentMode.ACT
      this.emitBehaviourMode(AgentMode.ACT)
      const result = await this.goalExecutor.execute(g)
      if (result.success) {
        this.emit('jarvis:speak', {
          text: `Done. ${g} completed.`,
          priority: 'normal',
        })
      } else {
        this.emit('jarvis:speak', {
          text: `I got stuck. ${result.failureReason ?? 'Unknown error'}`,
          priority: 'normal',
        })
      }
      this.mode = AgentMode.WATCH
      this.emitBehaviourMode(AgentMode.WATCH)
      this.bridge.send({ command: 'set_mode', mode: 'WATCH' })
      console.info('Returned to WATCH mode after goal completion')
      return
    }

    const previous = this.mode
    if (previous !== mode) {
      if (mode === AgentMode.ADVISE) {
        console.info('Entering ADVISE mode ÔÇö Jarvis will speak proactively')
      }
      if (previous === AgentMode.ADVISE) {
        console.info('Leaving ADVISE mode')
      }
      this.prevState = null
    }
    this.mode = mode
    if (previous !== mode) {
      this.emitBehaviourMode(mode)
    }
    this.bridge.send({ command: 'set_mode', mode, goal })
    console.info('[ScreenAgent] mode', mode, goal ?? '')
  }

  stop(): void {
    this.off('user:confirmed', this.onUserConfirmed)
    this.off('user:cancelled', this.onUserCancelled)
    if (this.goalExecutor.isGoalExecutionActive()) {
      this.emit('jarvis:speak', {
        text: 'Stopping current task.',
        priority: 'high',
      })
    }
    this.goalExecutor.stop()
    this.bridge.off('screen_change', this.handleScreenChange)
    this.bridge.off('connected', this.onBridgeConnected)
    this.bridge.off('disconnected', this.onBridgeDisconnected)
    this.bridge.disconnect()
    console.info('Screen agent stopped')
  }

  async queryScreen(question: string): Promise<string> {
    if (this.bridge.getStatus() !== 'connected') {
      return 'Screen agent not connected'
    }
    return await new Promise<string>((resolve, reject) => {
      const to = setTimeout(() => {
        this.bridge.off('query_response', onResp)
        reject(new Error('queryScreen: timeout waiting for query_response'))
      }, 10_000)
      const onResp = (payload: { answer: string }): void => {
        clearTimeout(to)
        this.bridge.off('query_response', onResp)
        resolve(payload.answer)
      }
      this.bridge.on('query_response', onResp)
      this.bridge.send({ command: 'query_screen', question })
    })
  }

  async getMemoryAt(timestamp: number): Promise<ScreenState | null> {
    const local = await this.stateManager.getStateAt(timestamp)
    if (local !== null) {
      return local
    }
    if (this.bridge.getStatus() !== 'connected') {
      return null
    }
    return await new Promise<ScreenState | null>((resolve) => {
      const to = setTimeout(() => {
        this.bridge.off('memory_response', onMem)
        resolve(null)
      }, 5000)
      const onMem = (payload: { record: unknown }): void => {
        clearTimeout(to)
        this.bridge.off('memory_response', onMem)
        const r = payload.record
        if (r !== null && typeof r === 'object' && isScreenStateLike(r)) {
          resolve(r)
        } else {
          resolve(null)
        }
      }
      this.bridge.on('memory_response', onMem)
      this.bridge.send({ command: 'query_memory', timestamp })
    })
  }

  getCurrentState(): ScreenState | null {
    return this.currentState
  }

  getMode(): AgentMode {
    return this.mode
  }

  /** True when the Python sidecar WebSocket is connected (desktop screen pipeline live). */
  isPythonBridgeConnected(): boolean {
    return this.bridge.getStatus() === 'connected'
  }
}

export * from './types'
export { DEFAULT_CONFIG, DENYLIST, APPROVAL_REQUIRED_PATTERNS, VOICE_PROTECTED_PATTERNS } from './config'
export { PythonBridge } from './python-bridge'
export type { ConnectionStatus } from './python-bridge'
export { StateManager, type JarvisMemoryClient } from './state-manager'
export { SignificanceDetector } from './significance-detector'
export { AdviceGenerator, type JarvisAdviceLlm } from './advice-generator'
export { SafetyGate } from './safety-gate'
export { GoalExecutor } from './goal-executor'

import EventEmitter from 'eventemitter3'
import WebSocket from 'ws'

export type ConnectionStatus = 'connecting' | 'connected' | 'disconnected'

const CONNECT_TIMEOUT_MS = 10_000
const RECONNECT_DELAY_MS = 3000

/**
 * Wire protocol events from the Python sidecar (distinct from {@link ScreenAgentEvents} in `./types`).
 */
export interface PythonBridgeEvents {
  screen_change: [Record<string, unknown>]
  query_response: [{ answer: string }]
  memory_response: [{ record: unknown }]
  goal_progress: [Record<string, unknown>]
  goal_complete: [Record<string, unknown>]
  goal_failed: [Record<string, unknown>]
  approval_required: [Record<string, unknown>]
  connected: []
  disconnected: []
}

/**
 * WebSocket client to the Python screen-capture sidecar (`ws://localhost:{port}`).
 */
export class PythonBridge extends EventEmitter<PythonBridgeEvents> {
  private readonly url: string
  private ws: WebSocket | null = null
  private status: ConnectionStatus = 'disconnected'
  private reconnectTimer: ReturnType<typeof setTimeout> | null = null
  private reconnectScheduled = false
  private closingIntentionally = false

  constructor(private readonly port: number) {
    super()
    this.url = `ws://localhost:${String(port)}`
  }

  getStatus(): ConnectionStatus {
    return this.status
  }

  async connect(): Promise<void> {
    this.clearReconnectTimer()
    this.closingIntentionally = false
    this.status = 'connecting'

    await new Promise<void>((resolve, reject) => {
      const socket = new WebSocket(this.url)
      this.ws = socket

      let settled = false
      const to = setTimeout(() => {
        if (settled) return
        settled = true
        socket.removeAllListeners()
        try {
          socket.terminate()
        } catch {
          /* ignore */
        }
        this.ws = null
        this.status = 'disconnected'
        reject(new Error(`PythonBridge: connect timeout after ${String(CONNECT_TIMEOUT_MS)}ms`))
      }, CONNECT_TIMEOUT_MS)

      const finish = (fn: () => void) => {
        if (settled) return
        settled = true
        clearTimeout(to)
        fn()
      }

      const onConnectError = (err: Error) => {
        finish(() => {
          console.error('[PythonBridge] connect error:', err)
          try {
            socket.terminate()
          } catch {
            /* ignore */
          }
          this.ws = null
          this.status = 'disconnected'
          reject(err instanceof Error ? err : new Error(String(err)))
        })
      }
      socket.once('error', onConnectError)

      socket.once('open', () => {
        socket.off('error', onConnectError)
        finish(() => {
          this.status = 'connected'
          socket.on('error', (runtimeErr: Error) => {
            console.error('[PythonBridge] socket error:', runtimeErr)
          })
          this.emit('connected')
          resolve()
        })
      })

      socket.on('message', (data: WebSocket.RawData) => {
        try {
          const text = typeof data === 'string' ? data : data.toString('utf8')
          const msg = JSON.parse(text) as Record<string, unknown>
          const t = msg.type
          if (t === 'screen_change') {
            this.emit('screen_change', msg)
          } else if (t === 'query_response') {
            const answer = typeof msg.answer === 'string' ? msg.answer : ''
            this.emit('query_response', { answer })
          } else if (t === 'memory_response') {
            const record = 'record' in msg ? msg.record : null
            this.emit('memory_response', { record })
          } else if (t === 'goal_progress') {
            this.emit('goal_progress', msg)
          } else if (t === 'goal_complete') {
            this.emit('goal_complete', msg)
          } else if (t === 'goal_failed') {
            this.emit('goal_failed', msg)
          } else if (t === 'approval_required') {
            this.emit('approval_required', msg)
          }
        } catch (e) {
          console.error('[PythonBridge] message parse error:', e)
        }
      })

      socket.on('close', () => {
        clearTimeout(to)
        this.status = 'disconnected'
        this.emit('disconnected')
        this.ws = null
        const intentional = this.closingIntentionally
        this.closingIntentionally = false
        if (!intentional) {
          this.scheduleReconnect()
        }
      })
    })
  }

  send(command: Record<string, unknown>): void {
    if (this.status !== 'connected' || this.ws === null) {
      console.warn('[PythonBridge] send skipped ÔÇö not connected', command)
      return
    }
    try {
      this.ws.send(JSON.stringify(command))
    } catch (e) {
      console.error('[PythonBridge] send failed:', e)
    }
  }

  disconnect(): void {
    this.clearReconnectTimer()
    this.reconnectScheduled = false
    this.closingIntentionally = true
    if (this.ws !== null) {
      try {
        this.ws.removeAllListeners()
        this.ws.close()
      } catch {
        /* ignore */
      }
      this.ws = null
    }
    this.status = 'disconnected'
  }

  private clearReconnectTimer(): void {
    if (this.reconnectTimer !== null) {
      clearTimeout(this.reconnectTimer)
      this.reconnectTimer = null
    }
  }

  private scheduleReconnect(): void {
    if (this.reconnectScheduled) {
      return
    }
    this.reconnectScheduled = true
    console.info('[PythonBridge] scheduling reconnect in', RECONNECT_DELAY_MS, 'ms')
    this.reconnectTimer = setTimeout(() => {
      this.reconnectTimer = null
      this.reconnectScheduled = false
      console.info('[PythonBridge] reconnect attempt')
      void this.connect().catch((err: unknown) => {
        console.error('[PythonBridge] reconnect failed:', err)
      })
    }, RECONNECT_DELAY_MS)
  }
}

import { SAME_EVENT_COOLDOWN_MS } from './config'
import type { ScreenState, SignificanceResult } from './types'

const CRITICAL_SUBSTRINGS = [
  'terminal',
  'powershell',
  'cmd',
  'deployment',
  'vercel',
  'railway',
  'digitalocean',
] as const

function wordCount(text: string): number {
  const t = text.trim()
  if (t.length === 0) {
    return 0
  }
  return t.split(/\s+/).length
}

function isCriticalApp(activeApp: string | null): boolean {
  if (activeApp === null) {
    return false
  }
  const n = activeApp.toLowerCase()
  return CRITICAL_SUBSTRINGS.some((k) => n.includes(k))
}

function titleImpliesFailure(windowTitle: string | null): boolean {
  if (windowTitle === null) {
    return false
  }
  const t = windowTitle.toLowerCase()
  return t.includes('failed') || t.includes('error') || t.includes('crashed')
}

/**
 * Scores screen-frame deltas to decide whether Jarvis should speak in ADVISE mode.
 */
export class SignificanceDetector {
  private readonly cooldowns = new Map<string, number>()
  private readonly COOLDOWN_MS = SAME_EVENT_COOLDOWN_MS

  detect(curr: ScreenState, prev: ScreenState | null): SignificanceResult {
    if (curr.errorDetected && prev?.errorDetected) {
      return this.applyCooldown({ score: 0.3, reason: 'error_ongoing', shouldSpeak: false })
    }

    const candidates: SignificanceResult[] = []

    if (curr.errorDetected && !prev?.errorDetected) {
      candidates.push({ score: 0.9, reason: 'error_appeared', shouldSpeak: true })
    }

    if (titleImpliesFailure(curr.windowTitle)) {
      candidates.push({ score: 0.85, reason: 'failure_in_title', shouldSpeak: true })
    }

    if (prev !== null && curr.activeApp !== prev.activeApp && isCriticalApp(curr.activeApp)) {
      candidates.push({ score: 0.75, reason: 'critical_app_opened', shouldSpeak: true })
    }
    if (prev === null && isCriticalApp(curr.activeApp)) {
      candidates.push({ score: 0.75, reason: 'critical_app_opened', shouldSpeak: true })
    }

    const prevWords = prev === null ? 0 : wordCount(prev.fullText)
    const currWords = wordCount(curr.fullText)
    if (currWords - prevWords >= 500) {
      candidates.push({ score: 0.7, reason: 'major_content_change', shouldSpeak: true })
    }

    if (prev !== null && curr.activeApp !== prev.activeApp) {
      if (!isCriticalApp(curr.activeApp)) {
        candidates.push({ score: 0.4, reason: 'app_switch', shouldSpeak: false })
      }
    }

    if (
      prev !== null &&
      curr.activeApp === prev.activeApp &&
      curr.windowTitle !== prev.windowTitle
    ) {
      candidates.push({ score: 0.35, reason: 'window_change', shouldSpeak: false })
    }

    if (candidates.length === 0) {
      return this.applyCooldown({ score: 0.1, reason: 'no_change', shouldSpeak: false })
    }

    const best = candidates.reduce((a, b) => (a.score >= b.score ? a : b))
    return this.applyCooldown(best)
  }

  isOnCooldown(reason: string): boolean {
    const last = this.cooldowns.get(reason)
    if (last === undefined) {
      return false
    }
    return Date.now() - last < this.COOLDOWN_MS
  }

  resetCooldown(reason: string): void {
    this.cooldowns.set(reason, Date.now())
  }

  private applyCooldown(result: SignificanceResult): SignificanceResult {
    let { score, reason, shouldSpeak } = result
    if (shouldSpeak && this.isOnCooldown(reason)) {
      shouldSpeak = false
    }
    if (shouldSpeak) {
      this.resetCooldown(reason)
    }
    return { score, reason, shouldSpeak }
  }
}

/**
 * Jarvis voice agent: listens on the shared emitter for `jarvis:speak` and plays via ElevenLabs PCM
 * (same upstream contract as the Electron `/api/elevenlabs-tts` proxy).
 */
import type { ChildProcess } from 'node:child_process'
import { spawn } from 'node:child_process'
import { unlink, writeFile } from 'node:fs/promises'
import { platform, tmpdir } from 'node:os'
import { join } from 'node:path'

import type EventEmitter from 'eventemitter3'

import { fetchElevenLabsPcm } from '@/lib/elevenlabs-tts-stream'

const SAMPLE_RATE = 24_000

export type JarvisSpeakPriority = 'low' | 'normal' | 'high'

export interface JarvisSpeakPayload {
  text: string
  priority: JarvisSpeakPriority
}

function pcm16MonoToWav(pcm: Buffer): Buffer {
  const numChannels = 1
  const bitsPerSample = 16
  const blockAlign = numChannels * (bitsPerSample / 8)
  const byteRate = SAMPLE_RATE * blockAlign
  const dataSize = pcm.length
  const out = Buffer.alloc(44 + dataSize)
  out.write('RIFF', 0)
  out.writeUInt32LE(36 + dataSize, 4)
  out.write('WAVE', 8)
  out.write('fmt ', 12)
  out.writeUInt32LE(16, 16)
  out.writeUInt16LE(1, 20)
  out.writeUInt16LE(numChannels, 22)
  out.writeUInt32LE(SAMPLE_RATE, 24)
  out.writeUInt32LE(byteRate, 28)
  out.writeUInt16LE(blockAlign, 32)
  out.writeUInt16LE(bitsPerSample, 34)
  out.write('data', 36)
  out.writeUInt32LE(dataSize, 40)
  pcm.copy(out, 44)
  return out
}

async function playPcmWithWebAudio(pcm: Buffer, signal: AbortSignal): Promise<void> {
  const AC = globalThis.AudioContext ?? (globalThis as unknown as { webkitAudioContext?: typeof AudioContext }).webkitAudioContext
  if (!AC) {
    throw new Error('AudioContext not available')
  }
  const wav = pcm16MonoToWav(pcm)
  const ctx = new AC({ sampleRate: SAMPLE_RATE })
  const copy = wav.buffer.slice(wav.byteOffset, wav.byteOffset + wav.byteLength)
  const audioBuf = await ctx.decodeAudioData(copy)
  await new Promise<void>((resolve, reject) => {
    if (signal.aborted) {
      void ctx.close().catch(() => {})
      resolve()
      return
    }
    const src = ctx.createBufferSource()
    src.buffer = audioBuf
    src.connect(ctx.destination)
    const onAbort = (): void => {
      try {
        src.stop()
      } catch {
        /* ignored */
      }
      void ctx.close().catch(() => {})
      resolve()
    }
    signal.addEventListener('abort', onAbort, { once: true })
    src.onended = (): void => {
      signal.removeEventListener('abort', onAbort)
      void ctx.close().catch(() => {})
      resolve()
    }
    src.start(0)
    if (ctx.state === 'suspended') {
      void ctx.resume().catch(reject)
    }
  })
}

function playWavWithPowerShell(wavPath: string): ChildProcess {
  const escaped = wavPath.replace(/'/g, "''")
  return spawn(
    'powershell.exe',
    ['-NoProfile', '-Command', `$sp = New-Object System.Media.SoundPlayer('${escaped}'); $sp.PlaySync()`],
    { stdio: 'ignore', windowsHide: true },
  )
}

function playWavWithFfplay(wavPath: string): ChildProcess {
  return spawn('ffplay', ['-nodisp', '-autoexit', '-loglevel', 'quiet', '-i', wavPath], {
    stdio: 'ignore',
    windowsHide: true,
  })
}

function playWavWithAplay(wavPath: string): ChildProcess {
  return spawn('aplay', ['-q', wavPath], { stdio: 'ignore', windowsHide: true })
}

async function waitChild(child: ChildProcess, signal: AbortSignal): Promise<void> {
  await new Promise<void>((resolve, reject) => {
    const onAbort = (): void => {
      try {
        child.kill('SIGTERM')
      } catch {
        /* ignored */
      }
    }
    signal.addEventListener('abort', onAbort, { once: true })
    child.on('error', (e) => {
      signal.removeEventListener('abort', onAbort)
      reject(e)
    })
    child.on('close', (code, sig) => {
      signal.removeEventListener('abort', onAbort)
      if (signal.aborted) {
        resolve()
        return
      }
      if (code === 0 || sig === 'SIGTERM') {
        resolve()
        return
      }
      reject(new Error(`playback exited ${String(code)}`))
    })
  })
}

/** Prefer ffplay; fall back to ALSA `aplay` when ffplay is not installed. */
function spawnUnixPlayer(wavPath: string): Promise<ChildProcess> {
  return new Promise((resolve, reject) => {
    const ff = playWavWithFfplay(wavPath)
    ff.once('spawn', () => resolve(ff))
    ff.once('error', (err: NodeJS.ErrnoException) => {
      if (err.code !== 'ENOENT') {
        reject(err)
        return
      }
      const ap = playWavWithAplay(wavPath)
      ap.once('spawn', () => resolve(ap))
      ap.once('error', reject)
    })
  })
}

async function playPcmNode(
  pcm: Buffer,
  signal: AbortSignal,
  hooks?: { onPlaybackChild?: (c: ChildProcess | null) => void },
): Promise<void> {
  const wav = pcm16MonoToWav(pcm)
  const path = join(tmpdir(), `jarvis-voice-${Date.now()}-${Math.random().toString(36).slice(2)}.wav`)
  await writeFile(path, wav)
  hooks?.onPlaybackChild?.(null)
  try {
    const child =
      platform() === 'win32' ? playWavWithPowerShell(path) : await spawnUnixPlayer(path)
    hooks?.onPlaybackChild?.(child)
    try {
      await waitChild(child, signal)
    } finally {
      hooks?.onPlaybackChild?.(null)
    }
  } finally {
    await unlink(path).catch(() => {})
  }
}

async function playPcm(
  pcm: Buffer,
  signal: AbortSignal,
  hooks?: { onPlaybackChild?: (c: ChildProcess | null) => void },
): Promise<void> {
  if (
    typeof globalThis.AudioContext !== 'undefined' ||
    typeof (globalThis as unknown as { webkitAudioContext?: unknown }).webkitAudioContext !== 'undefined'
  ) {
    await playPcmWithWebAudio(pcm, signal)
    return
  }
  await playPcmNode(pcm, signal, hooks)
}

export class VoiceAgent {
  private readonly emitter: EventEmitter
  private readonly onJarvisSpeak: (p: unknown) => void
  private started = false
  private readonly queue: string[] = []
  private drainRunning = false
  private currentAbort: AbortController | null = null
  private playbackChild: ChildProcess | null = null
  private lowTimer: ReturnType<typeof setTimeout> | null = null
  private pendingLow: string | null = null
  /** When true (e.g. Voice Mode open in renderer), skip ElevenLabs ÔÇö avoids double voice with Realtime. */
  private playbackSuppressed = false

  constructor(emitter: EventEmitter) {
    this.emitter = emitter
    this.onJarvisSpeak = (raw: unknown): void => {
      const p = raw as Partial<JarvisSpeakPayload>
      const text = typeof p.text === 'string' ? p.text.trim() : ''
      const pr = p.priority
      if (!text || (pr !== 'low' && pr !== 'normal' && pr !== 'high')) {
        return
      }
      this.handleSpeak({ text, priority: pr })
    }
  }

  async initialize(): Promise<void> {
    if (this.started) {
      return
    }
    this.emitter.on('jarvis:speak', this.onJarvisSpeak)
    this.started = true
  }

  /** Suppress main-process TTS (e.g. while renderer Voice Mode is active). */
  setPlaybackSuppressed(suppress: boolean): void {
    this.playbackSuppressed = suppress
    if (suppress) {
      this.clearLowDebounce()
      this.queue.length = 0
      this.cancelOngoing()
    }
  }

  stop(): void {
    if (!this.started) {
      return
    }
    this.emitter.off('jarvis:speak', this.onJarvisSpeak)
    this.started = false
    this.clearLowDebounce()
    this.queue.length = 0
    this.cancelOngoing()
  }

  private clearLowDebounce(): void {
    if (this.lowTimer !== null) {
      clearTimeout(this.lowTimer)
      this.lowTimer = null
    }
    this.pendingLow = null
  }

  private cancelOngoing(): void {
    this.currentAbort?.abort()
    this.currentAbort = null
    if (this.playbackChild !== null) {
      try {
        this.playbackChild.kill('SIGTERM')
      } catch {
        /* ignored */
      }
      this.playbackChild = null
    }
  }

  private handleSpeak(p: JarvisSpeakPayload): void {
    if (this.playbackSuppressed) {
      return
    }
    if (p.priority === 'high') {
      this.clearLowDebounce()
      this.cancelOngoing()
      this.queue.unshift(p.text)
      void this.drain()
      return
    }
    if (p.priority === 'normal') {
      this.clearLowDebounce()
      this.queue.push(p.text)
      void this.drain()
      return
    }
    // low ÔÇö debounce: only the latest text within 500ms is queued
    this.pendingLow = p.text
    if (this.lowTimer !== null) {
      clearTimeout(this.lowTimer)
    }
    this.lowTimer = setTimeout(() => {
      this.lowTimer = null
      const t = this.pendingLow
      this.pendingLow = null
      if (t && t.length > 0) {
        this.queue.push(t)
        void this.drain()
      }
    }, 500)
  }

  private async drain(): Promise<void> {
    if (this.drainRunning) {
      return
    }
    this.drainRunning = true
    try {
      while (this.started && this.queue.length > 0) {
        const text = this.queue.shift()!
        const ac = new AbortController()
        this.currentAbort = ac
        try {
          const pcm = await fetchElevenLabsPcm(text, { signal: ac.signal })
          await playPcm(pcm, ac.signal, {
            onPlaybackChild: (c) => {
              this.playbackChild = c
            },
          })
        } catch (e) {
          if (ac.signal.aborted) {
            continue
          }
          console.error('[VoiceAgent] speak failed:', e)
        } finally {
          if (this.currentAbort === ac) {
            this.currentAbort = null
          }
        }
      }
    } finally {
      this.drainRunning = false
    }
  }
}

export function createVoiceAgent(emitter: EventEmitter): VoiceAgent {
  return new VoiceAgent(emitter)
}

import {
  useEffect,
  useRef,
  useState,
  type Dispatch,
  type SetStateAction,
} from 'react'

/** SSE / JSON payload shape for `event: telemetry` rows from `/api/dashboard/stream`. */
export interface TelemetryEvent {
  type: string
  sessionId: string
  data: Record<string, unknown>
  timestamp: string
}

export interface ReActTraceEntry {
  sessionId: string
  step: 'thought' | 'action' | 'observation'
  content: string
  taskType: string
  timestamp: string
  confidenceScore?: number
}

export interface ConfidencePoint {
  timestamp: string
  scalar: number
  level: string
  action: string
  taskType: string
  sessionId: string
}

export interface ReflexionEvent {
  timestamp: string
  iteration: number
  critiqueScore: number
  passed: boolean
  taskType: string
  sessionId: string
}

export interface TotSearchSummary {
  timestamp: string
  nodesExplored: number
  nodesPruned: number
  bestScore: number
  taskType: string
  durationMs: number
}

export interface DashboardState {
  /** Connection */
  isConnected: boolean
  lastHeartbeat: string | null

  /** ReAct traces */
  recentTraces: ReActTraceEntry[]

  /** Confidence */
  confidenceHistory: ConfidencePoint[]
  sessionConfidenceTrend: 'improving' | 'stable' | 'degrading'

  /** Cost */
  costByTier: Record<string, { calls: number; costUSD: number }>
  totalCostUSD: number
  sessionCostToDate: number

  /** Routing */
  routingByTier: Record<string, number>
  overrideCount: number

  /** Reflexion */
  reflexionEvents: ReflexionEvent[]
  avgCritiqueScore: number

  /** ToT */
  totSearches: TotSearchSummary[]
  avgNodesExplored: number

  /** System */
  systemStats: Record<string, unknown> | null

  /** {@link TelemetryEvent} `pre_task_confidence` rollups for the live SSE stream. */
  preTaskStats: {
    totalEstimates: number
    blockedCount: number
    lowConfidenceCount: number
    avgPreTaskConfidence: number
  }
}

const MAX_TRACES = 20
const MAX_CONFIDENCE = 50
const MAX_REFLEXION = 20
const MAX_TOT = 10

function asNumber(value: unknown): number | undefined {
  if (typeof value === 'number' && !Number.isNaN(value)) {
    return value
  }
  return undefined
}

function asString(value: unknown, fallback = ''): string {
  return typeof value === 'string' ? value : fallback
}

function asBoolean(value: unknown): boolean {
  return value === true
}

function parseTrend(value: unknown): 'improving' | 'stable' | 'degrading' {
  const s = asString(value, 'stable').trim()
  if (s === 'improving' || s === 'stable' || s === 'degrading') {
    return s
  }
  return 'stable'
}

function appendCapped<T>(list: T[], item: T, max: number): T[] {
  const next = [...list, item]
  return next.length > max ? next.slice(next.length - max) : next
}

function average(nums: number[]): number {
  if (nums.length === 0) return 0
  return nums.reduce((a, b) => a + b, 0) / nums.length
}

/** Default {@link DashboardState} before the first SSE `connected` / snapshot. */
export const INITIAL_DASHBOARD_STATE: DashboardState = {
  isConnected: false,
  lastHeartbeat: null,
  recentTraces: [],
  confidenceHistory: [],
  sessionConfidenceTrend: 'stable',
  costByTier: {},
  totalCostUSD: 0,
  sessionCostToDate: 0,
  routingByTier: {},
  overrideCount: 0,
  reflexionEvents: [],
  avgCritiqueScore: 0,
  totSearches: [],
  avgNodesExplored: 0,
  systemStats: null,
  preTaskStats: {
    totalEstimates: 0,
    blockedCount: 0,
    lowConfidenceCount: 0,
    avgPreTaskConfidence: 0,
  },
}

/**
 * Merge one telemetry row into dashboard state (immutable).
 *
 * Handles 8 explicit telemetry event types + default no-op:
 * react_thought, react_action, react_observation,
 * confidence_scored, model_routed, reflexion_critique,
 * tot_search_complete, cost_warning
 * Previous spec comment said 7 ÔÇö implementation correctly handles 8.
 */
function _applyEvent(state: DashboardState, event: TelemetryEvent): DashboardState {
  const d = event.data
  const sessionId = event.sessionId
  const ts = event.timestamp
  const taskType = asString(d.taskType, 'unknown')

  switch (event.type) {
    case 'react_thought': {
      const thoughtType = asString(d.type, 'thought')
      const conf = asNumber(d.confidence)
      let content = `Thought ┬À ${thoughtType}`
      if (conf !== undefined) {
        content += ` (confidence ${conf.toFixed(2)})`
      }
      const entry: ReActTraceEntry = {
        sessionId,
        step: 'thought',
        content,
        taskType,
        timestamp: ts,
        ...(conf !== undefined ? { confidenceScore: conf } : {}),
      }
      return { ...state, recentTraces: appendCapped(state.recentTraces, entry, MAX_TRACES) }
    }
    case 'react_action': {
      const desc = asString(d.description, asString(d.actionType, 'action'))
      const entry: ReActTraceEntry = {
        sessionId,
        step: 'action',
        content: desc.length > 0 ? desc : 'Action',
        taskType,
        timestamp: ts,
      }
      return { ...state, recentTraces: appendCapped(state.recentTraces, entry, MAX_TRACES) }
    }
    case 'react_observation': {
      const status = asString(d.status, 'unknown')
      const meets = d.meetsExpectation
      let content = `Observation ┬À ${status}`
      if (typeof meets === 'boolean') {
        content += ` ┬À meetsExpectation: ${String(meets)}`
      }
      const entry: ReActTraceEntry = {
        sessionId,
        step: 'observation',
        content,
        taskType,
        timestamp: ts,
      }
      return { ...state, recentTraces: appendCapped(state.recentTraces, entry, MAX_TRACES) }
    }
    case 'confidence_scored': {
      const scalar = asNumber(d.scalar) ?? 0
      const point: ConfidencePoint = {
        timestamp: ts,
        scalar,
        level: asString(d.level, ''),
        action: asString(d.action, ''),
        taskType,
        sessionId,
      }
      return {
        ...state,
        confidenceHistory: appendCapped(state.confidenceHistory, point, MAX_CONFIDENCE),
        sessionConfidenceTrend: parseTrend(d.trend),
      }
    }
    case 'model_routed': {
      const tier = asString(d.tier, 'unknown')
      const est = asNumber(d.estimatedCostUSD) ?? 0
      const prevTier = state.costByTier[tier] ?? { calls: 0, costUSD: 0 }
      const costByTier = {
        ...state.costByTier,
        [tier]: { calls: prevTier.calls + 1, costUSD: prevTier.costUSD + est },
      }
      const routingByTier = {
        ...state.routingByTier,
        [tier]: (state.routingByTier[tier] ?? 0) + 1,
      }
      let overrideCount = state.overrideCount
      if (asBoolean(d.wasOverridden)) {
        overrideCount++
      }
      return {
        ...state,
        costByTier,
        routingByTier,
        overrideCount,
        totalCostUSD: state.totalCostUSD + est,
      }
    }
    case 'reflexion_critique': {
      const critiqueScore = asNumber(d.score) ?? 0
      const iteration = asNumber(d.iteration) ?? 0
      const ev: ReflexionEvent = {
        timestamp: ts,
        iteration,
        critiqueScore,
        passed: asBoolean(d.passed),
        taskType,
        sessionId,
      }
      const reflexionEvents = appendCapped(state.reflexionEvents, ev, MAX_REFLEXION)
      const avgCritiqueScore = average(reflexionEvents.map((e) => e.critiqueScore))
      return { ...state, reflexionEvents, avgCritiqueScore }
    }
    case 'tot_search_complete': {
      const nodesExplored = asNumber(d.nodesGenerated) ?? asNumber(d.nodesExplored) ?? 0
      const nodesPruned = asNumber(d.nodesPruned) ?? 0
      const bestScore = asNumber(d.bestScore) ?? 0
      const durationMs = asNumber(d.durationMs) ?? 0
      const summary: TotSearchSummary = {
        timestamp: ts,
        nodesExplored,
        nodesPruned,
        bestScore,
        taskType,
        durationMs,
      }
      const totSearches = appendCapped(state.totSearches, summary, MAX_TOT)
      const avgNodesExplored = average(totSearches.map((t) => t.nodesExplored))
      return { ...state, totSearches, avgNodesExplored }
    }
    case 'cost_warning': {
      const total = asNumber(d.totalCostUSD)
      return total !== undefined
        ? { ...state, sessionCostToDate: total, totalCostUSD: total }
        : state
    }
    case 'pre_task_confidence': {
      const conf = asNumber(d.confidence)
      const prev = state.preTaskStats
      const totalEstimates = prev.totalEstimates + 1
      const blockedCount = prev.blockedCount + (d.shouldProceed === false ? 1 : 0)
      const lowConfidenceCount =
        prev.lowConfidenceCount +
        (conf !== undefined && Number.isFinite(conf) && conf < 0.6 ? 1 : 0)
      const v =
        conf !== undefined && Number.isFinite(conf)
          ? conf
          : prev.totalEstimates === 0
            ? 0
            : prev.avgPreTaskConfidence
      const avgPreTaskConfidence =
        (prev.avgPreTaskConfidence * prev.totalEstimates + v) / totalEstimates
      return {
        ...state,
        preTaskStats: {
          totalEstimates,
          blockedCount,
          lowConfidenceCount,
          avgPreTaskConfidence,
        },
      }
    }
    default:
      return state
  }
}

function isTelemetryEventPayload(value: unknown): value is TelemetryEvent {
  if (value === null || typeof value !== 'object' || Array.isArray(value)) {
    return false
  }
  const o = value as Record<string, unknown>
  return (
    typeof o.type === 'string' &&
    typeof o.sessionId === 'string' &&
    o.data !== null &&
    typeof o.data === 'object' &&
    !Array.isArray(o.data) &&
    typeof o.timestamp === 'string'
  )
}

function applySnapshotToState(
  setState: Dispatch<SetStateAction<DashboardState>>,
  body: unknown,
): void {
  if (body === null || typeof body !== 'object' || Array.isArray(body)) {
    return
  }
  const stats = (body as { stats?: unknown }).stats
  if (stats !== undefined && stats !== null && typeof stats === 'object' && !Array.isArray(stats)) {
    setState((s) => ({ ...s, systemStats: stats as Record<string, unknown> }))
  }
}

async function fetchDashboardSnapshot(setState: Dispatch<SetStateAction<DashboardState>>): Promise<void> {
  try {
    const r = await fetch('/api/dashboard/snapshot')
    const body: unknown = await r.json()
    applySnapshotToState(setState, body)
  } catch {
    /* snapshot optional ÔÇö ignore */
  }
}

function onSseHeartbeat(
  setState: Dispatch<SetStateAction<DashboardState>>,
  e: MessageEvent<string>,
): void {
  try {
    const data = JSON.parse(e.data) as { ts?: string }
    const ts = typeof data.ts === 'string' ? data.ts : null
    setState((s) => ({ ...s, lastHeartbeat: ts }))
  } catch {
    /* ignore malformed heartbeat */
  }
}

function onSseTelemetry(
  setState: Dispatch<SetStateAction<DashboardState>>,
  e: MessageEvent<string>,
): void {
  try {
    const parsed: unknown = JSON.parse(e.data)
    if (isTelemetryEventPayload(parsed)) {
      setState((s) => _applyEvent(s, parsed))
    }
  } catch {
    /* ignore malformed telemetry */
  }
}

/**
 * Subscribes to Jarvis dashboard SSE (`/api/dashboard/stream`) and folds telemetry into {@link DashboardState}.
 * @param sessionId - Filter to one session, or `'all'` for every session (server-side filter).
 */
export default function useJarvisTelemetry(sessionId: string = 'all'): DashboardState {
  const [state, setState] = useState<DashboardState>(INITIAL_DASHBOARD_STATE)
  const eventSourceRef = useRef<EventSource | null>(null)

  useEffect(() => {
    setState({ ...INITIAL_DASHBOARD_STATE })

    const q = encodeURIComponent(sessionId)
    const es = new EventSource(`/api/dashboard/stream?sessionId=${q}`)
    eventSourceRef.current = es

    const onConnected = (): void => {
      setState((s) => ({ ...s, isConnected: true }))
      fetchDashboardSnapshot(setState).catch(() => {
        /* snapshot optional ÔÇö ignore */
      })
    }

    const onError = (): void => {
      setState((s) => ({ ...s, isConnected: false }))
    }

    es.addEventListener('connected', onConnected)
    es.addEventListener('heartbeat', (e) => onSseHeartbeat(setState, e))
    es.addEventListener('telemetry', (e) => onSseTelemetry(setState, e))
    es.onerror = onError

    return () => {
      eventSourceRef.current?.close()
      eventSourceRef.current = null
    }
  }, [sessionId])

  return state
}

import { useState, useEffect, useRef, useCallback } from 'react'

export interface ScreenVisionState {
  streaming: boolean
  stream: MediaStream | null
  error: string | null
}

/**
 * Live display capture for the Jarvis desktop shell. Requires user consent via getDisplayMedia;
 * main process can grant sources via `setDisplayMediaRequestHandler` (see jarvis-desktop-automation).
 */
export function useScreenVision() {
  const [state, setState] = useState<ScreenVisionState>({
    streaming: false,
    stream: null,
    error: null,
  })
  const videoRef = useRef<HTMLVideoElement | null>(null)
  const canvasRef = useRef<HTMLCanvasElement | null>(null)

  const startStream = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getDisplayMedia({
        video: { width: 1920, height: 1080, frameRate: 15 },
        audio: false,
      })
      setState({ streaming: true, stream, error: null })
      if (videoRef.current) {
        videoRef.current.srcObject = stream
        void videoRef.current.play()
      }
    } catch (err) {
      setState({ streaming: false, stream: null, error: String(err) })
    }
  }, [])

  const captureFrame = useCallback((): string | null => {
    const video = videoRef.current
    const canvas = canvasRef.current
    if (!video || !canvas || !state.streaming) return null
    canvas.width = video.videoWidth
    canvas.height = video.videoHeight
    const ctx = canvas.getContext('2d')
    if (!ctx) return null
    ctx.drawImage(video, 0, 0)
    return canvas.toDataURL('image/jpeg', 0.8)
  }, [state.streaming])

  const stopStream = useCallback(() => {
    setState((prev) => {
      prev.stream?.getTracks().forEach((t) => t.stop())
      return { streaming: false, stream: null, error: null }
    })
  }, [])

  useEffect(() => () => stopStream(), [stopStream])

  return { ...state, videoRef, canvasRef, startStream, stopStream, captureFrame }
}

