export async function transferUrlToStorage(url: string): Promise<string> {
  const res = await a2eFetch('/v1/tos/transferToStorage', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: a2eJsonBody({ url }),
