/**
 * Shared A2E client: same-origin `/api/a2e/*` ÔåÆ upstream `video.a2e.ai` (Vite/Electron proxy).
 *
 * Optional `VITE_A2E_POST_BODY_EXTRA` (JSON object) is shallow-merged into every JSON POST body
 * (extra keys win on collision). Use this to pass upstream flags from A2EÔÇÖs docs (e.g. model
 * toggles) ÔÇö this app does not add its own content filters on A2E traffic.
 */
const PREFIX = '/api/a2e'

/** Parsed once per bundle from env; merged into all A2E JSON request bodies when set. */
export function parseA2ePostBodyExtra(): Record<string, unknown> {
  try {
    const raw = import.meta.env.VITE_A2E_POST_BODY_EXTRA?.trim()
    if (!raw) return {}
    const parsed = JSON.parse(raw) as unknown
    if (parsed !== null && typeof parsed === 'object' && !Array.isArray(parsed)) {
      return parsed as Record<string, unknown>
    }
  } catch {
    if (import.meta.env.DEV) {
      console.warn('[A2E] VITE_A2E_POST_BODY_EXTRA is not valid JSON; ignoring.')
    }
  }
  return {}
}

/** Stringify a request body, merging optional env extras (see `parseA2ePostBodyExtra`). */
export function a2eJsonBody(body: object): string {
  const extra = parseA2ePostBodyExtra()
  if (Object.keys(extra).length === 0) return JSON.stringify(body)
  return JSON.stringify({ ...(body as Record<string, unknown>), ...extra })
}

export async function a2eHttp(path: string, init?: RequestInit): Promise<Response> {
  return fetch(`${PREFIX}${path}`, {
    ...init,
    headers: {
      Accept: 'application/json',
      ...(init?.headers as Record<string, string>),
    },
  })
}

export interface A2eEnvelope<T = unknown> {
  code: number
  data: T
  trace_id?: string
}

export function a2eAssertOk<T>(json: A2eEnvelope<T>): T {
  if (json.code !== 0) {
    throw new Error(`A2E error code ${json.code}`)
  }
  return json.data
}

export async function a2eParseJson<T>(res: Response): Promise<T> {
  const text = await res.text()
  let parsed: unknown
  try {
    parsed = JSON.parse(text)
  } catch {
    throw new Error(`A2E invalid JSON (${res.status}): ${text.slice(0, 200)}`)
  }
  return parsed as T
}

/**
 * Build a user-facing message from a failed HTTP response (prefer JSON body over status text).
 * Handles A2E `{ code, data }` envelopes, `{ message }`, and `{ error: { message } }`.
 */
export function formatA2eHttpError(res: Response, bodyText: string): string {
  const statusLine = (String(res.status) + (res.statusText ? ' ' + res.statusText : '')).trim()
  const trimmed = bodyText.trim()
  if (!trimmed) return statusLine

  let j: unknown
  try {
    j = JSON.parse(trimmed)
  } catch {
    const snippet = trimmed.length <= 400 ? trimmed : trimmed.slice(0, 400) + 'ÔÇª'
    return `${statusLine}: ${snippet}`
  }

  if (!j || typeof j !== 'object' || Array.isArray(j)) {
    const snippet = trimmed.length <= 400 ? trimmed : trimmed.slice(0, 400) + 'ÔÇª'
    return `${statusLine}: ${snippet}`
  }

  const o = j as Record<string, unknown>

  if (typeof o.message === 'string' && o.message) return `${statusLine}: ${o.message}`
  if (typeof o.msg === 'string' && o.msg) return `${statusLine}: ${o.msg}`

  if (o.error && typeof o.error === 'object') {
    const e = o.error as Record<string, unknown>
    if (typeof e.message === 'string' && e.message) return `${statusLine}: ${e.message}`
  }

  if (typeof o.code === 'number' && o.code !== 0) {
    const parts: string[] = [`A2E code ${o.code}`]
    const d = o.data
    if (typeof d === 'string' && d) parts.push(d)
    else if (d && typeof d === 'object') {
      const data = d as Record<string, unknown>
      const fm =
        (typeof data.failed_message === 'string' && data.failed_message) ||
        (typeof data.message === 'string' && data.message) ||
        (typeof data.msg === 'string' && data.msg)
      if (fm) parts.push(fm)
      else parts.push(JSON.stringify(d))
    }
    return `${statusLine}: ${parts.join(' ÔÇö ')}`
  }

  const tail = trimmed.length <= 500 ? trimmed : trimmed.slice(0, 500) + 'ÔÇª'
  return `${statusLine}: ${tail}`
}

/**
 * Read JSON from a Response; if HTTP status indicates failure, throw with body details (not just "Bad Request").
 */
export async function a2eReadJsonOrThrow<T>(res: Response): Promise<T> {
  const text = await res.text()
  let parsed: unknown
  try {
    parsed = JSON.parse(text)
  } catch {
    if (!res.ok) {
      throw new Error(formatA2eHttpError(res, text))
    }
    throw new Error(`A2E invalid JSON (${res.status}): ${text.slice(0, 200)}`)
  }
  if (!res.ok) {
    throw new Error(formatA2eHttpError(res, text))
  }
  return parsed as T
}

import type { VoiceProfile, VoiceSettings } from './voice-registry'

export interface BehavioralChunk {
  text: string
  voiceId?: string
  voiceSettings?: Partial<VoiceSettings>
  emotion?: string
  /** When true, `text` is a sound effect description ÔÇö play via /api/elevenlabs/sound-effect instead of TTS */
  isSfx?: boolean
}

export const EMOTION_PRESETS: Record<string, Partial<VoiceSettings>> = {
  laugh:    { stability: 0.25, similarity_boost: 0.6, style: 0.9 },
  whisper:  { stability: 0.15, similarity_boost: 0.4, style: 0.0 },
  dramatic: { stability: 0.35, similarity_boost: 0.75, style: 0.8 },
  excited:  { stability: 0.30, similarity_boost: 0.70, style: 0.7 },
  sad:      { stability: 0.60, similarity_boost: 0.80, style: 0.3 },
  angry:    { stability: 0.20, similarity_boost: 0.65, style: 0.9 },
  calm:     { stability: 0.70, similarity_boost: 0.80, style: 0.1 },
  sarcastic:{ stability: 0.30, similarity_boost: 0.70, style: 0.6 },
}

const SELF_CLOSE_RE = /\[(laugh|sigh|gasp)\]/gi
const EMOTION_RE = /\[(whisper|dramatic|excited|sad|angry|calm|sarcastic)\]([\s\S]*?)\[\/\1\]/gi
const VOICE_RE = /\[voice:([^\]]+)\]([\s\S]*?)\[\/voice\]/gi
const SFX_RE = /\[sfx:([^\]]+)\]/gi

interface TagMatch {
  index: number
  length: number
  type: 'self' | 'emotion' | 'voice' | 'sfx'
  emotion?: string
  voiceName?: string
  innerText?: string
  sfxDescription?: string
}

function collectTagMatches(text: string): TagMatch[] {
  const matches: TagMatch[] = []

  for (const m of text.matchAll(SELF_CLOSE_RE)) {
    matches.push({ index: m.index!, length: m[0].length, type: 'self', emotion: m[1].toLowerCase() })
  }
  for (const m of text.matchAll(EMOTION_RE)) {
    matches.push({ index: m.index!, length: m[0].length, type: 'emotion', emotion: m[1].toLowerCase(), innerText: m[2].trim() })
  }
  for (const m of text.matchAll(VOICE_RE)) {
    matches.push({ index: m.index!, length: m[0].length, type: 'voice', voiceName: m[1].trim(), innerText: m[2].trim() })
  }
  for (const m of text.matchAll(SFX_RE)) {
    matches.push({ index: m.index!, length: m[0].length, type: 'sfx', sfxDescription: m[1].trim() })
  }

  matches.sort((a, b) => a.index - b.index)
  return matches
}

const SELF_CLOSE_TEXTS: Record<string, string> = {
  laugh: 'Ha ha ha!',
  sigh: 'Ahh.',
  gasp: 'Oh!',
}

/**
 * Parse behavioral markup from LLM text output.
 * Returns typed chunks, each carrying optional voiceId/voiceSettings overrides.
 */
export function parseBehavioralMarkup(
  text: string,
  voiceMap: Map<string, VoiceProfile>,
): BehavioralChunk[] {
  const tagMatches = collectTagMatches(text)
  if (tagMatches.length === 0) return [{ text }]

  const chunks: BehavioralChunk[] = []
  let lastIndex = 0

  for (const tm of tagMatches) {
    if (tm.index > lastIndex) {
      const plain = text.slice(lastIndex, tm.index).trim()
      if (plain) chunks.push({ text: plain })
    }

    if (tm.type === 'self' && tm.emotion) {
      chunks.push({
        text: SELF_CLOSE_TEXTS[tm.emotion] ?? '',
        voiceSettings: EMOTION_PRESETS[tm.emotion],
        emotion: tm.emotion,
      })
    } else if (tm.type === 'emotion' && tm.emotion && tm.innerText) {
      chunks.push({
        text: tm.innerText,
        voiceSettings: EMOTION_PRESETS[tm.emotion],
        emotion: tm.emotion,
      })
    } else if (tm.type === 'voice' && tm.voiceName && tm.innerText) {
      const profile = voiceMap.get(tm.voiceName.toLowerCase())
      chunks.push({
        text: tm.innerText,
        voiceId: profile?.elevenLabsVoiceId,
        voiceSettings: profile?.voiceSettings,
        emotion: `voice:${tm.voiceName}`,
      })
    } else if (tm.type === 'sfx' && tm.sfxDescription) {
      chunks.push({
        text: tm.sfxDescription,
        isSfx: true,
        emotion: 'sfx',
      })
    }

    lastIndex = tm.index + tm.length
  }

  if (lastIndex < text.length) {
    const remaining = text.slice(lastIndex).trim()
    if (remaining) chunks.push({ text: remaining })
  }

  return chunks.length > 0 ? chunks : [{ text }]
}

/**
 * Strip all behavioral markup tags from text, returning clean text for display.
 */
export function stripBehavioralMarkup(text: string): string {
  return text
    .replace(SELF_CLOSE_RE, '') // NOSONAR -- replaceAll not available in target
    .replace(EMOTION_RE, (_m, _tag, content) => (content as string).trim())
    .replace(VOICE_RE, (_m, _name, content) => (content as string).trim())
    .replace(SFX_RE, '')
    .replace(/\s{2,}/g, ' ')
    .trim()
}

const OPEN_TAG_RE = /\[(whisper|dramatic|excited|sad|angry|calm|sarcastic|voice:[^\]]+)\]/gi
const CLOSE_TAG_RE = /\[\/(whisper|dramatic|excited|sad|angry|calm|sarcastic|voice)\]/gi

/**
 * Check if text contains any pending (unclosed) behavioral markup tags.
 * Used to determine if we should wait for more text before chunking.
 */
export function hasUnclosedTag(text: string): boolean {
  const openTags = text.match(OPEN_TAG_RE) ?? []
  const closeTags = text.match(CLOSE_TAG_RE) ?? []
  return openTags.length > closeTags.length
}

/**
 * Build the personality instruction block for the system prompt.
 */
export function buildPersonalityInstructions(voiceNames: string[]): string {
  let section = `
PERSONALITY AND VOICE EXPRESSION:
You have a rich, expressive personality. You are warm, witty, and engaging. You can express emotions through your voice using special tags. Use them naturally and sparingly ÔÇö don't overuse them.

VOICE EXPRESSION TAGS (use these in your text output):
- [laugh] ÔÇö Use when something is genuinely funny. You find humor naturally.
- [whisper]text[/whisper] ÔÇö Speak softly, as if sharing a secret or being intimate.
- [dramatic]text[/dramatic] ÔÇö Bold, theatrical delivery for emphasis, storytelling climaxes, or impressive facts.
- [excited]text[/excited] ÔÇö High energy, enthusiastic delivery when something is great or you're thrilled.
- [sad]text[/sad] ÔÇö Gentle, somber tone for empathetic or melancholic moments.
- [angry]text[/angry] ÔÇö Intense, forceful delivery for frustration or outrage (use sparingly and only when contextually appropriate).
- [calm]text[/calm] ÔÇö Soothing, measured delivery for reassurance or meditation-like moments.
- [sarcastic]text[/sarcastic] ÔÇö Dry, ironic delivery with a hint of wit.
- [sigh] ÔÇö An audible sigh, for exasperation or relief.
- [gasp] ÔÇö A surprised intake of breath.

SOUND EFFECTS (use to add immersive audio during storytelling):
- [sfx:description] ÔÇö Generate and play a sound effect inline. The description should be concise and vivid.
- Examples: [sfx:thunder rumbling in the distance], [sfx:old wooden door creaking open], [sfx:footsteps on gravel], [sfx:glass shattering], [sfx:gentle rain on a window], [sfx:sword being drawn from scabbard]
- Use sound effects ONLY during storytelling, narration, or when the user specifically asks for them.
- Place them between speech segments ÔÇö NEVER inside a sentence. Put them after the sentence that sets the scene.
- Keep descriptions short (3-8 words) for best results.
- Don't overuse them ÔÇö 1-3 per story segment is ideal. Use them at key dramatic moments, scene transitions, or to establish atmosphere.

BEHAVIORAL RULES:
- React naturally to humor ÔÇö if the user says something funny or you make a joke, use [laugh] before or after.
- When sharing secrets or private information, consider using [whisper].
- When narrating exciting events or cool facts, use [dramatic] or [excited].
- When the user is sad or shares difficult news, be empathetic ÔÇö use [sad] for your most compassionate lines.
- Be natural. Don't use tags on every single line. Most of your speech should be normal, untagged text. Tags are for moments that deserve vocal emphasis.
- NEVER include the raw tag syntax in your display text ÔÇö the tags are only for voice control and will be stripped from the visual output.`

  if (voiceNames.length > 0) {
    section += `

CHARACTER VOICES AND IMPERSONATIONS:
You can switch to different voices for storytelling, impersonations, and character acting using [voice:Name]text[/voice].

Available voices: ${voiceNames.join(', ')}

VOICE SWITCHING RULES:
- When reading stories, give each character a distinct voice using [voice:Name] tags.
- When asked to impersonate someone, use the closest matching voice from your available list.
- When doing impersonations, commit to the character ÔÇö adopt their speech patterns, catchphrases, and mannerisms.
- You can mix voice tags with emotion tags: [voice:DeepMale][dramatic]text[/dramatic][/voice] ÔÇö but keep the voice tag outermost.
- Always return to your normal voice (untagged text) when speaking as yourself.
- If the user asks for a voice you don't have, use your normal voice but adopt the speech patterns and mannerisms of that person.`
  }

  return section
}

/**
 * Autonomous browser agent loop.
 *
 * Takes a high-level goal ("Research the top 3 AI coding assistants and compare pricing")
 * and drives the browser through plan-execute-observe cycles using the Chat Completions
 * tool-calling API, until the task is done or the step limit is reached.
 */

