}

export interface AgentRunOptions {
  maxSteps?: number
  model?: string
  guideMode?: boolean
  /** When set, controls spoken output: guide = narrate model ÔÇ£thinkingÔÇØ; copilot = short per-action lines; off = silent. */
  voiceGuidanceMode?: 'copilot' | 'guide' | 'off'
  onStep?: (step: AgentStep) => void
  onThinking?: (thought: string) => void
  /** Fire-and-forget TTS hook (e.g. playTts). Copilot: one short line per action; guide: one line per model turn. */
  onSpeakNarration?: (text: string) => void
  signal?: AbortSignal
