export function ideJoinPath(root: string, ...parts: string[]): string {
  const sep = root.includes('\\') ? '\\' : '/'
  const clean = (s: string) => s.replaceAll(/^[\\/]+|[\\/]+$/g, '')
  return [clean(root), ...parts.map(clean)].filter(Boolean).join(sep)
}

