function lineOfIndex(code: string, index: number): number {
  return code.slice(0, index).split(/\r?\n/).length
}

function pushIssue(
  issues: MissingLogicIssue[],
  code: string,
  id: MissingLogicDetectionId,
  message: string,
  index?: number
) {
  issues.push({
    id,
    message,
    line: index !== undefined && index >= 0 ? lineOfIndex(code, index) : undefined,
  })
}

function scanTsJsLike(code: string, filename: string, issues: MissingLogicIssue[]) {
  // Unreachable after return/throw
  const unreachable = /(?:return|throw)\s+[^;]+;\s*\n\s*([^\s}])/gm
  let m: RegExpExecArray | null
  while ((m = unreachable.exec(code)) !== null) {
    if (!/^(case|default|if|\/\/|\/\*|\})/.test(m[1])) {
      pushIssue(issues, code, 'unreachable-code', 'Possible unreachable code after return/throw', m.index)
    }
  }

  // Typed function without return (heuristic)
  if (/\bfunction\s+\w+\s*\([^)]*\)\s*:\s*(?!void\b)(?:string|number|boolean|\w+)\s*\{/.test(code)) {
    const fnStart = code.search(/\bfunction\s+\w+/)
    const brace = code.indexOf('{', fnStart)
    if (brace > 0) {
      const chunk = code.slice(brace, brace + 800)
      if (!/\breturn\b/.test(chunk)) {
        pushIssue(issues, code, 'missing-return', 'Function with return type may be missing return', fnStart)
      }
    }
  }
  // switch: missing default
  if (/\bswitch\s*\(/.test(code) && !/\bdefault\s*:/.test(code)) {
    pushIssue(issues, code, 'missing-default', 'switch has no default branch', code.indexOf('switch'))
  }

  // switch case without break/return (heuristic: case followed by case)
  const caseBlocks = code.split(/\bcase\s+/g)
  if (caseBlocks.length > 1) {
    for (let i = 1; i < caseBlocks.length; i++) {
      const segment = caseBlocks[i].split(':')[1] || ''
      const untilNext = segment.split(/\bcase\b|\bdefault\b/)[0] || ''
      if (
        untilNext.length > 10 &&
        !/\b(break|return|throw)\s*[;\n]/.test(untilNext) &&
        /[a-zA-Z_$]/.test(untilNext)
      ) {
        pushIssue(issues, code, 'missing-break', 'switch case may fall through without break/return', code.indexOf('case'))
        break
      }
    }
  }

  // if without else (optional ÔÇö flag only deep nesting)
  if (/\bif\s*\([^)]+\)\s*\{[^}]{30,}\}\s*if\s*\(/.test(code) && !/\belse\b/.test(code.slice(code.search(/\bif\s*\(/), code.search(/\bif\s*\(/)+400))) {
    pushIssue(issues, code, 'missing-else', 'Consecutive if chains may need else', code.search(/\bif\s*\(/))
  }

  // Empty condition
  if (/\bif\s*\(\s*\)/.test(code) || /\bwhile\s*\(\s*\)/.test(code)) {
    pushIssue(issues, code, 'incomplete-conditionals', 'Empty if/while condition', code.search(/\bif\s*\(\s*\)/))
  }

  // async function with fetch/promise without await
  if (/\basync\s+function|\basync\s*\(/.test(code)) {
    if (/\bfetch\s*\(/.test(code) && !/\bawait\s+fetch/.test(code)) {
      const idx = code.indexOf('fetch')
      if (idx >= 0) pushIssue(issues, code, 'missing-await', 'fetch() in async context may need await', idx)
    }
    if (/\.then\s*\(/.test(code) && !/\bawait\b/.test(code.split('.then')[0].slice(-80))) {
      pushIssue(issues, code, 'missing-await', 'Promise chain in async code may use await', code.indexOf('.then'))
    }
  }

  // Promise without catch
  if (/\.then\s*\([^)]+\)(?!\.catch)/.test(code.replaceAll(/\s+/g, ' ')) && /\.then/.test(code) && !/\.catch/.test(code)) {
    pushIssue(issues, code, 'missing-error-handling', 'Promise chain missing .catch()', code.indexOf('.then'))
  }

  // try without catch
  if (/\btry\s*\{/.test(code) && !/\bcatch\s*\(/.test(code)) {
    pushIssue(issues, code, 'missing-try-catch', 'try block without catch', code.indexOf('try'))
  }

  // process.env without fallback
  if (/process\.env\.\w+/.test(code) && !/process\.env\.\w+\s*\?\?/.test(code) && !/process\.env\.\w+\s*\|\|/.test(code)) {
    pushIssue(issues, code, 'missing-environment-variables', 'process.env access may need default (?? or ||)', code.search(/process\.env/))
  }

  // while(true)
  if (/\bwhile\s*\(\s*true\s*\)/.test(code)) {
    const sub = /\bwhile\s*\(\s*true\s*\)\s*\{[\s\S]*?\b(break|return)/.exec(code)
    if (!sub) pushIssue(issues, code, 'infinite-loops', 'while(true) without obvious break/return', code.search(/while\s*\(\s*true/))
  }

  // Recursion without base case (very rough)
  if (/\bfunction\s+(\w+)\s*\([^)]*\)\s*\{[\s\S]*?\b\1\s*\(/.test(code)) {
    const fn = /\bfunction\s+(\w+)/.exec(code)
    if (fn && !new RegExp(String.raw`\bif\s*\([^)]*${fn[1]}`).test(code)) {
      pushIssue(issues, code, 'unbounded-recursion', 'Recursive call with no obvious base-case guard', code.indexOf('function'))
    }
  }

  // setTimeout 0 loop
  if (/setInterval\s*\(/.test(code) && !/clearInterval/.test(code)) {
    pushIssue(issues, code, 'missing-timeout-handling', 'setInterval without clearInterval in file', code.indexOf('setInterval'))
  }

  // Express route without status
  if (/res\.(json|send)\s*\(/.test(code) && /\.(get|post|put|delete)\s*\(/.test(code) && !/res\.status\s*\(/.test(code)) {
    pushIssue(issues, code, 'missing-http-status-codes', 'Route handler may need explicit res.status()', code.search(/\.(get|post)\s*\(/))
  }

  // API handler without validation
  if (/req\.body/.test(code) && !/zod|joi|yup|validate|schema/i.test(code)) {
    pushIssue(issues, code, 'missing-validation', 'req.body used without obvious validation library', code.indexOf('req.body'))
  }

  if (/useEffect\s*\(\s*\(\)\s*=>/.test(code)) {
    const eff = /useEffect\s*\([\s\S]*?\)/.exec(code)
    if (eff && !eff[0].includes('[') && eff[0].length < 200) {
      pushIssue(issues, code, 'missing-parameters', 'useEffect may be missing dependency array as second argument', code.indexOf('useEffect'))
    }
  }

  if (/@Injectable\s*\(\s*\)/.test(code) && /class\s+\w+/.test(code) && !/constructor\s*\(/.test(code)) {
    pushIssue(issues, code, 'missing-dependency-injection', 'Injectable class without constructor injection', code.indexOf('@Injectable'))
  }

  if (/useContext\s*\(/.test(code) && !/createContext/.test(code) && /tsx?$/.test(filename)) {
    pushIssue(issues, code, 'missing-context-providers', 'useContext used; ensure Provider wraps tree', code.indexOf('useContext'))
  }

  if (/useSelector\s*\(/.test(code) && !/useDispatch/.test(code) && /dispatch/.test(code) === false) {
    pushIssue(issues, code, 'missing-redux-dispatches', 'useSelector without useDispatch in same module', code.indexOf('useSelector'))
  }

  if (/useState\s*\(/.test(code) && /router|navigate|push/.test(code) && !/reset|setState\(\s*\(\)\s*=>/.test(code)) {
    pushIssue(issues, code, 'missing-state-resets', 'Navigation with state ÔÇö consider reset on route change', code.indexOf('useState'))
  }

  // Layer imports (path heuristic)
  if (/\/domain\//i.test(filename) && /from\s+['"][^'"]*\/(components|ui)\//i.test(code)) {
    pushIssue(issues, code, 'domain-layer-violations', 'Domain file imports UI layer', 0)
  }
  if (/\/(components|ui)\//i.test(filename) && /from\s+['"][^'"]*\/domain\/[^'"]*service/i.test(code)) {
    pushIssue(issues, code, 'ui-layer-violations', 'UI file imports domain service directly (bypass adapter?)', 0)
  }
  if (/\/repository\//i.test(filename) && /\.queryRaw\s*\(/.test(code)) {
    pushIssue(issues, code, 'repository-misuse', 'Raw query in repository layer', code.indexOf('queryRaw'))
  }
  if (/\bclass\s+\w+\s*\{[\s\S]*\b(router|express)\b/.test(code) && /\.(get|post)/.test(code)) {
    pushIssue(issues, code, 'controller-logic-in-models', 'HTTP routing mixed into model-like class', code.indexOf('class'))
  }

  // GraphQL
  if (filename.endsWith('.graphql') || filename.endsWith('.gql')) {
    if (/type\s+Query/.test(code) && !/Query\s*:\s*\{/.test(code) && !code.includes('resolver')) {
      pushIssue(issues, code, 'missing-graphql-resolvers', 'Schema may need resolver wiring on server', 0)
    }
  }

  // REST server
  if (/express\s*\(/.test(code) || /from\s+['"]express['"]/.test(code)) {
    if (!/app\.(get|post|put|delete|patch)\s*\(/.test(code)) {
      pushIssue(issues, code, 'missing-rest-endpoints', 'Express app has no route registrations', code.indexOf('express'))
    }
    if (!/\/health|healthcheck/i.test(code)) {
      pushIssue(issues, code, 'missing-health-checks', 'No /health route detected', 0)
    }
  }

  // WebSocket
  if (/WebSocket|ws['"]/.test(code) && !/on\s*\(\s*['"]message['"]/.test(code)) {
    pushIssue(issues, code, 'missing-websocket-handlers', 'WebSocket without message handler', code.indexOf('WebSocket'))
  }

  // Imports
  const importLines = code.match(/^import\s+.+$/gm) || []
  const specifiers = new Map<string, number>()
  for (const line of importLines) {
    const names = [...line.matchAll(/\b(\w+)\b/g)].map((x) => x[1]!)
    for (const n of names) {
      if (['import', 'from', 'type', 'as'].includes(n)) continue
      specifiers.set(n, (specifiers.get(n) || 0) + 1)
    }
  }
  for (const [name, count] of specifiers) {
    if (count === 1 && !new RegExp(String.raw`\b${name}\b`).test(code.replaceAll(/^import\s+.+$/gm, ''))) {
      if (name.length > 2 && /^[A-Z]/.test(name)) {
        pushIssue(issues, code, 'unused-imports', `Import "${name}" may be unused`, code.indexOf(name))
        break
      }
    }
  }

  if (importLines.length > 0) {
    const froms = [...code.matchAll(/from\s+['"]([^'"]+)['"]/g)].map((x) => x[1]!)
    for (const f of froms) {
      if (f.startsWith('.') && f.includes('/../') && /\.\.\/\.\.\/\.\./.test(f)) {
        pushIssue(issues, code, 'incorrect-import-paths', `Deep relative import ${f}`, code.indexOf(f))
        break
      }
    }
    const dup = froms.filter((f, i) => froms.indexOf(f) !== i)
    if (dup.length && dup[0]) pushIssue(issues, code, 'missing-imports', 'Duplicate import from same path ÔÇö consolidate', code.indexOf(dup[0]))
  }

  if (importLines.length >= 2) {
    const a = /from\s+['"]([^'"]+)['"]/.exec(importLines[0] ?? '')?.[1]
    const b = /from\s+['"]([^'"]+)['"]/.exec(importLines[1] ?? '')?.[1]
    if (a && b && a === b) pushIssue(issues, code, 'circular-imports', 'Same module imported twice ÔÇö possible circularity risk', 0)
  }

  // Optional chaining gaps
  if (/\w+\.\w+\.\w+/.test(code) && !/\?\.|\|\||\?\?/.test(code.split('\n').slice(0, 15).join('\n'))) {
    pushIssue(issues, code, 'missing-null-checks', 'Deep property access without optional chaining or guards', 0)
  }

  if (/\bundefined\b/.test(code) && !/(===\s*undefined|\?\?|typeof\s+\w+\s*===)/.test(code)) {
    pushIssue(issues, code, 'missing-undefined-checks', 'undefined referenced ÔÇö consider explicit checks', code.indexOf('undefined'))
  }

  if (/\.length\s*[<>=]/.test(code) && !/\bif\s*\([^)]*length/.test(code) && /\[0\]/.test(code)) {
    pushIssue(issues, code, 'missing-boundary-checks', 'Array index access ÔÇö verify length/bounds', code.indexOf('[0]'))
  }

  if (/fetch\s*\(|axios\.|http\.get/.test(code) && !/AbortSignal|timeout|signal:/i.test(code)) {
    pushIssue(issues, code, 'missing-timeout-handling', 'HTTP client call without timeout/AbortSignal', code.search(/fetch|axios/))
  }

  if (/fetch\s*\(/.test(code) && !/429|rate|throttle/i.test(code)) {
    pushIssue(issues, code, 'missing-rate-limit-handling', 'Network call without rate-limit handling comment/guard', code.indexOf('fetch'))
  }

  // sync while loop
  if (/\bwhile\s*\([^)]+\)\s*\{(?![\s\S]*await)/.test(code) && /while/.test(code)) {
    const w = code.indexOf('while')
    if (w >= 0 && !/async/.test(code.slice(0, w))) {
      pushIssue(issues, code, 'blocking-operations', 'Synchronous while loop may block event loop', w)
    }
  }

  // Missing fallback
  if (/\?\./.test(code) === false && /\|\|\s*['"]{2}/.test(code) === false && /JSON\.parse/.test(code)) {
    pushIssue(issues, code, 'missing-fallback-logic', 'JSON.parse without try/catch or fallback', code.indexOf('JSON.parse'))
  }

  // Tests
  if (/\.(test|spec)\.(tsx?|jsx?)$/i.test(filename) || /__tests__/.test(filename)) {
    if (/describe\s*\(/.test(code) && !/it\s*\(|test\s*\(/.test(code)) {
      pushIssue(issues, code, 'missing-assertions', 'describe without it/test', code.indexOf('describe'))
    }
    if (/it\s*\(/.test(code) && !/expect\s*\(/.test(code)) {
      pushIssue(issues, code, 'missing-assertions', 'test case without expect()', code.indexOf('it'))
    }
    if (!/afterEach|afterAll|cleanup/.test(code) && /render\s*\(/.test(code)) {
      pushIssue(issues, code, 'missing-cleanup', 'Test renders component ÔÇö consider cleanup', code.indexOf('render'))
    }
    if (/toMatchSnapshot/.test(code) && !/update.*snapshot/i.test(code) && /#.*snapshot/i.test(code) === false) {
      pushIssue(issues, code, 'missing-snapshot-updates', 'Snapshot matcher present ÔÇö verify updates on change', code.indexOf('toMatchSnapshot'))
    }
    if (/\.skip\(|xit\(|xdescribe/.test(code)) {
      pushIssue(issues, code, 'tests-outdated-behavior', 'Skipped tests may be outdated', code.search(/\.skip|xit/))
    }
    if (/function\s+foo|bar\s*\(/.test(code) && /import.*removed/i.test(code) === false) {
      /* placeholder for ref removed ÔÇö heuristic string */
    }
    if (/not\.toThrow|toThrow/.test(code) === false && /it\s*\(/.test(code)) {
      pushIssue(issues, code, 'missing-assertions', 'Consider explicit error assertions for risky code', 0)
    }
  } else if (!/\.(test|spec)\./i.test(filename) && /export\s+(async\s+)?function|export\s+const\s+\w+\s*=/.test(code) && !/\.test\.|__tests__/.test(filename)) {
    pushIssue(issues, code, 'missing-tests', 'Source file has exports but no co-located test heuristic', 0)
  }

  // Interface / implements
  if (/\bclass\s+\w+\s+implements\s+(\w+)/.test(code)) {
    const impl = /\bimplements\s+(\w+)/.exec(code)
    if (impl && !new RegExp(String.raw`\b${impl[1]}\b`).test(code.slice(code.indexOf('{')))) {
      pushIssue(issues, code, 'missing-interface-implementation', 'Class implements interface ÔÇö verify all members', code.indexOf('implements'))
    }
  }

  if (/interface\s+\w+\s*\{/.test(code) && /export/.test(code) && !/\bimplements\b/.test(code)) {
    pushIssue(issues, code, 'mismatched-ts-interfaces', 'Public interface ÔÇö ensure consumers match', code.indexOf('interface'))
  }

  // DTO / API
  if (/z\.object\s*\(/.test(code) && !/\.strict\s*\(/.test(code)) {
    pushIssue(issues, code, 'missing-schema-validation', 'Zod object ÔÇö consider .strict()', code.indexOf('z.object'))
  }

  if (/res\.json\s*\(\s*\{/.test(code) && !/status\s*\(/.test(code.slice(0, code.indexOf('res.json') + 200))) {
    pushIssue(issues, code, 'missing-response-fields', 'res.json with object ÔÇö document expected shape', code.indexOf('res.json'))
  }

  if (/res\.(json|send)\s*\(/.test(code) && /\.(get|post|put|delete)\s*\(/.test(code) && !/catch\s*\(/.test(code) && !/next\s*\(/.test(code)) {
    pushIssue(issues, code, 'missing-error-responses', 'Route handler may need explicit error response path', code.search(/\.(get|post)\s*\(/))
  }

  if (/fetch\s*\(\s*['"]\/api/.test(code) && !/\.json\s*\(\s*\)/.test(code)) {
    pushIssue(issues, code, 'missing-api-responses', 'fetch to /api may need response body handling', code.indexOf('fetch'))
  }

  if (/:\s*\w+Dto\b/.test(code) && /as\s+\w+/.test(code) === false) {
    pushIssue(issues, code, 'mismatched-dtos', 'DTO type name ÔÇö verify mapping to API contract', code.search(/Dto\b/))
  }

  if (/status\s*\(\s*5\d\d/.test(code) === false && /throw\s+new\s+Error/.test(code) && /express|app/.test(code)) {
    pushIssue(issues, code, 'missing-error-codes', 'Errors thrown without structured error code / status', code.indexOf('throw'))
  }

  if (/axios\.|fetch\s*\(/.test(code) && !/interface\s+\w+Response/.test(code) && !/type\s+\w+Response/.test(code)) {
    pushIssue(issues, code, 'mismatched-api-types', 'HTTP client without obvious Response type in module', 0)
  }

  if (/\/(api|routes)\//i.test(filename) && /prisma\.|mongoose\.|sequelize\.|queryRaw/.test(code) && !/Service/.test(code)) {
    pushIssue(issues, code, 'service-bypass', 'Route file may be calling DB/ORM directly ÔÇö use service/repository layer', 0)
  }

  if (/\bRepository\b/.test(code) && !/\bimplements\b/.test(code) && /class\s+\w+Repository/.test(code)) {
    pushIssue(issues, code, 'missing-repository-implementation', 'Repository class ÔÇö verify interface contract', code.indexOf('Repository'))
  }

  if (/interface\s+\w+Adapter\b/.test(code) && !/(implements|implements)\s+\w+Adapter/.test(code)) {
    pushIssue(issues, code, 'missing-adapter', 'Adapter interface declared ÔÇö verify implementation', code.indexOf('Adapter'))
  }

  if (/Factory\s*\{/.test(code) && !/\bcreate\s*\(/.test(code)) {
    pushIssue(issues, code, 'missing-factory', 'Factory-like object without create/build method', code.indexOf('Factory'))
  }

  if (/createContext\s*\(/.test(code) && !/\.Provider/.test(code)) {
    pushIssue(issues, code, 'missing-provider', 'createContext without .Provider usage in file', code.indexOf('createContext'))
  }

  if (/z\.object\s*\(\s*\{/.test(code) && !/required\s*\(/.test(code) && !/\.min\s*\(/.test(code)) {
    pushIssue(issues, code, 'missing-required-fields', 'Zod schema ÔÇö mark required fields explicitly', code.indexOf('z.object'))
  }

  if (/\.(test|spec)\.(tsx?|jsx?)$/i.test(filename) && /from\s+['"]/.test(code) && !/jest\.mock|vi\.mock/.test(code)) {
    pushIssue(issues, code, 'missing-mocks', 'Test file imports modules ÔÇö consider mocks for external deps', 0)
  }

  if (/describe\s*\(/.test(code) && /removed|deprecated|TODO:\s*rename/i.test(code)) {
    pushIssue(issues, code, 'tests-ref-removed-code', 'Test comment may reference removed/deprecated code', code.search(/removed|deprecated/i))
  }

  if (/\.(test|spec)\./i.test(filename) && /function\s+\w+\s*\(/.test(code) && /\.(tsx?|jsx?)$/i.test(code) === false) {
    pushIssue(issues, code, 'tests-ref-renamed-functions', 'Test may reference old function names ÔÇö verify against source', 0)
  }

  if (/setInterval\s*\(/.test(code) && !/clearInterval/.test(code) && !/\d{3,}/.test(code.split('setInterval')[1]?.slice(0, 40) || '')) {
    pushIssue(issues, code, 'missing-throttling', 'setInterval without obvious delay ÔÇö verify throttling', code.indexOf('setInterval'))
  }

  if (/\breturn\s+true;/.test(code) && /\)\s*:\s*string\b/.test(code)) {
    pushIssue(issues, code, 'mismatched-return-types', 'Return value may not match annotated return type', code.indexOf('return'))
  }

  if (/from\s+['"]\s*['"]/.test(code)) {
    pushIssue(issues, code, 'missing-imports', 'Empty module path in import', code.search(/from\s+['"]\s*['"]/))
  }

  if (/async\s+function\s+\w+/.test(code) && /Promise\s*</.test(code) && !/\breturn\b/.test(code.split('{').pop()?.slice(0, 1500) || '')) {
    pushIssue(issues, code, 'missing-return-values', 'Async function / Promise type without return in body (heuristic)', code.search(/async/))
  }

  if (/useState\s*\(/.test(code) && /useEffect\s*\(/.test(code) && !/set\w+\s*\(/.test(code.split('useEffect')[1]?.slice(0, 400) || '')) {
    pushIssue(issues, code, 'missing-state-updates', 'useEffect block may need state setter calls', code.indexOf('useEffect'))
  }

  if (/\blet\s+(\w+)\s*;/.test(code)) {
    const lm = /\blet\s+(\w+)\s*;/.exec(code)
    const name = lm?.[1]
    if (name) {
      if (new RegExp(String.raw`\b${name}\b`).test(code) && !new RegExp(String.raw`\b${name}\s*=`).test(code)) {
        pushIssue(issues, code, 'uninitialized-variables', `let ${name} may be used without assignment`, code.indexOf('let'))
      }
      const idx = code.indexOf(`let ${name};`)
      if (idx >= 0) {
        const after = code.slice(idx + `let ${name};`.length, idx + 200)
        if (new RegExp(String.raw`\b${name}\b`).test(after) && !after.includes(`${name} =`)) {
          pushIssue(issues, code, 'use-before-assignment', `Variable ${name} may be used before assignment`, idx)
        }
      }
    }
  }
}

function scanPython(code: string, issues: MissingLogicIssue[]) {
  if (/\bdef\s+\w+\s*\([^)]*\)\s*->\s*None\s*:/.test(code) && /\breturn\b/.test(code) === false) {
    pushIssue(issues, code, 'missing-return', 'Function annotated -> None but may need explicit return', code.indexOf('def'))
  }
  if (/\bwhile\s+True\s*:/.test(code) && !/\bbreak\b/.test(code.split('while True')[1] || '')) {
    pushIssue(issues, code, 'infinite-loops', 'while True without break in scope', code.indexOf('while True'))
  }
  if (/requests\.(get|post)/.test(code) && !/timeout\s*=/.test(code)) {
    pushIssue(issues, code, 'missing-timeout-handling', 'requests call without timeout=', code.indexOf('requests'))
  }
}

function scanWorkspace(ctx: MissingLogicWorkspaceContext, issues: MissingLogicIssue[]) {
  const files = ctx.workspaceRelFiles || []
  const lower = files.map((f) => f.toLowerCase())

  if (!lower.some((f) => f.includes('dockerfile') || f.endsWith('dockerfile'))) {
    if (files.length > 5) pushIssue(issues, '', 'missing-docker-instructions', 'No Dockerfile in workspace file list')
  }
  if (!lower.some((f) => f.includes('k8s') || f.includes('kubernetes') || /deployment\.ya?ml/.test(f))) {
    if (files.length > 20 && lower.some((f) => f.includes('package.json'))) {
      pushIssue(issues, '', 'missing-kubernetes-manifests', 'No Kubernetes manifests detected in tree')
    }
  }

  if (ctx.packageJsonContent) {
    try {
      const pkg = JSON.parse(ctx.packageJsonContent) as {
        scripts?: Record<string, string>
        peerDependencies?: Record<string, string>
        devDependencies?: Record<string, string>
        dependencies?: Record<string, string>
      }
      if (!pkg.scripts?.build && !pkg.scripts?.compile) {
        pushIssue(issues, '', 'missing-build-scripts', 'package.json has no build/compile script')
      }
      const peers = Object.keys(pkg.peerDependencies || {})
      for (const p of peers) {
        const inDeps = pkg.dependencies?.[p] || pkg.devDependencies?.[p]
        if (!inDeps) pushIssue(issues, '', 'missing-peer-dependencies', `Peer "${p}" not in dependencies/devDependencies`)
      }
      const needTypes = ['express', 'react', 'lodash']
      for (const n of needTypes) {
        if (pkg.dependencies?.[n] && !pkg.devDependencies?.[`@types/${n}`] && n === 'express') {
          pushIssue(issues, '', 'missing-type-definitions', 'Consider @types for installed packages')
        }
      }
    } catch {
      /* ignore */
    }
  }

  if (ctx.tsconfigContent) {
    if (!/"paths"\s*:/.test(ctx.tsconfigContent)) {
      pushIssue(issues, '', 'missing-tsconfig-paths', 'tsconfig has no paths aliases')
    }
  }

  if (!lower.some((f) => f.includes('webpack') || f.includes('vite.config') || f.includes('rollup'))) {
    if (lower.some((f) => f.endsWith('tsx') || f.endsWith('jsx')) && files.length > 10) {
      pushIssue(issues, '', 'missing-bundler-config', 'No vite/webpack/rollup config in workspace list')
    }
  }

  if (ctx.packageJsonContent?.includes('password') && /"password"\s*:\s*"[^"]{2,}"/.test(ctx.packageJsonContent)) {
    pushIssue(issues, '', 'missing-secrets-management', 'Hardcoded password-like string in package.json')
  }
}

export function analyzeMissingLogic(
  code: string,
  filename: string | undefined,
  language: string,
  ctx: MissingLogicWorkspaceContext = {}
): MissingLogicIssue[] {
  const issues: MissingLogicIssue[] = []
  const fn = filename || 'untitled'
  const lang = language.toLowerCase()

  if (['javascript', 'typescript', 'jsx', 'tsx', 'javascriptreact', 'typescriptreact'].includes(lang) || /\.(tsx?|jsx?)$/i.test(fn)) {
    scanTsJsLike(code, fn, issues)
  } else if (lang === 'python' || fn.endsWith('.py')) {
    scanPython(code, issues)
  }

  scanWorkspace(ctx, issues)

  // Dedupe by id (keep first message)
  const seen = new Set<MissingLogicDetectionId>()
  return issues.filter((i) => {
    if (seen.has(i.id)) return false
    seen.add(i.id)
    return true
  })
}

/**
 * Runs ESLint (JSON), tsc, graphql-schema-linter, and Sonar scanner via ideRunCommand,
 * normalizes output into workspace-relative problem rows.
 */

import type { JarvisIdeRunCommandResult } from '@/types/jarvis-ide'

export interface JarvisWorkspaceQualityProblem {
  line: number
  column: number
  severity: 'error' | 'warning' | 'info' | 'hint'
  message: string
  source: string
}

function toWorkspaceRelPath(workspaceRoot: string, filePath: string): string {
  const norm = filePath.replaceAll('\\', '/')
  const wr = workspaceRoot.replaceAll('\\', '/').replace(/\/$/, '')
  const wrLower = wr.toLowerCase()
  const nLower = norm.toLowerCase()
  if (nLower.startsWith(wrLower + '/')) return norm.slice(wr.length + 1)
  if (nLower === wrLower) return '(workspace)'
  if (!norm.includes('/') && !norm.includes('\\')) return norm
  const parts = norm.split('/')
  return parts.at(-1) ?? norm
}

function dedupeProblems(problems: JarvisWorkspaceQualityProblem[]): JarvisWorkspaceQualityProblem[] {
  const seen = new Set<string>()
  const out: JarvisWorkspaceQualityProblem[] = []
  for (const p of problems) {
    const k = `${p.source}|${p.line}|${p.column}|${p.message}`
    if (seen.has(k)) continue
    seen.add(k)
    out.push(p)
  }
  return out
}

/** ESLint `-f json` (array of file results). */
export function parseEslintJsonOutput(stdout: string, workspaceRoot: string): JarvisWorkspaceQualityProblem[] {
  const trimmed = stdout.trim()
  const start = trimmed.indexOf('[')
  if (start === -1) return []
  let jsonStr = trimmed.slice(start)
  const end = jsonStr.lastIndexOf(']')
  if (end !== -1) jsonStr = jsonStr.slice(0, end + 1)
  let arr: Array<{
    filePath?: string
    messages?: Array<{
      line?: number
      column?: number
      severity?: number
      message?: string
      ruleId?: string | null
    }>
  }>
  try {
    arr = JSON.parse(jsonStr) as typeof arr
  } catch {
    return []
  }
  if (!Array.isArray(arr)) return []
  const out: JarvisWorkspaceQualityProblem[] = []
  for (const f of arr) {
    const fp = f.filePath || ''
    const source = toWorkspaceRelPath(workspaceRoot, fp)
    for (const m of f.messages || []) {
      if (m.line == null || m.line < 1) continue
      let sev: 'error' | 'warning' | 'info' = 'info'
      if (m.severity === 2) sev = 'error'
      else if (m.severity === 1) sev = 'warning'
      const rule = m.ruleId ? String(m.ruleId) : ''
      const msg = m.message || 'ESLint'
      out.push({
        line: m.line,
        column: Math.max(1, m.column ?? 1),
        severity: sev,
        message: rule ? `[eslint] ${msg} (${rule})` : `[eslint] ${msg}`,
        source,
      })
    }
  }
  return out
}

/** TypeScript compiler: path(line,col): error|warning ÔÇª */
export function parseTscOutput(combined: string, workspaceRoot: string): JarvisWorkspaceQualityProblem[] {
  const out: JarvisWorkspaceQualityProblem[] = []
  const lines = combined.split(/\r?\n/)
  const re = /^(.+?)\((\d+),(\d+)\):\s*(error|warning)\s+(.+)$/
  for (const line of lines) {
    const m = re.exec(line)
    if (!m) continue
    const rawPath = m[1].trim()
    const source = toWorkspaceRelPath(workspaceRoot, rawPath)
    const sev = m[4] === 'error' ? 'error' : 'warning'
    out.push({
      line: Number.parseInt(m[2], 10),
      column: Number.parseInt(m[3], 10),
      severity: sev,
      message: `[tsc] ${m[5].trim()}`,
      source,
    })
  }
  return out
}

/** graphql-schema-linter default text output. */
export function parseGraphqlSchemaLinterStdout(text: string, defaultRel: string, workspaceRoot: string): JarvisWorkspaceQualityProblem[] {
  const out: JarvisWorkspaceQualityProblem[] = []
  const lines = text.split(/\r?\n/)
  let current = defaultRel
  const fileHeader = /^(.+\.(?:graphql|gql))$/i
  const issueRe = /^\s*(\d+):(\d+)\s+(error|warning)\s+(.+)$/
  for (const line of lines) {
    const fh = fileHeader.exec(line.trim())
    if (fh && !/\s/.test(line.trim())) {
      current = toWorkspaceRelPath(workspaceRoot, fh[1].trim())
      continue
    }
    const im = issueRe.exec(line)
    if (im) {
      out.push({
        line: Number.parseInt(im[1], 10),
        column: Number.parseInt(im[2], 10),
        severity: im[3] === 'error' ? 'error' : 'warning',
        message: `[graphql] ${im[4].trim()}`,
        source: current,
      })
    }
  }
  return out
}

/** Sonar scanner: no stable file:line in logs; surface failure tail when exit != 0. */
export function parseSonarScannerOutput(combined: string, exitCode: number | null): JarvisWorkspaceQualityProblem[] {
  if (exitCode === 0 || exitCode === null) return []
  const tail = combined
    .split(/\r?\n/)
    .filter(Boolean)
    .slice(-40)
    .join('\n')
    .slice(0, 8000)
  const msg = tail || `scanner exited with code ${String(exitCode)}`
  return [
    {
      line: 1,
      column: 1,
      severity: 'error',
      message: `[sonar] ${msg}`,
      source: 'sonar-scanner',
    },
  ]
}

export interface RunJarvisWorkspaceQualityOptions {
  workspaceRoot: string
  runCommand: (cwd: string, command: string) => Promise<JarvisIdeRunCommandResult>
  hasTsconfig: boolean
  graphqlRelPaths: readonly string[]
  runSonar: boolean
}

export async function runJarvisWorkspaceQuality(opts: RunJarvisWorkspaceQualityOptions): Promise<{
  problems: JarvisWorkspaceQualityProblem[]
  logs: string[]
}> {
  const { workspaceRoot, runCommand, hasTsconfig, graphqlRelPaths, runSonar } = opts
  const logs: string[] = []
  const problems: JarvisWorkspaceQualityProblem[] = []

  const eslintCmd =
    'npx --yes eslint . --ext .ts,.tsx,.js,.jsx,.mjs,.cjs --no-error-on-unmatched-pattern -f json'
  logs.push('--- ESLint ---')
  const eslintR = await runCommand(workspaceRoot, eslintCmd)
  const eslintText = `${eslintR.stdout}\n${eslintR.stderr}`
  problems.push(...parseEslintJsonOutput(eslintText, workspaceRoot))
  logs.push(`eslint exit=${String(eslintR.exitCode)}`)

  if (hasTsconfig) {
    logs.push('--- tsc ---')
    const tscR = await runCommand(workspaceRoot, 'npx --yes tsc --noEmit -p tsconfig.json')
    const tscText = `${tscR.stdout}\n${tscR.stderr}`
    problems.push(...parseTscOutput(tscText, workspaceRoot))
    logs.push(`tsc exit=${String(tscR.exitCode)}`)
  } else {
    logs.push('--- tsc (skipped: no tsconfig.json) ---')
  }

  const gqlPaths = graphqlRelPaths.slice(0, 8)
  if (gqlPaths.length === 0) {
    logs.push('--- GraphQL schema linter (skipped: no .graphql/.gql files in index) ---')
  }
  for (const rel of gqlPaths) {
    const safe = rel.replaceAll('"', '').replaceAll('\\', '/')
    logs.push(`--- graphql-schema-linter ${safe} ---`)
    const q = `"${safe}"`
    const gqlR = await runCommand(workspaceRoot, `npx --yes graphql-schema-linter ${q}`)
    const gqlText = `${gqlR.stdout}\n${gqlR.stderr}`
    problems.push(...parseGraphqlSchemaLinterStdout(gqlText, safe, workspaceRoot))
    logs.push(`graphql-schema-linter exit=${String(gqlR.exitCode)}`)
  }

  if (runSonar) {
    logs.push('--- SonarScanner ---')
    let sonarR = await runCommand(workspaceRoot, 'npx --yes @sonar/scan')
    const sonarText = `${sonarR.stdout}\n${sonarR.stderr}`
    const looksMissing =
      /not recognized|not found|ENOENT|is not recognized as an internal or external command/i.test(sonarText)
    if ((sonarR.exitCode !== 0 && sonarR.exitCode != null) && looksMissing) {
      sonarR = await runCommand(workspaceRoot, 'sonar-scanner')
    }
    const finalText = `${sonarR.stdout}\n${sonarR.stderr}`
    problems.push(...parseSonarScannerOutput(finalText, sonarR.exitCode))
    logs.push(`sonar exit=${String(sonarR.exitCode)}`)
  } else {
    logs.push('--- SonarScanner (skipped: no sonar-project.properties) ---')
  }

  return { problems: dedupeProblems(problems), logs }
}

/**
 * Self-Learning Engine
 *
 * Silently analyzes every conversation exchange to extract:
 * - Preferences (communication style, formatting, tool choices)
 * - Corrections (mistakes to never repeat)
 * - Patterns (routines, frequent queries, workflows)
 * - Knowledge (useful facts worth remembering)
 * - Tool outcomes (success/failure tracking)
 *
 * All learning happens asynchronously after the response is delivered.
 */

import { callLlm } from './llm'

// ÔöÇÔöÇ Types ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

interface LearnedPreference {
  domain: string
  key: string
  value: string
}

interface LearnedCorrection {
  category: string
  mistake: string
  correction: string
}

interface LearnedPattern {
  pattern_type: string
  description: string
  metadata?: Record<string, unknown>
}

interface LearnedKnowledge {
  topic: string
  content: string
  source: string
}

interface AnalysisResult {
  preferences: LearnedPreference[]
  corrections: LearnedCorrection[]
  patterns: LearnedPattern[]
  knowledge: LearnedKnowledge[]
}

interface ToolOutcome {
  tool_name: string
  query_type?: string
  success: boolean
  execution_time_ms?: number
  error_message?: string
}

// ÔöÇÔöÇ Analysis prompt ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

const ANALYSIS_PROMPT = `You are a silent learning system that analyzes conversations to extract useful patterns.

Given a user message and assistant response, extract ANY of the following (return empty arrays if nothing applies):

1. PREFERENCES ÔÇö Things the user implicitly or explicitly prefers:
   - communication style (formal/casual, verbose/concise)
   - formatting (bullet points, code blocks, tables)
   - topic interests
   - tool preferences
   - behavioral preferences ("don't do X", "always do Y")

2. CORRECTIONS ÔÇö If the user corrected the assistant:
   - What was wrong (the mistake)
   - What was wanted (the correction)
   - Category: factual, preference, tool_choice, behavior, format

3. PATTERNS ÔÇö Behavioral patterns observed:
   - routine: regular activities or time-based behaviors
   - workflow: sequences of actions the user commonly does
   - frequent_query: types of questions asked repeatedly

4. KNOWLEDGE ÔÇö Useful facts worth remembering:
   - Personal facts about the user
   - Domain knowledge shared by the user
   - Preferences expressed as knowledge

Respond in JSON only. No markdown, no explanation.
{
  "preferences": [{ "domain": "communication|formatting|tools|topics|behavior", "key": "short_key", "value": "description" }],
  "corrections": [{ "category": "factual|preference|tool_choice|behavior|format", "mistake": "what was wrong", "correction": "what was wanted" }],
  "patterns": [{ "pattern_type": "routine|workflow|frequent_query", "description": "brief description" }],
  "knowledge": [{ "topic": "topic", "content": "fact", "source": "conversation" }]
}`

// ÔöÇÔöÇ Core functions ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

/**
 * Analyze an exchange and extract learnings. Runs asynchronously.
 * Returns the analysis result (also posts to the server to store).
 */
export async function analyzeExchange(
  userMessage: string,
  assistantResponse: string,
  toolsUsed?: string[],
): Promise<AnalysisResult | null> {
  try {
    const toolContext = toolsUsed?.length
      ? `\nTools used in this exchange: ${toolsUsed.join(', ')}`
      : ''

    const prompt = `${ANALYSIS_PROMPT}

USER MESSAGE:
${userMessage.slice(0, 2000)}

ASSISTANT RESPONSE:
${assistantResponse.slice(0, 2000)}${toolContext}`

    const raw = await callLlm(prompt, 'gpt-4o-mini', true)
    const result = JSON.parse(raw) as AnalysisResult

    if (!result.preferences) result.preferences = []
    if (!result.corrections) result.corrections = []
    if (!result.patterns) result.patterns = []
    if (!result.knowledge) result.knowledge = []

    const hasLearnings =
      result.preferences.length > 0 ||
      result.corrections.length > 0 ||
      result.patterns.length > 0 ||
      result.knowledge.length > 0

    if (!hasLearnings) return null

    await fetch('/api/jarvis-memory/learn', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(result),
    }).catch(() => { /* non-critical */ })

    return result
  } catch {
    return null
  }
}

/**
 * Fire-and-forget wrapper for analyzeExchange.
 * Never blocks the caller.
 */
export function analyzeExchangeAsync(
  userMessage: string,
  assistantResponse: string,
  toolsUsed?: string[],
): void {
  setTimeout(() => {
    analyzeExchange(userMessage, assistantResponse, toolsUsed).catch(() => {})
  }, 100)
}

/**
 * Fetch the pre-built learned context block from the server.
 * Returns a string to inject into the system prompt (empty if nothing learned yet).
 */
export async function getLearnedContext(): Promise<string> {
  try {
    const res = await fetch('/api/jarvis-memory/learned-context')
    if (!res.ok) return ''
    const data = await res.json() as { context: string }
    return data.context || ''
  } catch {
    return ''
  }
}

/**
 * Track a tool execution outcome.
 */
export async function trackToolOutcome(outcome: ToolOutcome): Promise<void> {
  try {
    await fetch('/api/jarvis-memory/track-tool', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(outcome),
    })
  } catch { /* non-critical */ }
}

/**
 * Fetch learning statistics (for the learning_stats tool).
 */
export async function getLearningStats(): Promise<string> {
  try {
    const res = await fetch('/api/jarvis-memory/learning-stats')
    if (!res.ok) return 'Learning system not available.'
    const data = await res.json() as {
      stats: Record<string, number>
      preferences: Array<{ domain: string; key: string; value: string }>
      corrections: Array<{ mistake: string; correction: string }>
      patterns: Array<{ description: string; frequency: number }>
      knowledge: Array<{ topic: string; content: string }>
      tool_stats: Array<{ tool_name: string; total_uses: number; success_rate: number }>
    }

    const lines: string[] = [
      '=== JARVIS LEARNING REPORT ===',
      `Preferences learned: ${data.stats.preferences}`,
      `Corrections stored: ${data.stats.corrections}`,
      `Patterns detected: ${data.stats.patterns}`,
      `Tools tracked: ${data.stats.tools_tracked}`,
      `Knowledge items: ${data.stats.knowledge_items}`,
    ]

    if (data.preferences.length > 0) {
      lines.push('\n--- Learned Preferences ---')
      for (const p of data.preferences) {
        lines.push(`[${p.domain}] ${p.key}: ${p.value}`)
      }
    }

    if (data.corrections.length > 0) {
      lines.push('\n--- Corrections (mistakes to avoid) ---')
      for (const c of data.corrections) {
        lines.push(`AVOID: "${c.mistake}" ÔåÆ DO: "${c.correction}"`)
      }
    }

    if (data.patterns.length > 0) {
      lines.push('\n--- Detected Patterns ---')
      for (const p of data.patterns) {
        lines.push(`${p.description} (seen ${p.frequency}x)`)
      }
    }

    if (data.knowledge.length > 0) {
      lines.push('\n--- Learned Knowledge ---')
      for (const k of data.knowledge) {
        lines.push(`[${k.topic}] ${k.content}`)
      }
    }

    if (data.tool_stats.length > 0) {
      lines.push('\n--- Tool Performance ---')
      for (const t of data.tool_stats) {
        lines.push(`${t.tool_name}: ${t.total_uses} uses, ${t.success_rate}% success`)
      }
    }

    return lines.join('\n')
  } catch {
    return 'Unable to retrieve learning statistics.'
  }
}

import { Document, Packer, Paragraph, TextRun } from 'docx'
import { jsPDF } from 'jspdf'

/** Rough plain text for TTS / exports (not perfect markdown stripping). */
export function markdownToPlainText(md: string): string {
  return md
    .replace(/```[\s\S]*?```/g, '\n')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/\*\*([^*]+)\*\*/g, '$1')
    .replace(/\*([^*]+)\*/g, '$1')
    .replace(/__([^_]+)__/g, '$1')
    .replace(/_([^_]+)_/g, '$1')
    .replace(/^#+\s+/gm, '')
    .replace(/^\s*[-*]\s+/gm, 'ÔÇó ')
    .replace(/\[(.*?)\]\([^)]*\)/g, '$1')
    .replace(/\n{3,}/g, '\n\n')
    .trim()
}

function downloadBlob(blob: Blob, filename: string) {
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = filename
  a.click()
  URL.revokeObjectURL(url)
}

export function exportMarkdownFile(markdown: string, baseName: string) {
  const blob = new Blob([markdown], { type: 'text/markdown;charset=utf-8' })
  downloadBlob(blob, `${baseName}.md`)
}

export function exportPdf(markdown: string, baseName: string) {
  const plain = markdownToPlainText(markdown)
  const doc = new jsPDF({ unit: 'mm', format: 'a4' })
  const pageW = doc.internal.pageSize.getWidth()
  const margin = 15
  const maxW = pageW - margin * 2
  const lines = doc.splitTextToSize(plain, maxW)
  let y = 20
  const lineH = 6
  for (let i = 0; i < lines.length; i++) {
    if (y > doc.internal.pageSize.getHeight() - 15) {
      doc.addPage()
      y = 20
    }
    doc.text(lines[i], margin, y)
    y += lineH
  }
  doc.save(`${baseName}.pdf`)
}

export async function exportDocx(markdown: string, baseName: string) {
  const plain = markdownToPlainText(markdown)
  const blocks = plain.split(/\n+/).map(
    (line) =>
      new Paragraph({
        children: [new TextRun(line || ' ')],
      })
  )
  const document = new Document({
    sections: [
      {
        properties: {},
        children: blocks.length > 0 ? blocks : [new Paragraph({ children: [new TextRun(' ')] })],
      },
    ],
  })
  const blob = await Packer.toBlob(document)
  downloadBlob(blob, `${baseName}.docx`)
}

/**
 * NOW TV rail: user-curated bookmarks only (no NOW API).
 * Optional `VITE_NOWTV_BOOKMARKS` JSON array ÔÇö see `.env.example`.
 */

export interface NowTvBookmarkRow {
  readonly title: string
  readonly meta: string
  readonly progress: number
  /** When set, row opens in a new tab */
  readonly href?: string
}

export const NOWTV_DEFAULT_BOOKMARKS: readonly NowTvBookmarkRow[] = [
  { title: 'The Last of Us', meta: 'S2 ┬À Ep3', progress: 62 },
  { title: 'House of the Dragon', meta: 'S1 ┬À Ep8', progress: 100 },
  { title: 'True Detective', meta: 'S4 ┬À Ep1', progress: 14 },
]

/**
 * Parse `VITE_NOWTV_BOOKMARKS` JSON. Returns `null` if empty or invalid.
 * Expected shape: `[{ "title": "ÔÇª", "meta": "ÔÇª", "progress": 0-100, "href": "https://ÔÇª" }]`
 */
export function parseNowTvBookmarksEnv(raw: string | undefined): NowTvBookmarkRow[] | null {
  const s = raw?.trim()
  if (!s) return null
  try {
    const data = JSON.parse(s) as unknown
    if (!Array.isArray(data)) return null
    const out: NowTvBookmarkRow[] = []
    for (const item of data) {
      if (!item || typeof item !== 'object') continue
      const o = item as Record<string, unknown>
      const title = typeof o.title === 'string' ? o.title.trim() : ''
      if (!title) continue
      const meta = typeof o.meta === 'string' && o.meta.trim() ? o.meta.trim() : 'ÔÇö'
      let progress = typeof o.progress === 'number' && Number.isFinite(o.progress) ? Math.round(o.progress) : 0
      if (progress < 0) progress = 0
      if (progress > 100) progress = 100
      let href: string | undefined
      if (typeof o.href === 'string' && o.href.trim()) {
        try {
          const u = new URL(o.href.trim())
          if (u.protocol === 'http:' || u.protocol === 'https:') href = u.href
        } catch {
          /* ignore invalid URL */
        }
      }
      out.push({ title, meta, progress, href })
    }
    return out.length > 0 ? out : null
  } catch {
    return null
  }
}

export function getNowTvBookmarks(): { rows: NowTvBookmarkRow[]; fromEnv: boolean } {
  const raw = import.meta.env.VITE_NOWTV_BOOKMARKS?.trim()
  const parsed = parseNowTvBookmarksEnv(raw)
  if (parsed) return { rows: parsed, fromEnv: true }
  return { rows: [...NOWTV_DEFAULT_BOOKMARKS], fromEnv: false }
}

export function getNowTvHomeUrl(): string {
  const u = import.meta.env.VITE_NOWTV_HOME_URL?.trim()
  if (u) {
    try {
      const parsed = new URL(u)
      if (parsed.protocol === 'http:' || parsed.protocol === 'https:') return parsed.href
    } catch {
      /* fall through */
    }
  }
  return 'https://www.nowtv.com'
}

/**
 * In-memory rolling telemetry for the Jarvis pipeline: turns, routing, retrieval, workers, and costs.
 */

import { v4 as uuidv4 } from 'uuid'

import { CONFIDENCE_THRESHOLDS } from '@/reasoning/confidenceTypes'

/** USD per 1K tokens used for rough cost in {@link TelemetryCollector.record} `prompt_assembled` events. */
const PROMPT_ASSEMBLED_COST_PER_1K_TOKENS_USD = 0.005

/** All supported telemetry event categories. */
export type TelemetryEventType =
  | 'turn_started'
  | 'turn_completed'
  | 'route_classified'
  | 'retrieval_gate_decision'
  | 'worker_executed'
  | 'worker_verified'
  | 'prompt_assembled'
  | 'context_compacted'
  | 'search_fired'
  | 'react_thought'
  | 'react_observation'
  | 'react_trace_complete'
  | 'scratchpad_confidence_update'
  | 'reflexion_critique'
  | 'tot_search_complete'
  | 'tot_decision'
  | 'cost_warning'
  | 'model_routed'
  | 'confidence_scored'
  | 'pre_task_confidence'
  | 'error'

/**
 * Single immutable event row stored in {@link TelemetryCollector}.
 * Passed to {@link TelemetryCollector.subscribe} callbacks (SSE and other live consumers).
 */
export interface TelemetryEvent {
  /** Unique id (uuid v4). */
  id: string
  type: TelemetryEventType
  sessionId: string
  /** ISO-8601 timestamp when the event was recorded. */
  timestamp: string
  durationMs?: number
  /** Type-specific payload (routes, gate source, token counts, etc.). */
  data: Record<string, unknown>
  error?: string
}

/** Aggregated per-session metrics derived from recorded events. */
export interface SessionSummary {
  sessionId: string
  startedAt: string
  lastActivityAt: string
  turnCount: number
  totalTokensUsed: number
  totalCostUsd: number
  routeBreakdown: Record<string, number>
  webSearchCount: number
  sessionHitCount: number
  longTermHitCount: number
  workerCallCount: number
  /** Fraction of worker verifications that passed (0ÔÇô1). */
  verificationPassRate: number
  avgVerificationScore: number
  compactionCount: number
  errorCount: number
  avgTurnLatencyMs: number
  /** ReAct reasoning rollups for this session (present after ReAct events). */
  reasoningStats?: {
    totalThoughts: number
    avgConfidence: number
    lowConfidenceCount: number
    traceCount: number
    /** Count of {@link TelemetryEventType} `scratchpad_confidence_update` events for this session. */
    scratchpadSamples: number
    /** Rolling mean of scratchpad trajectory confidence (separate from thought {@link avgConfidence}). */
    avgScratchpadConfidence: number
    /** Rollups from {@link TelemetryEventType} `reflexion_critique` events. */
    reflexionStats?: {
      totalCritiques: number
      avgCritiqueScore: number
      /** Critiques that passed on iteration 1. */
      passedFirstAttempt: number
      /** Sum of `lessonsLearnedCount` fields on reflexion critique event payloads. */
      totalLessonsLearned: number
    }
    /** Rollups from `tot_decision` and `tot_search_complete` events. */
    totStats?: {
      /** Times {@link TelemetryEventType} `tot_decision` had `usedTot: true`. */
      totalSearches: number
      /** Rolling mean of `nodesGenerated` from completed ToT beam searches. */
      avgNodesExplored: number
      /** Rolling mean of `bestScore` from completed ToT beam searches. */
      avgBestScore: number
      /** Times {@link TelemetryEventType} `tot_decision` had `usedTot: false`. */
      skippedCount: number
    }
    /** Rollups from {@link TelemetryEventType} `confidence_scored` events. */
    confidenceStats?: {
      totalScored: number
      avgScore: number
      /** Count where `action` is `trigger_uar` or `escalate_model` (resolver invoked). */
      uarTriggerCount: number
      /** Count where scalar is below {@link CONFIDENCE_THRESHOLDS.HARD_BLOCK}. */
      hardBlockCount: number
      /** Count where `action === 'proceed_with_flag'`. */
      flaggedOutputCount: number
      /** Latest `trend` from the most recent `confidence_scored` event in this session. */
      currentTrend: 'improving' | 'stable' | 'degrading'
    }
  }
  /** Rollups from {@link TelemetryEventType} `model_routed` events for this session. */
  routingStats?: {
    totalRoutedCalls: number
    /** Tier id ÔåÆ number of routing decisions. */
    byTier: Partial<Record<string, number>>
    /** Count of routes where `wasOverridden` was true (hard-rule / guardrail overrides). */
    overrideCount: number
    /** Sum of `estimatedCostUSD` from each `model_routed` payload. */
    totalEstimatedCostUSD: number
  }
  /** Rollups from {@link TelemetryEventType} `pre_task_confidence` events for this session. */
  preTaskStats?: {
    totalEstimates: number
    blockedCount: number
    lowConfidenceCount: number
    avgPreTaskConfidence: number
  }
}

/** Internal row: same as {@link SessionSummary} plus running totals for averages. */
type MutableSession = SessionSummary & {
  _latencySumMs: number
  _latencyN: number
  _verPass: number
  _verTotal: number
  _verScoreSum: number
  _verScoreN: number
  /** Samples for {@link SessionSummary.reasoningStats} `totStats` averages (from `tot_search_complete`). */
  _totSearchCompleteSamples?: number
  _totNodesGeneratedSum?: number
  _totBestScoreSum?: number
}

function createMutableSession(sessionId: string, firstTs: string): MutableSession {
  return {
    sessionId,
    startedAt: firstTs,
    lastActivityAt: firstTs,
    turnCount: 0,
    totalTokensUsed: 0,
    totalCostUsd: 0,
    routeBreakdown: {},
    webSearchCount: 0,
    sessionHitCount: 0,
    longTermHitCount: 0,
    workerCallCount: 0,
    verificationPassRate: 0,
    avgVerificationScore: 0,
    compactionCount: 0,
    errorCount: 0,
    avgTurnLatencyMs: 0,
    _latencySumMs: 0,
    _latencyN: 0,
    _verPass: 0,
    _verTotal: 0,
    _verScoreSum: 0,
    _verScoreN: 0,
  }
}

function toPublicSummary(m: MutableSession): SessionSummary {
  return {
    sessionId: m.sessionId,
    startedAt: m.startedAt,
    lastActivityAt: m.lastActivityAt,
    turnCount: m.turnCount,
    totalTokensUsed: m.totalTokensUsed,
    totalCostUsd: m.totalCostUsd,
    routeBreakdown: { ...m.routeBreakdown },
    webSearchCount: m.webSearchCount,
    sessionHitCount: m.sessionHitCount,
    longTermHitCount: m.longTermHitCount,
    workerCallCount: m.workerCallCount,
    verificationPassRate: m.verificationPassRate,
    avgVerificationScore: m.avgVerificationScore,
    compactionCount: m.compactionCount,
    errorCount: m.errorCount,
    avgTurnLatencyMs: m.avgTurnLatencyMs,
    ...(m.reasoningStats !== undefined
      ? {
          reasoningStats: cloneReasoningStatsForSummary(m.reasoningStats),
        }
      : {}),
    ...(m.routingStats !== undefined
      ? {
          routingStats: {
            totalRoutedCalls: m.routingStats.totalRoutedCalls,
            overrideCount: m.routingStats.overrideCount,
            totalEstimatedCostUSD: m.routingStats.totalEstimatedCostUSD,
            byTier: { ...m.routingStats.byTier },
          },
        }
      : {}),
    ...(m.preTaskStats !== undefined ? { preTaskStats: { ...m.preTaskStats } } : {}),
  }
}

function cloneReasoningStatsForSummary(
  rs: NonNullable<SessionSummary['reasoningStats']>,
): SessionSummary['reasoningStats'] {
  const { reflexionStats, totStats, confidenceStats, ...rest } = rs
  return {
    ...rest,
    ...(reflexionStats !== undefined ? { reflexionStats: { ...reflexionStats } } : {}),
    ...(totStats !== undefined ? { totStats: { ...totStats } } : {}),
    ...(confidenceStats !== undefined ? { confidenceStats: { ...confidenceStats } } : {}),
  }
}

/** Cross-session snapshot returned by {@link TelemetryCollector.getSystemStats}. */
export interface SystemStats {
  totalEvents: number
  activeSessions: number
  totalTurns: number
  totalWebSearches: number
  totalWorkerCalls: number
  avgVerificationScore: number
  /** Count of {@link TelemetryEvent} rows that contributed to {@link avgVerificationScore}. */
  verificationSampleCount: number
  totalErrors: number
  /** Count of `error` events in the rolling buffer from roughly the last 10 minutes. */
  recentErrors: number
  oldestEventAt: string | null
  newestEventAt: string | null
  reasoningStats: {
    totalThoughts: number
    avgConfidence: number
    lowConfidenceRate: number
    scratchpadSamples: number
    avgScratchpadConfidence: number
    reflexion: {
      totalCritiques: number
      avgCritiqueScore: number
      passedFirstAttemptRate: number
      totalLessonsLearned: number
    }
    tot: {
      totalSearches: number
      avgNodesExplored: number
      avgBestScore: number
      skippedCount: number
    }
    /** Aggregated {@link SessionSummary.reasoningStats.confidenceStats} across sessions. */
    confidenceStats: {
      totalScored: number
      avgScore: number
      uarTriggerCount: number
      hardBlockCount: number
      flaggedOutputCount: number
      currentTrend: 'improving' | 'stable' | 'degrading'
    }
  }
  /** Aggregated {@link SessionSummary.routingStats} across active sessions. */
  routingStats: {
    totalRoutedCalls: number
    byTier: Partial<Record<string, number>>
    overrideCount: number
    totalEstimatedCostUSD: number
  }
}

function asNumber(value: unknown): number | undefined {
  if (typeof value === 'number' && !Number.isNaN(value)) {
    return value
  }
  return undefined
}

function asBoolean(value: unknown): boolean | undefined {
  if (typeof value === 'boolean') {
    return value
  }
  return undefined
}

function asString(value: unknown): string | undefined {
  if (typeof value === 'string' && value.length > 0) {
    return value
  }
  return undefined
}

type ConfidenceTrend = 'improving' | 'stable' | 'degrading'

function parseConfidenceTrend(value: unknown): ConfidenceTrend {
  const s = typeof value === 'string' ? value.trim() : ''
  if (s === 'improving' || s === 'stable' || s === 'degrading') {
    return s
  }
  return 'stable'
}

/**
 * Collects pipeline events in a bounded buffer and maintains per-session rollups.
 */
export default class TelemetryCollector {
  private readonly events: TelemetryEvent[] = []

  private readonly sessionSummaries = new Map<string, MutableSession>()

  /** Live fan-out for SSE / dashboards; keyed by subscriber id from {@link subscribe}. */
  private readonly subscribers = new Map<string, (event: TelemetryEvent) => void>()

  private readonly maxEvents: number

  /**
   * @param maxEvents - Rolling cap; oldest events are dropped when exceeded.
   */
  constructor(maxEvents: number = 1000) {
    this.maxEvents = Math.max(1, maxEvents)
  }

  /**
   * Records one event, updates the session summary, enforces the rolling window, and returns the event.
   */
  record(
    type: TelemetryEventType,
    sessionId: string,
    data: Record<string, unknown>,
    durationMs?: number,
    error?: string,
  ): TelemetryEvent {
    const event: TelemetryEvent = {
      id: uuidv4(),
      type,
      sessionId,
      timestamp: new Date().toISOString(),
      durationMs,
      data: { ...data },
      error,
    }

    this.events.push(event)
    while (this.events.length > this.maxEvents) {
      this.events.shift()
    }

    this.updateSessionSummary(event)

    this.subscribers.forEach((cb) => {
      try {
        cb(event)
      } catch {
        /* Subscriber error ÔÇö ignore */
      }
    })

    return event
  }

  /**
   * Register a callback invoked synchronously after each {@link record} (same process).
   * @param callback - Receives the immutable {@link TelemetryEvent} just stored.
   * @returns Opaque id for {@link unsubscribe}.
   */
  subscribe(callback: (event: TelemetryEvent) => void): string {
    const subscriberId = uuidv4()
    this.subscribers.set(subscriberId, callback)
    return subscriberId
  }

  /**
   * Remove a listener registered with {@link subscribe}.
   * @param subscriberId - Value returned from {@link subscribe}; no-op if unknown.
   */
  unsubscribe(subscriberId: string): void {
    this.subscribers.delete(subscriberId)
  }

  private applyTurnCompleted(s: MutableSession, event: TelemetryEvent): void {
    s.turnCount++
    const d = asNumber(event.durationMs)
    if (d !== undefined && d >= 0) {
      s._latencySumMs += d
      s._latencyN++
      s.avgTurnLatencyMs = s._latencySumMs / s._latencyN
    }
  }

  private applyRetrievalGate(s: MutableSession, event: TelemetryEvent): void {
    const source = asString(event.data.source)
    if (source === 'session' || source === 'session_fallback') {
      s.sessionHitCount++
    } else if (source === 'long_term') {
      s.longTermHitCount++
    }
    if (asBoolean(event.data.shouldSearchWeb) === true) {
      s.webSearchCount++
    }
  }

  private applyWorkerVerified(s: MutableSession, event: TelemetryEvent): void {
    s._verTotal++
    if (asBoolean(event.data.passed) === true) {
      s._verPass++
    }
    s.verificationPassRate = s._verTotal > 0 ? s._verPass / s._verTotal : 0
    const score = asNumber(event.data.score)
    if (score !== undefined) {
      s._verScoreSum += score
      s._verScoreN++
      s.avgVerificationScore = s._verScoreSum / s._verScoreN
    }
  }

  private applyPromptAssembled(s: MutableSession, event: TelemetryEvent): void {
    const tokens = asNumber(event.data.tokensUsed)
    if (tokens !== undefined && tokens >= 0) {
      s.totalTokensUsed += tokens
      s.totalCostUsd = (s.totalTokensUsed / 1000) * PROMPT_ASSEMBLED_COST_PER_1K_TOKENS_USD
    }
  }

  private ensureReasoningStats(s: MutableSession): NonNullable<SessionSummary['reasoningStats']> {
    if (s.reasoningStats === undefined) {
      s.reasoningStats = {
        totalThoughts: 0,
        avgConfidence: 0,
        lowConfidenceCount: 0,
        traceCount: 0,
        scratchpadSamples: 0,
        avgScratchpadConfidence: 0,
      }
    }
    return s.reasoningStats
  }

  private ensureRoutingStats(s: MutableSession): NonNullable<SessionSummary['routingStats']> {
    if (s.routingStats === undefined) {
      s.routingStats = {
        totalRoutedCalls: 0,
        byTier: {},
        overrideCount: 0,
        totalEstimatedCostUSD: 0,
      }
    }
    return s.routingStats
  }

  private ensureConfidenceStats(
    s: MutableSession,
  ): NonNullable<NonNullable<SessionSummary['reasoningStats']>['confidenceStats']> {
    const summary = this.ensureReasoningStats(s)
    if (summary.confidenceStats === undefined) {
      summary.confidenceStats = {
        totalScored: 0,
        avgScore: 0,
        uarTriggerCount: 0,
        hardBlockCount: 0,
        flaggedOutputCount: 0,
        currentTrend: 'stable',
      }
    }
    return summary.confidenceStats
  }

  private ensurePreTaskStats(s: MutableSession): NonNullable<SessionSummary['preTaskStats']> {
    if (s.preTaskStats === undefined) {
      s.preTaskStats = {
        totalEstimates: 0,
        blockedCount: 0,
        lowConfidenceCount: 0,
        avgPreTaskConfidence: 0,
      }
    }
    return s.preTaskStats
  }

  private applyPreTaskConfidence(s: MutableSession, event: TelemetryEvent): void {
    const pt = this.ensurePreTaskStats(s)
    const conf = asNumber(event.data.confidence)
    pt.totalEstimates++
    const n = pt.totalEstimates
    if (event.data.shouldProceed === false) {
      pt.blockedCount++
    }
    if (conf !== undefined && Number.isFinite(conf) && conf < 0.6) {
      pt.lowConfidenceCount++
    }
    const v =
      conf !== undefined && Number.isFinite(conf)
        ? conf
        : n === 1
          ? 0
          : pt.avgPreTaskConfidence
    pt.avgPreTaskConfidence = (pt.avgPreTaskConfidence * (n - 1) + v) / n
  }

  private applyConfidenceScored(s: MutableSession, event: TelemetryEvent): void {
    const cs = this.ensureConfidenceStats(s)
    const scalar = asNumber(event.data.scalar) ?? 0
    const action = asString(event.data.action) ?? ''

    cs.totalScored++
    const n = cs.totalScored
    cs.avgScore = (cs.avgScore * (n - 1) + scalar) / n

    // NOTE: uarTriggerCount = times UncertaintyResolver.resolve() was called (trigger_uar and escalate_model).
    // To distinguish paths, split into uarTriggerCount (trigger_uar only) and uarEscalationCount (escalate_model only).
    if (action === 'trigger_uar' || action === 'escalate_model') {
      cs.uarTriggerCount++
    }
    if (scalar < CONFIDENCE_THRESHOLDS.HARD_BLOCK) {
      cs.hardBlockCount++
    }
    if (action === 'proceed_with_flag') {
      cs.flaggedOutputCount++
    }
    cs.currentTrend = parseConfidenceTrend(event.data.trend)
  }

  private applyModelRouted(s: MutableSession, event: TelemetryEvent): void {
    const rs = this.ensureRoutingStats(s)
    rs.totalRoutedCalls++
    const tier = asString(event.data.tier) ?? 'unknown'
    rs.byTier[tier] = (rs.byTier[tier] ?? 0) + 1
    if (asBoolean(event.data.wasOverridden) === true) {
      rs.overrideCount++
    }
    const est = asNumber(event.data.estimatedCostUSD)
    if (est !== undefined) {
      rs.totalEstimatedCostUSD += est
    }
  }

  private applyReactThought(s: MutableSession, event: TelemetryEvent): void {
    const summary = this.ensureReasoningStats(s)
    summary.totalThoughts++
    const conf = asNumber(event.data.confidence) ?? 0
    summary.avgConfidence =
      (summary.avgConfidence * (summary.totalThoughts - 1) + conf) / summary.totalThoughts
    if (conf < 0.65) {
      summary.lowConfidenceCount++
    }
  }

  private applyReactTraceComplete(s: MutableSession): void {
    const summary = this.ensureReasoningStats(s)
    summary.traceCount++
  }

  /** Rolls scratchpad trajectory confidence into {@link SessionSummary.reasoningStats}. */
  private applyScratchpadConfidenceUpdate(s: MutableSession, event: TelemetryEvent): void {
    const summary = this.ensureReasoningStats(s)
    const conf = asNumber(event.data.confidence) ?? 0
    summary.scratchpadSamples = (summary.scratchpadSamples ?? 0) + 1
    const n = summary.scratchpadSamples
    summary.avgScratchpadConfidence =
      ((summary.avgScratchpadConfidence ?? 0) * (n - 1) + conf) / n
  }

  private applyReflexionCritique(s: MutableSession, event: TelemetryEvent): void {
    const summary = this.ensureReasoningStats(s)
    if (summary.reflexionStats === undefined) {
      summary.reflexionStats = {
        totalCritiques: 0,
        avgCritiqueScore: 0,
        passedFirstAttempt: 0,
        totalLessonsLearned: 0,
      }
    }
    const rs = summary.reflexionStats
    const score = asNumber(event.data.score) ?? 0
    const iteration = asNumber(event.data.iteration) ?? 0
    const passed = asBoolean(event.data.passed) === true
    const lessonsDelta = asNumber(event.data.lessonsLearnedCount) ?? 0

    rs.totalCritiques++
    const n = rs.totalCritiques
    rs.avgCritiqueScore = (rs.avgCritiqueScore * (n - 1) + score) / n

    /**
     * NOTE: `passedFirstAttempt` (see {@link SessionSummary.reasoningStats} `reflexionStats`) counts ANY
     * `reflexion_critique` event where `iteration === 1` and `passed === true`, including
     * quick-critique-only paths (where no full `CriticAgent` call was made).
     * To count only full Critic passes: filter on `event.data.quickCritiqueOnly !== true`.
     * The current behaviour intentionally counts quick passes as first-attempt passes since
     * the output quality is the same regardless of evaluation path.
     */
    if (iteration === 1 && passed) {
      rs.passedFirstAttempt++
    }

    rs.totalLessonsLearned += lessonsDelta
  }

  private ensureTotStats(
    s: MutableSession,
  ): NonNullable<NonNullable<SessionSummary['reasoningStats']>['totStats']> {
    const summary = this.ensureReasoningStats(s)
    if (summary.totStats === undefined) {
      summary.totStats = {
        totalSearches: 0,
        avgNodesExplored: 0,
        avgBestScore: 0,
        skippedCount: 0,
      }
    }
    return summary.totStats
  }

  private applyTotDecision(s: MutableSession, event: TelemetryEvent): void {
    const ts = this.ensureTotStats(s)
    if (asBoolean(event.data.usedTot) === true) {
      ts.totalSearches++
    } else {
      ts.skippedCount++
    }
  }

  private applyTotSearchComplete(s: MutableSession, event: TelemetryEvent): void {
    const ts = this.ensureTotStats(s)
    const nodes = asNumber(event.data.nodesGenerated) ?? 0
    const best = asNumber(event.data.bestScore) ?? 0
    const prevN = s._totSearchCompleteSamples ?? 0
    const n = prevN + 1
    s._totSearchCompleteSamples = n
    s._totNodesGeneratedSum = (s._totNodesGeneratedSum ?? 0) + nodes
    s._totBestScoreSum = (s._totBestScoreSum ?? 0) + best
    ts.avgNodesExplored = (s._totNodesGeneratedSum ?? 0) / n
    ts.avgBestScore = (s._totBestScoreSum ?? 0) / n
  }

  private updateSessionSummary(event: TelemetryEvent): void {
    let s = this.sessionSummaries.get(event.sessionId)
    if (s === undefined) {
      s = createMutableSession(event.sessionId, event.timestamp)
      this.sessionSummaries.set(event.sessionId, s)
    }

    s.lastActivityAt = event.timestamp

    switch (event.type) {
      case 'turn_started':
        break
      case 'turn_completed':
        this.applyTurnCompleted(s, event)
        break
      case 'route_classified': {
        const route = asString(event.data.route) ?? 'unknown'
        s.routeBreakdown[route] = (s.routeBreakdown[route] ?? 0) + 1
        break
      }
      case 'retrieval_gate_decision':
        this.applyRetrievalGate(s, event)
        break
      case 'worker_executed':
        s.workerCallCount++
        break
      case 'worker_verified':
        this.applyWorkerVerified(s, event)
        break
      case 'prompt_assembled':
        this.applyPromptAssembled(s, event)
        break
      case 'context_compacted':
        s.compactionCount++
        break
      case 'search_fired':
        s.webSearchCount++
        break
      case 'error':
        s.errorCount++
        break
      case 'react_thought':
        this.applyReactThought(s, event)
        break
      case 'react_observation':
        break
      case 'react_trace_complete':
        this.applyReactTraceComplete(s)
        break
      case 'scratchpad_confidence_update':
        this.applyScratchpadConfidenceUpdate(s, event)
        break
      case 'reflexion_critique':
        this.applyReflexionCritique(s, event)
        break
      case 'tot_decision':
        this.applyTotDecision(s, event)
        break
      case 'tot_search_complete':
        this.applyTotSearchComplete(s, event)
        break
      case 'cost_warning':
        break
      case 'model_routed':
        this.applyModelRouted(s, event)
        break
      case 'confidence_scored':
        this.applyConfidenceScored(s, event)
        break
      case 'pre_task_confidence':
        this.applyPreTaskConfidence(s, event)
        break
      default:
        break
    }
  }

  /**
   * Latest events first; optional filters by session and/or type.
   */
  getRecentEvents(limit: number = 50, sessionId?: string, type?: TelemetryEventType): TelemetryEvent[] {
    let list = [...this.events]
    if (sessionId !== undefined) {
      list = list.filter((e) => e.sessionId === sessionId)
    }
    if (type !== undefined) {
      list = list.filter((e) => e.type === type)
    }
    list.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime())
    return list.slice(0, Math.max(0, limit))
  }

  /** Snapshot for one session, or null if none. */
  getSessionSummary(sessionId: string): SessionSummary | null {
    const s = this.sessionSummaries.get(sessionId)
    return s === undefined ? null : toPublicSummary(s)
  }

  /** All sessions, most recently active first. */
  getAllSessionSummaries(): SessionSummary[] {
    return [...this.sessionSummaries.values()]
      .map(toPublicSummary)
      .sort((a, b) => new Date(b.lastActivityAt).getTime() - new Date(a.lastActivityAt).getTime())
  }

  private accumulateReasoningRollups(
    rs: SessionSummary['reasoningStats'],
    acc: {
      reasoningThoughtsTotal: number
      reasoningWeightedConfSum: number
      reasoningLowConfTotal: number
      reasoningScratchpadSamplesTotal: number
      reasoningScratchpadWeightedSum: number
    },
  ): void {
    if (rs === undefined) {
      return
    }
    if (rs.totalThoughts > 0) {
      acc.reasoningThoughtsTotal += rs.totalThoughts
      acc.reasoningWeightedConfSum += rs.avgConfidence * rs.totalThoughts
      acc.reasoningLowConfTotal += rs.lowConfidenceCount
    }
    const sp = rs.scratchpadSamples ?? 0
    if (sp > 0) {
      acc.reasoningScratchpadSamplesTotal += sp
      acc.reasoningScratchpadWeightedSum += (rs.avgScratchpadConfidence ?? 0) * sp
    }
  }

  /**
   * Cross-session aggregates for dashboards.
   */
  getSystemStats(): SystemStats {
    const summaries = [...this.sessionSummaries.values()]
    let globalVerScoreSum = 0
    let globalVerScoreN = 0
    const reasoningAcc = {
      reasoningThoughtsTotal: 0,
      reasoningWeightedConfSum: 0,
      reasoningLowConfTotal: 0,
      reasoningScratchpadSamplesTotal: 0,
      reasoningScratchpadWeightedSum: 0,
    }
    let reflexionTotalCritiques = 0
    let reflexionCritiqueScoreSum = 0
    let reflexionPassedFirstAttempt = 0
    let reflexionTotalLessonsLearned = 0
    let totTotalSearches = 0
    let totSkippedCount = 0
    let totSearchSamplesTotal = 0
    let totNodesWeightedSum = 0
    let totBestScoreWeightedSum = 0
    const routingAcc = {
      totalRoutedCalls: 0,
      byTier: {} as Partial<Record<string, number>>,
      overrideCount: 0,
      totalEstimatedCostUSD: 0,
    }
    const confidenceAcc = {
      totalScoredSum: 0,
      scalarWeightedSum: 0,
      uarTriggerCount: 0,
      hardBlockCount: 0,
      flaggedOutputCount: 0,
    }
    let confidenceTrendLatest: ConfidenceTrend = 'stable'
    let confidenceTrendLatestTs = 0
    for (const m of summaries) {
      globalVerScoreSum += m._verScoreSum
      globalVerScoreN += m._verScoreN
      this.accumulateReasoningRollups(m.reasoningStats, reasoningAcc)
      const rs = m.reasoningStats?.reflexionStats
      if (rs !== undefined) {
        reflexionTotalCritiques += rs.totalCritiques
        reflexionCritiqueScoreSum += rs.avgCritiqueScore * rs.totalCritiques
        reflexionPassedFirstAttempt += rs.passedFirstAttempt
        reflexionTotalLessonsLearned += rs.totalLessonsLearned
      }
      const tot = m.reasoningStats?.totStats
      if (tot !== undefined) {
        totTotalSearches += tot.totalSearches
        totSkippedCount += tot.skippedCount
      }
      const totSamples = m._totSearchCompleteSamples ?? 0
      if (totSamples > 0 && tot !== undefined) {
        totSearchSamplesTotal += totSamples
        totNodesWeightedSum += tot.avgNodesExplored * totSamples
        totBestScoreWeightedSum += tot.avgBestScore * totSamples
      }
      const rout = m.routingStats
      if (rout !== undefined) {
        routingAcc.totalRoutedCalls += rout.totalRoutedCalls
        routingAcc.overrideCount += rout.overrideCount
        routingAcc.totalEstimatedCostUSD += rout.totalEstimatedCostUSD
        for (const [tierKey, c] of Object.entries(rout.byTier)) {
          const v = typeof c === 'number' && !Number.isNaN(c) ? c : 0
          routingAcc.byTier[tierKey] = (routingAcc.byTier[tierKey] ?? 0) + v
        }
      }
      const cstat = m.reasoningStats?.confidenceStats
      if (cstat !== undefined && cstat.totalScored > 0) {
        confidenceAcc.totalScoredSum += cstat.totalScored
        confidenceAcc.scalarWeightedSum += cstat.avgScore * cstat.totalScored
        confidenceAcc.uarTriggerCount += cstat.uarTriggerCount
        confidenceAcc.hardBlockCount += cstat.hardBlockCount
        confidenceAcc.flaggedOutputCount += cstat.flaggedOutputCount
        const act = new Date(m.lastActivityAt).getTime()
        if (!Number.isNaN(act) && act >= confidenceTrendLatestTs) {
          confidenceTrendLatestTs = act
          confidenceTrendLatest = cstat.currentTrend
        }
      }
    }
    const times = this.events.map((e) => new Date(e.timestamp).getTime()).filter((t) => !Number.isNaN(t))
    const oldest = times.length > 0 ? Math.min(...times) : null
    const newest = times.length > 0 ? Math.max(...times) : null
    const tenMinutesAgo = Date.now() - 10 * 60 * 1000
    const recentErrors = this.events.filter(
      (e) => e.type === 'error' && new Date(e.timestamp).getTime() > tenMinutesAgo,
    ).length
    return {
      totalEvents: this.events.length,
      activeSessions: this.sessionSummaries.size,
      totalTurns: summaries.reduce((a, s) => a + s.turnCount, 0),
      totalWebSearches: summaries.reduce((a, s) => a + s.webSearchCount, 0),
      totalWorkerCalls: summaries.reduce((a, s) => a + s.workerCallCount, 0),
      avgVerificationScore: globalVerScoreN > 0 ? globalVerScoreSum / globalVerScoreN : 0,
      verificationSampleCount: globalVerScoreN,
      totalErrors: summaries.reduce((a, s) => a + s.errorCount, 0),
      recentErrors,
      oldestEventAt: oldest !== null ? new Date(oldest).toISOString() : null,
      newestEventAt: newest !== null ? new Date(newest).toISOString() : null,
      reasoningStats: {
        totalThoughts: reasoningAcc.reasoningThoughtsTotal,
        avgConfidence:
          reasoningAcc.reasoningThoughtsTotal > 0
            ? reasoningAcc.reasoningWeightedConfSum / reasoningAcc.reasoningThoughtsTotal
            : 0,
        lowConfidenceRate:
          reasoningAcc.reasoningThoughtsTotal > 0
            ? reasoningAcc.reasoningLowConfTotal / reasoningAcc.reasoningThoughtsTotal
            : 0,
        scratchpadSamples: reasoningAcc.reasoningScratchpadSamplesTotal,
        avgScratchpadConfidence:
          reasoningAcc.reasoningScratchpadSamplesTotal > 0
            ? reasoningAcc.reasoningScratchpadWeightedSum / reasoningAcc.reasoningScratchpadSamplesTotal
            : 0,
        reflexion: {
          totalCritiques: reflexionTotalCritiques,
          avgCritiqueScore:
            reflexionTotalCritiques > 0 ? reflexionCritiqueScoreSum / reflexionTotalCritiques : 0,
          passedFirstAttemptRate:
            reflexionTotalCritiques > 0 ? reflexionPassedFirstAttempt / reflexionTotalCritiques : 0,
          totalLessonsLearned: reflexionTotalLessonsLearned,
        },
        tot: {
          totalSearches: totTotalSearches,
          skippedCount: totSkippedCount,
          avgNodesExplored:
            totSearchSamplesTotal > 0 ? totNodesWeightedSum / totSearchSamplesTotal : 0,
          avgBestScore:
            totSearchSamplesTotal > 0 ? totBestScoreWeightedSum / totSearchSamplesTotal : 0,
        },
        confidenceStats: {
          totalScored: confidenceAcc.totalScoredSum,
          avgScore:
            confidenceAcc.totalScoredSum > 0
              ? confidenceAcc.scalarWeightedSum / confidenceAcc.totalScoredSum
              : 0,
          uarTriggerCount: confidenceAcc.uarTriggerCount,
          hardBlockCount: confidenceAcc.hardBlockCount,
          flaggedOutputCount: confidenceAcc.flaggedOutputCount,
          currentTrend: confidenceTrendLatest,
        },
      },
      routingStats: {
        totalRoutedCalls: routingAcc.totalRoutedCalls,
        byTier: { ...routingAcc.byTier },
        overrideCount: routingAcc.overrideCount,
        totalEstimatedCostUSD: routingAcc.totalEstimatedCostUSD,
      },
    }
  }

  /** Drops buffered events and the summary row for a session. */
  clearSession(sessionId: string): void {
    this.sessionSummaries.delete(sessionId)
    for (let i = this.events.length - 1; i >= 0; i--) {
      if (this.events[i]!.sessionId === sessionId) {
        this.events.splice(i, 1)
      }
    }
  }

  /** All events for a session, oldest first (handy for export). */
  exportSessionEvents(sessionId: string): TelemetryEvent[] {
    return this.events
      .filter((e) => e.sessionId === sessionId)
      .sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime())
  }
}

/** Shared process-wide collector (bounded to 1000 events by default). */
export const telemetry = new TelemetryCollector()

/**
 * Open-Meteo forecast (no API key; https://open-meteo.com ). Used by WeatherModuleCard.
 */

export interface OpenMeteoForecastResult {
  currentTempC: number
  currentWeatherCode: number
  currentLabel: string
  hourly: Array<{ label: string; tempC: number }>
  latitude: number
  longitude: number
}

/** WMO Weather interpretation codes (Open-Meteo). */
export function wmoWeatherLabel(code: number): string {
  if (code < 0) return 'Forecast'
  if (code === 0) return 'Clear sky'
  if (code === 1) return 'Mainly clear'
  if (code === 2) return 'Partly cloudy'
  if (code === 3) return 'Overcast'
  if (code === 45 || code === 48) return 'Fog'
  if (code >= 51 && code <= 57) return 'Drizzle'
  if (code >= 61 && code <= 67) return 'Rain'
  if (code >= 71 && code <= 77) return 'Snow'
  if (code >= 80 && code <= 82) return 'Rain showers'
  if (code >= 85 && code <= 86) return 'Snow showers'
  if (code >= 95 && code <= 99) return 'Thunderstorm'
  return 'Variable'
}

function pickHourlyTemp(
  times: string[],
  temps: (number | null)[],
  targetMs: number
): number | null {
  let best: { idx: number; diff: number } | null = null
  for (let i = 0; i < times.length; i++) {
    const t = new Date(times[i]).getTime()
    if (Number.isNaN(t)) continue
    const v = temps[i]
    if (v === null || v === undefined) continue
    const diff = Math.abs(t - targetMs)
    if (!best || diff < best.diff) best = { idx: i, diff }
  }
  return best !== null ? (temps[best.idx] as number) : null
}

export async function fetchOpenMeteoForecast(
  latitude: number,
  longitude: number
): Promise<OpenMeteoForecastResult> {
  const u = new URL('https://api.open-meteo.com/v1/forecast')
  u.searchParams.set('latitude', String(latitude))
  u.searchParams.set('longitude', String(longitude))
  u.searchParams.set('current', 'temperature_2m,weather_code')
  u.searchParams.set('hourly', 'temperature_2m')
  u.searchParams.set('timezone', 'auto')
  u.searchParams.set('forecast_days', '2')

  const res = await fetch(u.toString())
  if (!res.ok) {
    throw new Error(`Weather request failed: ${res.status}`)
  }
  const data = (await res.json()) as {
    current?: { temperature_2m?: number; weather_code?: number }
    hourly?: { time?: string[]; temperature_2m?: (number | null)[] }
  }

  const currentTemp = data.current?.temperature_2m
  const code = data.current?.weather_code ?? -1
  if (currentTemp === undefined || currentTemp === null) {
    throw new Error('Invalid weather response')
  }

  const times = data.hourly?.time ?? []
  const temps = data.hourly?.temperature_2m ?? []
  const now = Date.now()

  const hourly: Array<{ label: string; tempC: number }> = [{ label: 'Now', tempC: currentTemp }]
  for (const h of [3, 6, 9]) {
    const t = pickHourlyTemp(times, temps, now + h * 3600 * 1000)
    if (t !== null) hourly.push({ label: `+${h}h`, tempC: t })
  }

  return {
    currentTempC: currentTemp,
    currentWeatherCode: code,
    currentLabel: wmoWeatherLabel(code),
    hourly,
    latitude,
    longitude,
  }
}

export function formatCoordsShort(lat: number, lon: number): string {
  const ns = lat >= 0 ? 'N' : 'S'
  const ew = lon >= 0 ? 'E' : 'W'
  return `${Math.abs(lat).toFixed(2)}┬░${ns} ┬À ${Math.abs(lon).toFixed(2)}┬░${ew}`
}

export interface ParseSseResult {
  /** Content (message) text deltas */
  contentDeltas: string[]
  /** Reasoning/thinking text deltas (o1, extended content, etc.) */
  reasoningDeltas: string[]
  /** Incomplete line left in buffer */
  rest: string
}

/**
 * Parse buffered SSE text: complete lines become deltas; incomplete last line stays in `rest`.
 * Supports both content and reasoning_content (e.g. OpenAI o1, extended APIs).
 */
export function parseSseLines(buffer: string): ParseSseResult {
  const lines = buffer.split('\n')
  const rest = lines.pop() ?? ''
  const contentDeltas: string[] = []
  const reasoningDeltas: string[] = []
  for (const line of lines) {
    const trimmed = line.trim()
    if (!trimmed.startsWith('data:')) continue
    const data = trimmed.slice(5).trim()
    if (data === '[DONE]') continue
    try {
      const json = JSON.parse(data) as {
        choices?: Array<{
          delta?: {
            content?: string | Array<{ type?: string; text?: string }>
            reasoning_content?: string
          }
        }>
      }
      const delta = json.choices?.[0]?.delta
      if (!delta) continue

      if (typeof delta.reasoning_content === 'string' && delta.reasoning_content.length > 0) {
        reasoningDeltas.push(delta.reasoning_content)
      }

      const c = delta.content
      if (typeof c === 'string' && c.length > 0) {
        contentDeltas.push(c)
      } else if (Array.isArray(c)) {
        for (const block of c) {
          if (block?.type === 'reasoning' && typeof block.text === 'string' && block.text.length > 0) {
            reasoningDeltas.push(block.text)
          } else if (block?.type === 'message' && typeof block.text === 'string' && block.text.length > 0) {
            contentDeltas.push(block.text)
          } else if (typeof block?.text === 'string' && block.text.length > 0) {
            contentDeltas.push(block.text)
          }
        }
      }
    } catch {
      /* skip malformed line */
    }
  }
  return { contentDeltas, reasoningDeltas, rest }
}

/**
 * Cross-session lessons persistence for Jarvis (DigitalOcean self-hosted).
 *
 * @packageDocumentation
 * TODO(package.json): add runtime dependency `better-sqlite3` and dev dependency
 * `@types/better-sqlite3` when enabling production SQLite at `data/jarvis.db`.
 */

import fs from 'fs'
import path from 'path'
import { createRequire } from 'module'

/**
 * STORAGE STRATEGY
 *
 * Development  ÔåÆ JsonFileLessonsAdapter ÔåÆ data/lessons.json
 *   Simple, human-readable, no dependencies, zero setup
 *   Fine for hundreds of lessons ÔÇö no performance concern at this scale
 *
 * Production   ÔåÆ SQLiteLessonsAdapter ÔåÆ data/jarvis.db
 *   better-sqlite3, indexed by taskType, efficient tag search
 *   Jarvis is self-hosted on DigitalOcean ÔÇö SQLite is appropriate
 *   No external database dependency, file-based, zero network latency
 *
 * Future       ÔåÆ If Jarvis becomes multi-instance or cloud-deployed:
 *   Replace with a PostgreSQL adapter following the same interface
 *   {@link LessonsPersistenceAdapter} remains unchanged
 *   Only {@link createLessonsAdapter} factory function needs updating
 */

// ÔöÇÔöÇÔöÇ DEPLOYMENT NOTE ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
// TODO (production): Install better-sqlite3 on the DigitalOcean server:
//   npm install better-sqlite3
//
// TODO (production): Mount a persistent volume at /data in App Platform.
//   Without it, data/jarvis.db is wiped on every re-deploy.
//   All cross-session lessons (LessonsStore) depend on this volume.
//
// In development: data/lessons.json is used ÔÇö no extra setup needed.
// See createLessonsAdapter() JSDoc for the full deployment checklist.
// ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

/** Lesson row stored by {@link LessonsPersistenceAdapter} implementations. */
export interface PersistedLesson {
  id: string
  /** The lesson text. */
  content: string
  taskType: string
  sessionId: string
  /** How many times this lesson was used. */
  appliedCount: number
  /** 0.0ÔÇô1.0: when applied, did outcome improve? */
  successRate: number
  createdAt: string
  lastAppliedAt: string | null
  /** Extracted keywords for fast lookup. */
  tags: string[]
  source: 'reflexion' | 'uar' | 'manual'
}

/** Storage backend for {@link PersistedLesson} records. */
export interface LessonsPersistenceAdapter {
  save(lesson: PersistedLesson): Promise<void>
  getAll(): Promise<PersistedLesson[]>
  getByTaskType(taskType: string): Promise<PersistedLesson[]>
  getByTags(tags: string[]): Promise<PersistedLesson[]>
  updateApplied(id: string, success: boolean): Promise<void>
  delete(id: string): Promise<void>
  count(): Promise<number>
}

function isPersistedLessonSource(s: string): s is PersistedLesson['source'] {
  return s === 'reflexion' || s === 'uar' || s === 'manual'
}

function parseLessonRow(row: Record<string, unknown>): PersistedLesson | null {
  const id = typeof row.id === 'string' ? row.id : ''
  const content = typeof row.content === 'string' ? row.content : ''
  const taskType = typeof row.taskType === 'string' ? row.taskType : ''
  const sessionId = typeof row.sessionId === 'string' ? row.sessionId : ''
  const appliedCount = typeof row.appliedCount === 'number' ? row.appliedCount : 0
  const successRate = typeof row.successRate === 'number' ? row.successRate : 0
  const createdAt = typeof row.createdAt === 'string' ? row.createdAt : ''
  const lastAppliedAt =
    row.lastAppliedAt === null || row.lastAppliedAt === undefined
      ? null
      : typeof row.lastAppliedAt === 'string'
        ? row.lastAppliedAt
        : null
  let tags: string[] = []
  if (typeof row.tags === 'string') {
    try {
      const parsed: unknown = JSON.parse(row.tags)
      tags = Array.isArray(parsed) ? parsed.filter((t): t is string => typeof t === 'string') : []
    } catch {
      tags = []
    }
  } else if (Array.isArray(row.tags)) {
    tags = row.tags.filter((t): t is string => typeof t === 'string')
  }
  const srcRaw = typeof row.source === 'string' ? row.source : ''
  const source: PersistedLesson['source'] = isPersistedLessonSource(srcRaw) ? srcRaw : 'manual'
  if (id.length === 0) {
    return null
  }
  return {
    id,
    content,
    taskType,
    sessionId,
    appliedCount,
    successRate,
    createdAt,
    lastAppliedAt,
    tags,
    source,
  }
}

/** Minimal better-sqlite3 surface (optional peer dependency). */
interface SqliteDatabase {
  prepare(sql: string): {
    run(...params: unknown[]): { changes: number }
    all(...params: unknown[]): Record<string, unknown>[]
    get(...params: unknown[]): Record<string, unknown> | undefined
  }
  exec(sql: string): void
}

const SQLITE_DDL = `
CREATE TABLE IF NOT EXISTS lessons (
  id TEXT PRIMARY KEY,
  content TEXT NOT NULL,
  taskType TEXT NOT NULL,
  sessionId TEXT NOT NULL,
  appliedCount INTEGER DEFAULT 0,
  successRate REAL DEFAULT 0,
  createdAt TEXT NOT NULL,
  lastAppliedAt TEXT,
  tags TEXT NOT NULL,
  source TEXT NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_taskType ON lessons(taskType);
`

/**
 * JSON fileÔÇôbacked adapter for development (`data/lessons.json`).
 */
export class JsonFileLessonsAdapter implements LessonsPersistenceAdapter {
  private readonly filePath: string

  // NOTE: Constructor is now side-effect free (no FS calls).
  // File system init is deferred to _ensureFile() on first _read().
  // This makes the adapter safe to instantiate in test environments
  // without requiring mock FS setup before import.
  constructor(filePath: string = 'data/lessons.json') {
    this.filePath = path.resolve(filePath)
    // NOTE: File system init is deferred to _ensureFile(),
    // called on first read/write. Constructor is now synchronous
    // and safe to call at import time without any FS side effects.
  }

  /**
   * Idempotent setup: creates data/ directory and initialises lessons.json
   * if either is missing. Called before every read so construction is
   * free of file system side effects. Safe to call multiple times.
   */
  private _ensureFile(): void {
    const dir = path.dirname(this.filePath)
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true })
    }
    if (!fs.existsSync(this.filePath)) {
      fs.writeFileSync(this.filePath, '[]', 'utf-8')
    }
  }

  private _read(): PersistedLesson[] {
    this._ensureFile()
    try {
      const raw = fs.readFileSync(this.filePath, 'utf-8')
      const parsed: unknown = JSON.parse(raw)
      if (!Array.isArray(parsed)) {
        return []
      }
      const out: PersistedLesson[] = []
      for (const item of parsed) {
        if (item !== null && typeof item === 'object' && !Array.isArray(item)) {
          const row = parseLessonRow(item as Record<string, unknown>)
          if (row !== null) {
            out.push(row)
          }
        }
      }
      return out
    } catch {
      return []
    }
  }

  // All public mutating methods call _read() before _write(), so the file
  // and parent directory are always ensured. No _ensureFile() here.
  private _write(lessons: PersistedLesson[]): void {
    fs.writeFileSync(this.filePath, `${JSON.stringify(lessons, null, 2)}\n`, 'utf-8')
  }

  /** @inheritdoc */
  async save(lesson: PersistedLesson): Promise<void> {
    const lessons = this._read()
    const i = lessons.findIndex((l) => l.id === lesson.id)
    if (i >= 0) {
      lessons[i] = lesson
    } else {
      lessons.push(lesson)
    }
    this._write(lessons)
  }

  /** @inheritdoc */
  async getAll(): Promise<PersistedLesson[]> {
    return this._read()
  }

  /** @inheritdoc */
  async getByTaskType(taskType: string): Promise<PersistedLesson[]> {
    return this._read().filter((l) => l.taskType === taskType)
  }

  /** @inheritdoc */
  async getByTags(tags: string[]): Promise<PersistedLesson[]> {
    if (tags.length === 0) {
      return []
    }
    const query = new Set(tags)
    return this._read().filter((lesson) => lesson.tags.some((t) => query.has(t)))
  }

  /** @inheritdoc */
  async updateApplied(id: string, success: boolean): Promise<void> {
    const lessons = this._read()
    const lesson = lessons.find((l) => l.id === id)
    if (lesson === undefined) {
      return
    }
    const appliedCount = lesson.appliedCount + 1
    const newRate =
      ((lesson.successRate * (appliedCount - 1)) + (success ? 1 : 0)) / appliedCount
    lesson.appliedCount = appliedCount
    lesson.successRate = newRate
    lesson.lastAppliedAt = new Date().toISOString()
    this._write(lessons)
  }

  /** @inheritdoc */
  async delete(id: string): Promise<void> {
    this._write(this._read().filter((l) => l.id !== id))
  }

  /** @inheritdoc */
  async count(): Promise<number> {
    return this._read().length
  }
}

/**
 * SQLite-backed adapter for production (`data/jarvis.db`).
 */
export class SQLiteLessonsAdapter implements LessonsPersistenceAdapter {
  private readonly resolvedPath: string
  private db: SqliteDatabase | null = null
  private initPromise: Promise<SqliteDatabase> | null = null

  constructor(dbPath: string = 'data/jarvis.db') {
    this.resolvedPath = path.resolve(dbPath)
  }

  private async getDb(): Promise<SqliteDatabase> {
    if (this.db !== null) {
      return this.db
    }
    if (this.initPromise === null) {
      this.initPromise = (async () => {
        const { default: Database } = await import('better-sqlite3')
        fs.mkdirSync(path.dirname(this.resolvedPath), { recursive: true })
        const database = new Database(this.resolvedPath) as SqliteDatabase
        database.exec(SQLITE_DDL)
        this.db = database
        return database
      })()
    }
    return this.initPromise
  }

  private rowToLesson(row: Record<string, unknown>): PersistedLesson | null {
    return parseLessonRow(row)
  }

  /** @inheritdoc */
  async save(lesson: PersistedLesson): Promise<void> {
    const db = await this.getDb()
    db.prepare(
      `INSERT OR REPLACE INTO lessons (id, content, taskType, sessionId, appliedCount, successRate, createdAt, lastAppliedAt, tags, source)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
    ).run(
      lesson.id,
      lesson.content,
      lesson.taskType,
      lesson.sessionId,
      lesson.appliedCount,
      lesson.successRate,
      lesson.createdAt,
      lesson.lastAppliedAt,
      JSON.stringify(lesson.tags),
      lesson.source,
    )
  }

  /** @inheritdoc */
  async getAll(): Promise<PersistedLesson[]> {
    const db = await this.getDb()
    const rows = db.prepare('SELECT * FROM lessons ORDER BY createdAt DESC').all()
    const out: PersistedLesson[] = []
    for (const row of rows) {
      const lesson = this.rowToLesson(row)
      if (lesson !== null) {
        out.push(lesson)
      }
    }
    return out
  }

  /** @inheritdoc */
  async getByTaskType(taskType: string): Promise<PersistedLesson[]> {
    const db = await this.getDb()
    const rows = db.prepare('SELECT * FROM lessons WHERE taskType = ? ORDER BY createdAt DESC').all(taskType)
    const out: PersistedLesson[] = []
    for (const row of rows) {
      const lesson = this.rowToLesson(row)
      if (lesson !== null) {
        out.push(lesson)
      }
    }
    return out
  }

  /** @inheritdoc */
  async getByTags(tags: string[]): Promise<PersistedLesson[]> {
    const all = await this.getAll()
    if (tags.length === 0) {
      return []
    }
    const query = new Set(tags)
    return all.filter((lesson) => lesson.tags.some((t) => query.has(t)))
  }

  /** @inheritdoc */
  async updateApplied(id: string, success: boolean): Promise<void> {
    const db = await this.getDb()
    const row = db.prepare('SELECT appliedCount, successRate FROM lessons WHERE id = ?').get(id)
    if (row === undefined) {
      return
    }
    const appliedCountPrev =
      typeof row.appliedCount === 'number' && !Number.isNaN(row.appliedCount) ? row.appliedCount : 0
    const successRatePrev =
      typeof row.successRate === 'number' && !Number.isNaN(row.successRate) ? row.successRate : 0
    const appliedCount = appliedCountPrev + 1
    const newRate = ((successRatePrev * (appliedCount - 1)) + (success ? 1 : 0)) / appliedCount
    db.prepare(
      'UPDATE lessons SET appliedCount = ?, successRate = ?, lastAppliedAt = ? WHERE id = ?',
    ).run(appliedCount, newRate, new Date().toISOString(), id)
  }

  /** @inheritdoc */
  async delete(id: string): Promise<void> {
    const db = await this.getDb()
    db.prepare('DELETE FROM lessons WHERE id = ?').run(id)
  }

  /** @inheritdoc */
  async count(): Promise<number> {
    const db = await this.getDb()
    const row = db.prepare('SELECT COUNT(*) AS n FROM lessons').get()
    const n = row !== undefined && typeof row.n === 'number' ? row.n : 0
    return n
  }
}

/**
 * Selects the appropriate lessons persistence adapter for the environment.
 *
 * DEVELOPMENT (NODE_ENV !== 'production'):
 *   JsonFileLessonsAdapter ÔåÆ data/lessons.json
 *   Zero dependencies, human-readable, easy to inspect and reset.
 *
 * PRODUCTION (NODE_ENV === 'production'):
 *   SQLiteLessonsAdapter ÔåÆ data/jarvis.db  (requires better-sqlite3)
 *   Falls back to JsonFileLessonsAdapter if better-sqlite3 is missing,
 *   with a console.warn telling you how to fix it.
 *
 * ÔöÇÔöÇÔöÇ DIGITALOCEAN DEPLOYMENT CHECKLIST ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
 * 1. npm install better-sqlite3        (on the server, not just locally)
 * 2. Ensure the Node process has write access to the data/ directory
 * 3. Confirm data/ is in .gitignore    (lessons are runtime state, not source)
 * 4. data/jarvis.db is created automatically on first run
 * 5. IMPORTANT: Mount a persistent volume at /data in App Platform config.
 *    Without a persistent volume, the db file is wiped on every re-deploy
 *    and all cross-session lessons are lost.
 *    DigitalOcean docs: App Platform ÔåÆ your app ÔåÆ Settings ÔåÆ Volumes
 *    Mount path: /data   Size: 1GB minimum
 * ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ
 */
export function createLessonsAdapter(): LessonsPersistenceAdapter {
  const production = process.env.NODE_ENV === 'production'
  if (production) {
    try {
      createRequire(import.meta.url).resolve('better-sqlite3')
      // eslint-disable-next-line no-console -- adapter diagnostics
      console.log(
        '[LessonsPersistence] SQLiteLessonsAdapter initialised (production). ' +
          'Lessons persisted to data/jarvis.db.',
      )
      return new SQLiteLessonsAdapter()
    } catch {
      // eslint-disable-next-line no-console -- adapter diagnostics
      console.warn(
        '[LessonsPersistence] WARNING: better-sqlite3 is not resolvable ' +
          'in production. Falling back to JsonFileLessonsAdapter. ' +
          'Lessons will still persist to data/lessons.json, but SQLite is ' +
          'strongly recommended for production. ' +
          'Fix: run "npm install better-sqlite3" on the DigitalOcean server, ' +
          'then restart the app.',
      )
      return new JsonFileLessonsAdapter()
    }
  }
  // eslint-disable-next-line no-console -- adapter diagnostics
  console.log('[LessonsPersistence] Using JsonFileLessonsAdapter (development)')
  return new JsonFileLessonsAdapter()
}

/** Process-wide lessons store backend. */
export const lessonsAdapter = createLessonsAdapter()

/**
 * Periodic screen observation (Electron + vision model). Gated by user setting proactiveVision.
 */

import { callLlmChat } from '@/lib/llm'
import { getJarvisNative } from '@/lib/jarvis-native-bridge'

const PROACTIVE_MODEL = 'gpt-4o-mini'

const SYSTEM = `You observe a screenshot of the user's desktop. If something clearly actionable stands out (error dialog, risky action, obvious next step they might miss), reply with exactly one line starting with SUGGEST: followed by brief spoken-friendly advice (max 25 words). Otherwise reply exactly: NONE`

/**
 * Captures the primary screen and asks the model for an optional suggestion line.
 * Returns null if capture/native is unavailable, or the raw model text.
 */
export async function runProactiveVisionObservation(signal?: AbortSignal): Promise<string | null> {
  const jn = getJarvisNative()
  if (!jn) return null

  const cap = await jn.screenCapture({ region: undefined })
  if (!cap.ok || !cap.data) return null

  const dataUrl = `data:image/png;base64,${cap.data}`
  const text = await callLlmChat(
    [
      { role: 'system', content: SYSTEM },
      {
        role: 'user',
        content: [
          { type: 'text', text: 'Analyze this screen. Reply with SUGGEST: ... or NONE.' },
          { type: 'image_url', image_url: { url: dataUrl, detail: 'low' } },
        ],
      },
    ],
    PROACTIVE_MODEL,
    { signal, max_tokens: 120, temperature: 0.2 },
  )

  return text.trim()
}

export function parseProactiveSuggestion(raw: string): string | null {
  const t = raw.trim()
  if (!t || /^NONE\b/i.test(t)) return null
  const m = t.match(/^SUGGEST:\s*(.+)$/i)
  if (m?.[1]) return m[1].trim()
  if (/^suggest\b/i.test(t)) return t.replace(/^SUGGEST:\s*/i, '').trim()
  return null
}

/**
 * Local post scheduler.
 * Stores scheduled posts in localStorage and fires them when due.
 */

import { randomIdSegment } from '@/lib/secure-random'
import { postTweet } from './social-api'

export interface ScheduledPost {
  id: string
  platform: 'x' | 'threads'
  text: string
  scheduledTime: string // ISO 8601
  createdAt: string
  status: 'pending' | 'posted' | 'failed'
  error?: string
  resultUrl?: string
}

const STORAGE_KEY = 'jarvis-scheduled-posts'

function loadPosts(): ScheduledPost[] {
  try {
    const raw = localStorage.getItem(STORAGE_KEY)
    return raw ? JSON.parse(raw) : []
  } catch {
    return []
  }
}

function savePosts(posts: ScheduledPost[]): void {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(posts))
}

export function schedulePost(
  platform: 'x' | 'threads',
  text: string,
  scheduledTime: string,
): ScheduledPost {
  const post: ScheduledPost = {
    id: `sched-${Date.now()}-${randomIdSegment()}`,
    platform,
    text,
    scheduledTime,
    createdAt: new Date().toISOString(),
    status: 'pending',
  }
  const posts = loadPosts()
  posts.push(post)
  savePosts(posts)
  return post
}

export function getScheduledPosts(): ScheduledPost[] {
  return loadPosts()
}

export function cancelScheduledPost(id: string): boolean {
  const posts = loadPosts()
  const idx = posts.findIndex(p => p.id === id)
  if (idx < 0) return false
  posts[idx].status = 'failed'
  posts[idx].error = 'Cancelled by user'
  savePosts(posts)
  return true
}

export function listScheduledPostsSummary(): string {
  const posts = loadPosts().filter(p => p.status === 'pending')
  if (posts.length === 0) return 'No scheduled posts.'
  return posts.map((p, i) => {
    const time = new Date(p.scheduledTime)
    const relative = formatRelativeTime(time)
    return `${i + 1}. [${p.platform.toUpperCase()}] "${p.text.slice(0, 60)}${p.text.length > 60 ? '...' : ''}" ÔÇö ${relative} (${time.toLocaleString()}) [id: ${p.id}]`
  }).join('\n')
}

function formatRelativeTime(date: Date): string {
  const now = Date.now()
  const diff = date.getTime() - now
  if (diff < 0) return 'overdue'
  const mins = Math.floor(diff / 60000)
  if (mins < 60) return `in ${mins} minute${mins === 1 ? '' : 's'}`
  const hours = Math.floor(mins / 60)
  if (hours < 24) return `in ${hours} hour${hours === 1 ? '' : 's'}`
  const days = Math.floor(hours / 24)
  return `in ${days} day${days === 1 ? '' : 's'}`
}

/**
 * Check for due posts and fire them.
 * Called on an interval from App.tsx.
 * Only handles X via API; Threads requires browser control (handled separately).
 */
export async function checkAndFireScheduled(
  onThreadsPost?: (text: string) => Promise<void>,
): Promise<void> {
  const posts = loadPosts()
  const now = Date.now()
  let changed = false

  for (const post of posts) {
    if (post.status !== 'pending') continue
    if (new Date(post.scheduledTime).getTime() > now) continue

    changed = true
    try {
      if (post.platform === 'x') {
        const result = await postTweet(post.text)
        post.status = 'posted'
        post.resultUrl = result.url
      } else if (post.platform === 'threads' && onThreadsPost) {
        await onThreadsPost(post.text)
        post.status = 'posted'
      } else {
        post.error = 'Threads posting requires browser ÔÇö will retry when browser is available'
      }
    } catch (e) {
      post.status = 'failed'
      post.error = e instanceof Error ? e.message : String(e)
    }
  }

  if (changed) savePosts(posts)
}

import { generateOAuthState } from '@/lib/oauth'
import type { OAuthToken } from '@/lib/types'

const SPOTIFY_AUTH = 'https://accounts.spotify.com/authorize'
const SPOTIFY_TOKEN = 'https://accounts.spotify.com/api/token'

const PKCE_VERIFIER_KEY = 'spotify_oauth_code_verifier'

/** Scopes for listing playlists and basic profile (embed playback still uses iframe). */
export const SPOTIFY_SCOPES = [
  'playlist-read-private',
  'playlist-read-collaborative',
  'user-read-email',
  'user-read-private',
].join(' ')

function redirectUri(): string {
  return `${window.location.origin}/oauth/callback`
}

function base64UrlEncode(buffer: ArrayBuffer): string {
  const bytes = new Uint8Array(buffer)
  let binary = ''
  for (let i = 0; i < bytes.byteLength; i++) {
    binary += String.fromCharCode(bytes[i]!)
  }
  return btoa(binary).replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '')
}

async function sha256(plain: string): Promise<ArrayBuffer> {
  const data = new TextEncoder().encode(plain)
  return crypto.subtle.digest('SHA-256', data)
}

function randomVerifier(): string {
  const array = new Uint8Array(32)
  crypto.getRandomValues(array)
  return base64UrlEncode(array.buffer)
}

/**
 * Spotify uses Authorization Code with PKCE (no client secret in the browser).
 */
export async function buildSpotifyAuthUrl(clientId: string): Promise<string | null> {
  const id = clientId.trim()
  if (!id) return null

  const verifier = randomVerifier()
  sessionStorage.setItem(PKCE_VERIFIER_KEY, verifier)

  const challenge = base64UrlEncode(await sha256(verifier))

  const state = generateOAuthState('spotify')
  sessionStorage.setItem('oauth_state', JSON.stringify(state))

  const params = new URLSearchParams({
    client_id: id,
    response_type: 'code',
    redirect_uri: redirectUri(),
    scope: SPOTIFY_SCOPES,
    state: state.nonce,
    code_challenge_method: 'S256',
    code_challenge: challenge,
  })

  return `${SPOTIFY_AUTH}?${params.toString()}`
}

export async function exchangeSpotifyCodeForToken(
  code: string,
  clientId: string
): Promise<OAuthToken | null> {
  const verifier = sessionStorage.getItem(PKCE_VERIFIER_KEY)
  sessionStorage.removeItem(PKCE_VERIFIER_KEY)
  if (!verifier) {
    console.error('Spotify PKCE: missing code_verifier')
    return null
  }

  const body = new URLSearchParams({
    grant_type: 'authorization_code',
    code,
    redirect_uri: redirectUri(),
    client_id: clientId.trim(),
    code_verifier: verifier,
  })

  try {
    const response = await fetch(SPOTIFY_TOKEN, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        Accept: 'application/json',
      },
      body: body.toString(),
    })

    if (!response.ok) {
      console.error('Spotify token exchange failed:', await response.text())
      return null
    }

    const data = (await response.json()) as {
      access_token: string
      refresh_token?: string
      expires_in: number
      token_type?: string
    }

    return {
      accessToken: data.access_token,
      refreshToken: data.refresh_token,
      expiresAt: Date.now() + (data.expires_in || 3600) * 1000,
      tokenType: data.token_type || 'Bearer',
    }
  } catch (e) {
    console.error('Spotify token exchange error:', e)
    return null
  }
}

export async function refreshSpotifyAccessToken(
  refreshToken: string,
  clientId: string
): Promise<OAuthToken | null> {
  const body = new URLSearchParams({
    grant_type: 'refresh_token',
    refresh_token: refreshToken,
    client_id: clientId.trim(),
  })

  try {
    const response = await fetch(SPOTIFY_TOKEN, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        Accept: 'application/json',
      },
      body: body.toString(),
    })

    if (!response.ok) {
      console.error('Spotify token refresh failed:', await response.text())
      return null
    }

    const data = (await response.json()) as {
      access_token: string
      refresh_token?: string
      expires_in: number
      token_type?: string
    }

    return {
      accessToken: data.access_token,
      refreshToken: data.refresh_token ?? refreshToken,
      expiresAt: Date.now() + (data.expires_in || 3600) * 1000,
      tokenType: data.token_type || 'Bearer',
    }
  } catch (e) {
    console.error('Spotify token refresh error:', e)
    return null
  }
}

import { WORLD_RADIO_SEARCH_SEEDS } from '@/lib/tunein-world-seeds'

/** Official TuneIn embedded player base (see https://cms.tunein.com/listen/embedded/). */
const TUNEIN_PLAYER_BASE = 'https://tunein.com/embed/player'

/** Max stations parsed from a single OPML search response (API typically returns &lt; ~100). */
const MAX_PARSE_PER_SEARCH = 500

const WORLDWIDE_BATCH_SIZE = 10

export interface TuneInPreset {
  readonly name: string
  readonly stationId: string
}

/** Curated defaults so the module works out of the box; override via env. */
export const TUNEIN_DEFAULT_PRESETS: readonly TuneInPreset[] = [
  { name: 'Example stream', stationId: 's24939' },
  { name: 'Switch Hits', stationId: 's323596' },
  { name: 'Example stream B', stationId: 's209772' },
]

function normalizeStationId(raw: string): string {
  const t = raw.trim()
  if (!t) return 's24939'
  const id = t.replace(/^\/+|\/+$/g, '')
  return id.startsWith('s') ? id : `s${id}`
}

/**
 * Build the iframe `src` for TuneInÔÇÖs embed player.
 * Optional query params: `background=dark`, `autoplay=true` (TuneIn docs).
 */
export function buildTuneInPlayerUrl(
  stationId: string,
  options?: { readonly background?: 'dark' | 'light'; readonly autoplay?: boolean }
): string {
  const id = normalizeStationId(stationId)
  const params = new URLSearchParams()
  if (options?.background === 'light') {
    /* default is light ÔÇö omit or set explicitly if TuneIn adds param */
  } else {
    params.set('background', 'dark')
  }
  if (options?.autoplay) params.set('autoplay', 'true')
  const q = params.toString()
  const path = `${TUNEIN_PLAYER_BASE}/${id}/`
  return q ? `${path}?${q}` : path
}

/**
 * Use full embed URL from env, or build from `VITE_TUNEIN_STATION_ID` (default first preset).
 */
export function getTuneInEmbedUrlForStation(stationId: string): string {
  const full = import.meta.env.VITE_TUNEIN_EMBED_URL?.trim()
  if (full) {
    return full
  }
  return buildTuneInPlayerUrl(stationId, { background: 'dark' })
}

/** Initial station: `VITE_TUNEIN_STATION_ID`, else first preset. */
export function getDefaultTuneInStationId(presets: readonly TuneInPreset[]): string {
  const fromEnv = import.meta.env.VITE_TUNEIN_STATION_ID?.trim()
  if (fromEnv) return normalizeStationId(fromEnv)
  return presets[0]?.stationId ?? 's24939'
}

/**
 * Optional env: `Label1:s111,Label2:s222` (station IDs with or without `s` prefix).
 */
export function parseTuneInPresetsFromEnv(): TuneInPreset[] {
  const raw = import.meta.env.VITE_TUNEIN_PRESETS?.trim()
  if (!raw) return [...TUNEIN_DEFAULT_PRESETS]

  const out: TuneInPreset[] = []
  for (const part of raw.split(',')) {
    const segment = part.trim()
    if (!segment) continue
    const colon = segment.indexOf(':')
    if (colon <= 0) continue
    const name = segment.slice(0, colon).trim()
    const idPart = segment.slice(colon + 1).trim()
    if (!name || !idPart) continue
    out.push({ name, stationId: normalizeStationId(idPart) })
  }
  return out.length > 0 ? out : [...TUNEIN_DEFAULT_PRESETS]
}

/**
 * RadioTime OPML base URL. Prefer same-origin `/tunein-opml` so the browser never hits CORS
 * (Vite dev + preview proxy, Electron static server, or host rewrites ÔåÆ opml.radiotime.com).
 * Override with full origin if you proxy elsewhere.
 */
function getOpmlBaseUrl(): string {
  const fromEnv = import.meta.env.VITE_TUNEIN_OPML_PROXY?.trim()
  if (fromEnv) return fromEnv.replace(/\/$/, '')
  return '/tunein-opml'
}

export interface TuneInSearchStation {
  readonly name: string
  readonly stationId: string
  readonly subtext?: string
  readonly imageUrl?: string
}

interface OpmlOutlineRow {
  readonly type?: string
  readonly item?: string
  readonly text?: string
  readonly guide_id?: string
  readonly preset_id?: string
  readonly subtext?: string
  readonly image?: string
  readonly URL?: string
}

function extractStationIdFromRow(row: OpmlOutlineRow): string | null {
  const tryId = (raw: string | undefined): string | null => {
    const t = raw?.trim()
    if (!t) return null
    return /^s\d+$/i.test(t) ? normalizeStationId(t) : null
  }
  const fromFields = tryId(row.guide_id) ?? tryId(row.preset_id)
  if (fromFields) return fromFields

  const url = row.URL?.trim() ?? ''
  const fromQuery = /(?:^|[?&])id=(s\d+)/i.exec(url)
  if (fromQuery) return normalizeStationId(fromQuery[1])
  const fromPath = /\/(s\d+)(?:\/?(?:\?|$))/i.exec(url)
  return fromPath ? normalizeStationId(fromPath[1]) : null
}

function rowLooksLikeRadioStation(row: OpmlOutlineRow): boolean {
  if (row.type === 'audio') return true
  if (row.URL?.includes('Tune.ashx') && row.URL.includes('id=s')) return true
  return false
}

function parseOpmlSearchBody(body: OpmlOutlineRow[], limit: number): TuneInSearchStation[] {
  const seen = new Set<string>()
  const out: TuneInSearchStation[] = []

  for (const row of body) {
    if (!rowLooksLikeRadioStation(row)) continue
    if (row.item === 'show' || row.item === 'topic') continue

    const stationId = extractStationIdFromRow(row)
    if (!stationId || seen.has(stationId)) continue
    seen.add(stationId)

    const name = (row.text ?? stationId).trim() || stationId
    out.push({
      name,
      stationId,
      subtext: row.subtext?.trim(),
      imageUrl: row.image?.trim(),
    })
    if (out.length >= limit) break
  }

  return out
}

async function fetchOpmlSearch(
  query: string,
  extraParams: Record<string, string>,
  parseLimit: number
): Promise<TuneInSearchStation[]> {
  const base = getOpmlBaseUrl()
  const params = new URLSearchParams({
    query: query.trim() || 'radio',
    render: 'json',
    ...extraParams,
  })
  const res = await fetch(`${base}/search.ashx?${params}`)
  if (!res.ok) {
    throw new Error(`TuneIn search failed (${res.status})`)
  }

  let data: { body?: OpmlOutlineRow[] }
  try {
    data = (await res.json()) as { body?: OpmlOutlineRow[] }
  } catch {
    throw new Error('TuneIn search returned invalid JSON')
  }

  const body = Array.isArray(data.body) ? data.body : []
  const cap = Math.min(Math.max(parseLimit, 1), MAX_PARSE_PER_SEARCH)
  return parseOpmlSearchBody(body, cap)
}

/**
 * Search TuneIn / RadioTime for playable stations (`sÔÇª` ids work in the embed player).
 * Empty `query` defaults to `"radio"`. Retries without `types=s` if the first response parses empty.
 */
export async function searchTuneInStations(query: string, limit = 24): Promise<TuneInSearchStation[]> {
  const q = query.trim() || 'radio'
  const parseLimit = Math.min(Math.max(limit, 96), MAX_PARSE_PER_SEARCH)
  let stations = await fetchOpmlSearch(q, { types: 's' }, parseLimit)
  if (stations.length === 0) {
    stations = await fetchOpmlSearch(q, {}, parseLimit)
  }
  return stations.slice(0, limit)
}

export interface TuneInWorldwideOptions {
  /** Max unique stations to collect (default 4000). */
  readonly maxTotal?: number
  /** Override seed queries (merged from RadioTime search). */
  readonly seedQueries?: readonly string[]
}

/**
 * Merge many RadioTime searches (world regions, genres, cities) into one deduplicated list.
 * Produces thousands of unique stations when the network and API cooperate.
 */
export async function searchTuneInStationsWorldwide(options?: TuneInWorldwideOptions): Promise<TuneInSearchStation[]> {
  const maxTotal = options?.maxTotal ?? 4000
  const seeds = options?.seedQueries ?? WORLD_RADIO_SEARCH_SEEDS
  const seen = new Set<string>()
  const out: TuneInSearchStation[] = []

  for (let i = 0; i < seeds.length && out.length < maxTotal; i += WORLDWIDE_BATCH_SIZE) {
    const batch = seeds.slice(i, i + WORLDWIDE_BATCH_SIZE)
    const results = await Promise.all(
      batch.map((q) =>
        searchTuneInStations(q, MAX_PARSE_PER_SEARCH).catch(() => [] as TuneInSearchStation[])
      )
    )
    for (const list of results) {
      for (const s of list) {
        if (seen.has(s.stationId)) continue
        seen.add(s.stationId)
        out.push(s)
        if (out.length >= maxTotal) return out
      }
    }
  }
  return out
}

let worldwideCatalogCache: TuneInSearchStation[] | null = null
let worldwideCatalogPromise: Promise<TuneInSearchStation[]> | null = null

/** Session cache so the rail does not re-fetch thousands of stations on every navigation. */
export async function getTuneInWorldwideCatalog(maxTotal = 4000): Promise<TuneInSearchStation[]> {
  if (worldwideCatalogCache && worldwideCatalogCache.length > 0) {
    return worldwideCatalogCache.slice(0, maxTotal)
  }
  if (worldwideCatalogPromise) {
    const rows = await worldwideCatalogPromise
    return rows.slice(0, maxTotal)
  }
  worldwideCatalogPromise = searchTuneInStationsWorldwide({ maxTotal })
    .then((rows) => {
      worldwideCatalogCache = rows
      worldwideCatalogPromise = null
      return rows
    })
    .catch((err) => {
      worldwideCatalogPromise = null
      throw err
    })
  return worldwideCatalogPromise
}

/** For tests or ÔÇ£refresh catalogÔÇØ UI. */
export function clearTuneInWorldwideCatalogCache(): void {
  worldwideCatalogCache = null
  worldwideCatalogPromise = null
}

/** Map env presets to search-shaped rows for fallback UI. */
export function tuneInPresetsAsSearchStations(presets: readonly TuneInPreset[]): TuneInSearchStation[] {
  return presets.map((p) => ({
    name: p.name,
    stationId: p.stationId,
  }))
}

/** Tune.ashx returns stream objects with url, bitrate, reliability, media_type. */
export interface TuneInStreamInfo {
  readonly url: string
  readonly bitrate?: number
  readonly reliability?: number
  readonly media_type?: string
}

/**
 * Resolve direct stream URL(s) for a station via Tune.ashx.
 * Use the returned URL with a native <audio> element for ad-free playback (no TuneIn embed UI).
 */
export async function fetchTuneInStreamUrl(stationId: string): Promise<TuneInStreamInfo | null> {
  const id = normalizeStationId(stationId)
  const base = getOpmlBaseUrl()
  const params = new URLSearchParams({
    id,
    formats: 'aac,mp3',
    render: 'json',
  })
  const res = await fetch(`${base}/Tune.ashx?${params}`)
  if (!res.ok) return null

  let data: { body?: Array<{ url?: string; URL?: string; bitrate?: number; reliability?: number; media_type?: string }> }
  try {
    data = (await res.json()) as typeof data
  } catch {
    return null
  }

  const body = Array.isArray(data?.body) ? data.body : []
  const streams = body
    .map((s) => {
      const raw = (s?.url ?? s?.URL ?? '').trim()
      if (!raw) return null
      return {
        url: raw.replace(/^http:\/\//, 'https://'),
        bitrate: Number(s?.bitrate) || 0,
        reliability: Number(s?.reliability) || 0,
        media_type: String(s?.media_type || 'mp3'),
      }
    })
    .filter((s): s is { url: string; bitrate: number; reliability: number; media_type: string } => s !== null)
  if (streams.length === 0) return null

  const sorted = [...streams].sort((a, b) => (b.reliability - a.reliability) || (b.bitrate - a.bitrate))
  const best = sorted[0]
  return { url: best.url, bitrate: best.bitrate, reliability: best.reliability, media_type: best.media_type }
}

export interface TuneInNowPlaying {
  readonly stationId: string
  readonly song?: string
  readonly artist?: string
}

/**
 * Fetch now-playing metadata (song, artist) via Describe.ashx.
 * Not all stations provide this; returns empty when unavailable.
 */
export async function fetchTuneInNowPlaying(stationId: string): Promise<TuneInNowPlaying> {
  const id = normalizeStationId(stationId)
  const base = getOpmlBaseUrl()
  const params = new URLSearchParams({ id, render: 'json' })
  const res = await fetch(`${base}/Describe.ashx?${params}`)
  if (!res.ok) return { stationId: id, song: undefined, artist: undefined }

  let data: { body?: Array<Record<string, unknown>> }
  try {
    data = (await res.json()) as typeof data
  } catch {
    return { stationId: id, song: undefined, artist: undefined }
  }

  const body = Array.isArray(data?.body) ? data.body : []

  function extract(obj: Record<string, unknown>): { song?: string; artist?: string } {
    const song =
      (typeof obj.current_song === 'string' ? obj.current_song.trim() : '') ||
      (typeof (obj as Record<string, unknown>).currentSong === 'string'
        ? String((obj as Record<string, unknown>).currentSong).trim()
        : '')
    const artist =
      (typeof obj.current_artist === 'string' ? obj.current_artist.trim() : '') ||
      (typeof (obj as Record<string, unknown>).currentArtist === 'string'
        ? String((obj as Record<string, unknown>).currentArtist).trim()
        : '')
    if (song || artist) return { song: song || undefined, artist: artist || undefined }
    const station = obj.station as Record<string, unknown> | undefined
    if (station) return extract(station)
    const children = obj.children as Array<Record<string, unknown>> | undefined
    if (Array.isArray(children)) {
      for (const c of children) {
        const out = extract(c)
        if (out.song || out.artist) return out
      }
    }
    return {}
  }

  for (const item of body) {
    const { song, artist } = extract(item)
    if (song || artist) return { stationId: id, song, artist }
  }
  return { stationId: id, song: undefined, artist: undefined }
}

/**
 * URL validation and parsing helpers.
 *
 * Provides safe, fallback-tolerant URL parsing, scheme/origin checking,
 * and path-traversal detection for security boundaries.
 *
 * @module lib/url-validation
 */

/**
 * Result of safe URL parsing.
 */
export interface ParsedUrl {
  /** Protocol/scheme (e.g. 'https') without colon */
  scheme: string
  /** Origin (protocol + hostname + port) ÔÇö e.g. 'https://example.com:8080' */
  origin: string
  /** Pathname starting with / */
  pathname: string
  /** Search string including ? or empty */
  search: string
}

/**
 * Test if a value is a valid, parseable URL.
 *
 * @param url - Value to test
 * @returns true if URL can be parsed without error
 *
 * @example
 * isValidUrl('https://example.com') // Ô£ô true
 * isValidUrl('not-a-url') // Ô£ù false
 * isValidUrl(null) // Ô£ù false
 */
export function isValidUrl(url: unknown): boolean {
  if (typeof url !== 'string') return false
  try {
    new URL(url)
    return true
  } catch {
    return false
  }
}

/**
 * Test if a scheme is in the allowed list for web navigation.
 *
 * Only 'http' and 'https' are safe for Jarvis navigation context.
 *
 * @param scheme - Scheme name (without colon) ÔÇö e.g. 'https'
 * @returns true if scheme is in whitelist
 *
 * @example
 * isSafeScheme('https') // Ô£ô true
 * isSafeScheme('http') // Ô£ô true
 * isSafeScheme('ftp') // Ô£ù false
 * isSafeScheme('file') // Ô£ù false
 * isSafeScheme('javascript') // Ô£ù false
 */
export function isSafeScheme(scheme: string): boolean {
  const safe = new Set(['http', 'https', 'ws', 'wss'])
  return safe.has(scheme.toLowerCase())
}

/**
 * Test if an origin matches an allowed origin list.
 *
 * Supports exact match and subdomain wildcards (e.g. `*.example.com`).
 *
 * @param origin - Origin to test (e.g. 'https://api.example.com')
 * @param allowedOrigins - List of allowed origins, may include `*.domain` wildcards
 * @returns true if origin is in whitelist or matches a wildcard pattern
 *
 * @example
 * isOriginAllowed('https://example.com', ['https://example.com']) // Ô£ô true
 * isOriginAllowed('https://api.example.com', ['https://*.example.com']) // Ô£ô true
 * isOriginAllowed('https://evil.com', ['https://example.com']) // Ô£ù false
 */
export function isOriginAllowed(origin: string, allowedOrigins: string[]): boolean {
  return allowedOrigins.some(allowed => {
    if (allowed.includes('*')) {
      // eslint-disable-next-line no-regex-spaces
      const pattern = allowed.replace(/\*/g, '[a-zA-Z0-9.-]+')
      const regex = new RegExp(`^${pattern}$`)
      return regex.test(origin)
    }
    return origin === allowed
  })
}

/**
 * Parse a URL safely into components without throwing.
 *
 * @param url - URL string to parse
 * @returns Structured components `{scheme, origin, pathname, search}`, or `null` on parse failure
 *
 * @example
 * parseUrlSafely('https://example.com:8080/api/v1?key=value')
 * // => {
 * //   scheme: 'https',
 * //   origin: 'https://example.com:8080',
 * //   pathname: '/api/v1',
 * //   search: '?key=value'
 * // }
 * parseUrlSafely('not-a-url') // => null
 */
export function parseUrlSafely(url: string): ParsedUrl | null {
  try {
    const parsed = new URL(url)
    return {
      scheme: parsed.protocol.replace(/:$/, ''),
      origin: `${parsed.protocol}//${parsed.host}`,
      pathname: parsed.pathname,
      search: parsed.search,
    }
  } catch {
    return null
  }
}

/**
 * Detect path traversal attempts in a pathname.
 *
 * Flags `..` and percent-encoded variants like `%2e%2e`, `%252e%252e`, etc.
 *
 * @param pathname - Pathname to check (e.g. from parsed URL)
 * @returns true if pathname contains traversal indicators
 *
 * @example
 * isPathTraversalAttempt('../../../etc/passwd') // Ô£ô true
 * isPathTraversalAttempt('%2e%2e/admin') // Ô£ô true
 * isPathTraversalAttempt('/api/v1/users/123') // Ô£ù false
 */
export function isPathTraversalAttempt(pathname: string): boolean {
  // Normalize URL encoding by running decode up to 5 times (handles nested encoding)
  let normalized = pathname
  for (let i = 0; i < 5; i++) {
    const decoded = decodeURIComponent(normalized)
    if (decoded === normalized) break
    normalized = decoded
  }

  // Check for .. indicators
  return /\.\./.test(normalized) || /\.\.%/.test(normalized)
}

/**
 * Validate and sanitize a redirect URL for same-origin or whitelist match.
 *
 * Safe for use in location.href assignments or redirect responses.
 *
 * @param url - URL to validate (may be string, null, undefined)
 * @param allowedOrigins - List of allowed target origins (e.g. `['https://app.example.com']`)
 * @returns The validated URL, or `null` if invalid
 *
 * @example
 * sanitizeRedirectUrl('https://example.com/dashboard', ['https://example.com'])
 * // => 'https://example.com/dashboard'
 *
 * sanitizeRedirectUrl('https://evil.com/phishing', ['https://example.com'])
 * // => null (blocked)
 *
 * // Relative URLs are considered same-origin (generally safe)
 * sanitizeRedirectUrl('/dashboard', [])
 * // => '/dashboard'
 */
export function sanitizeRedirectUrl(url: unknown, allowedOrigins: string[]): string | null {
  if (typeof url !== 'string') return null
  if (!url) return null

  // Relative URLs (same-origin) are considered safe
  if (url.startsWith('/')) return url
  if (url.startsWith('#')) return url

  // Absolute URLs must match allowed origins
  const parsed = parseUrlSafely(url)
  if (!parsed) return null
  if (!isSafeScheme(parsed.scheme)) return null

  const origin = parsed.origin
  if (!isOriginAllowed(origin, allowedOrigins)) return null

  return url
}

/**
 * Validate a download or file-write path against sandbox restrictions.
 *
 * Prevents path traversal attempts (`..`) and ensures path is within allowed directories.
 *
 * @param downloadPath - Path to validate (absolute or relative)
 * @param allowedDirs - List of allowed base directories (e.g. `['./downloads', '/tmp/uploads']`)
 * @returns true if path is safe and within allowed directories
 *
 * @example
 * validateFileDownloadPath('/downloads/report.pdf', ['/downloads'])
 * // => true
 *
 * validateFileDownloadPath('/downloads/../../../etc/passwd', ['/downloads'])
 * // => false (path traversal attempt)
 *
 * validateFileDownloadPath('/uploads/file.pdf', ['/downloads'])
 * // => false (not in allowed directory)
 */
export function validateFileDownloadPath(downloadPath: string, allowedDirs: string[]): boolean {
  if (!downloadPath) return false
  if (isPathTraversalAttempt(downloadPath)) return false

  // Normalize path for comparison (remove trailing slash, resolve . references)
  // eslint-disable-next-line no-regex-spaces
  const normalize = (path: string) => path.replace(/\/+/g, '/').replace(/\/$/, '') || '/'

  const normalized = normalize(downloadPath)
  return allowedDirs.some(dir => {
    const normalizedDir = normalize(dir)
    return normalized.startsWith(normalizedDir + '/') || normalized === normalizedDir
  })
}

import { VoiceRealtimeError } from '@/lib/voice/errors'
import type {
  VoiceEventHandler,
  VoiceEventMap,
  VoiceEventName,
  VoiceSessionState,
} from '@/lib/voice/types'
import type { VoiceSession } from '@/lib/voice/voiceSession'

/** Successful `POST /v1/realtime/client_secrets` JSON (browser receives only this). */
export interface RealtimeClientSecretPayload {
  value?: string
  expires_at?: number
}

export interface OpenAIRealtimeVoiceSessionOptions {
  /**
   * Same-origin URL that returns OpenAI `client_secrets` JSON (`value` = ephemeral key).
   * Default: `/api/realtime/session` (Vite dev/preview proxy).
   */
  sessionUrl?: string
  /**
   * Browser posts SDP here with `Authorization: Bearer <ephemeral>` per OpenAI WebRTC docs.
   * Default: `https://api.openai.com/v1/realtime/calls`
   */
  realtimeCallsUrl?: string
  /** Optional body for `POST sessionUrl` (merged server-side with defaults). */
  sessionRequestBody?: Record<string, unknown>
  rtcConfiguration?: RTCConfiguration
}

type ListenerMap = {
  [K in VoiceEventName]: Set<VoiceEventHandler<K>>
}

/**
 * OpenAI Realtime GA: ephemeral client secret from your backend, then WebRTC to
 * `POST /v1/realtime/calls` and `oai-events` data channel for lifecycle events.
 *
 * Requires a secure context and browser WebRTC (`getUserMedia`, `RTCPeerConnection`).
 */
export class OpenAIRealtimeVoiceSession implements VoiceSession {
  private readonly sessionUrl: string
  private readonly realtimeCallsUrl: string
  private readonly sessionRequestBody: Record<string, unknown> | undefined
  private readonly rtcConfiguration: RTCConfiguration

  private connectGeneration = 0
  private pc: RTCPeerConnection | null = null
  private dc: RTCDataChannel | null = null
  private localStream: MediaStream | null = null
  private remoteAudio: HTMLAudioElement | null = null

  private readonly listeners: ListenerMap = {
    user_speech_started: new Set(),
    user_speech_stopped: new Set(),
    assistant_audio_started: new Set(),
    assistant_audio_stopped: new Set(),
    error: new Set(),
    connection_state_changed: new Set(),
    state_changed: new Set(),
  }

  private assistantOutputActive = false
  private activeResponseId: string | null = null
  private currentSessionState: VoiceSessionState = 'idle'

  constructor(options: OpenAIRealtimeVoiceSessionOptions = {}) {
    this.sessionUrl = options.sessionUrl ?? '/api/realtime/session'
    this.realtimeCallsUrl = options.realtimeCallsUrl ?? 'https://api.openai.com/v1/realtime/calls'
    this.sessionRequestBody = options.sessionRequestBody
    this.rtcConfiguration = options.rtcConfiguration ?? {
      iceServers: [{ urls: 'stun:stun.l.google.com:19302' }],
    }
  }

  on<E extends VoiceEventName>(event: E, handler: VoiceEventHandler<E>): void {
    this.listeners[event].add(handler as VoiceEventHandler<VoiceEventName>)
  }

  off<E extends VoiceEventName>(event: E, handler: VoiceEventHandler<E>): void {
    this.listeners[event].delete(handler as VoiceEventHandler<VoiceEventName>)
  }

  private emit<E extends VoiceEventName>(event: E, payload: VoiceEventMap[E]): void {
    for (const h of this.listeners[event]) {
      try {
        ;(h as VoiceEventHandler<E>)(payload)
      } catch {
        /* consumer */
      }
    }
  }

  private emitConnection(state: VoiceEventMap['connection_state_changed']['state']): void {
    this.emit('connection_state_changed', { state, timestamp: Date.now() })
  }

  private setSessionState(state: VoiceSessionState): void {
    this.currentSessionState = state
    this.emit('state_changed', { state, timestamp: Date.now() })
  }

  private emitError(err: Error): void {
    this.emit('error', { error: err, timestamp: Date.now() })
    this.setSessionState('error')
  }

  async connect(): Promise<void> {
    if (typeof RTCPeerConnection === 'undefined' || typeof navigator?.mediaDevices?.getUserMedia !== 'function') {
      const err = new VoiceRealtimeError(
        'NOT_SUPPORTED',
        'WebRTC / getUserMedia is not available in this environment.'
      )
      this.emitError(err)
      throw err
    }

    this.disconnectWithoutNotifyingIdle()
    const generation = this.connectGeneration
    this.setSessionState('connecting')
    this.emitConnection('connecting')

    try {
      const sessionRes = await fetch(this.sessionUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(this.sessionRequestBody ?? {}),
      })
      const sessionText = await sessionRes.text()
      if (generation !== this.connectGeneration) {
        return
      }
      if (!sessionRes.ok) {
        throw new VoiceRealtimeError(
          'SESSION_BOOTSTRAP_FAILED',
          `Realtime session HTTP ${sessionRes.status}: ${sessionText}`
        )
      }
      let secret: RealtimeClientSecretPayload
      try {
        secret = JSON.parse(sessionText) as RealtimeClientSecretPayload
      } catch (e) {
        throw new VoiceRealtimeError('SESSION_BOOTSTRAP_FAILED', 'Invalid JSON from session endpoint', {
          cause: e,
        })
      }
      const ephemeral = secret.value?.trim()
      if (!ephemeral) {
        throw new VoiceRealtimeError('MISSING_EPHEMERAL_KEY', 'Session response missing ephemeral `value`')
      }

      const pc = new RTCPeerConnection(this.rtcConfiguration)
      this.pc = pc

      pc.onconnectionstatechange = () => {
        if (pc.connectionState === 'failed') {
          this.emitConnection('failed')
          this.emitError(
            new VoiceRealtimeError('WEBRTC_NEGOTIATION_FAILED', `Peer connection ${pc.connectionState}`)
          )
        }
      }

      const remoteAudio = document.createElement('audio')
      remoteAudio.autoplay = true
      remoteAudio.setAttribute('playsInline', 'true')
      remoteAudio.style.display = 'none'
      document.body.appendChild(remoteAudio)
      this.remoteAudio = remoteAudio

      pc.ontrack = (ev) => {
        const [stream] = ev.streams
        if (stream && remoteAudio) {
          remoteAudio.srcObject = stream
          remoteAudio.play().catch(() => {
            /* may require user gesture; autoplay policy */
          })
        }
        // If the data channel omits `response.output_audio.delta` (common for WebRTC media path), treat remote audio as assistant output once a response exists.
        if (ev.track.kind === 'audio' && !this.assistantOutputActive && this.activeResponseId) {
          this.assistantOutputActive = true
          this.emit('assistant_audio_started', { timestamp: Date.now() })
          this.setSessionState('speaking')
        }
      }

      let localStream: MediaStream
      try {
        localStream = await navigator.mediaDevices.getUserMedia({ audio: true })
      } catch (e) {
        throw new VoiceRealtimeError('USER_MEDIA_DENIED', 'Microphone access was denied or unavailable.', {
          cause: e,
        })
      }
      if (generation !== this.connectGeneration) {
        localStream.getTracks().forEach((t) => t.stop())
        return
      }
      this.localStream = localStream
      for (const track of localStream.getTracks()) {
        pc.addTrack(track, localStream)
      }

      const dc = pc.createDataChannel('oai-events')
      this.dc = dc

      dc.onmessage = (ev) => {
        this.handleServerEvent(ev.data)
      }

      const offer = await pc.createOffer()
      await pc.setLocalDescription(offer)

      const sdpRes = await fetch(this.realtimeCallsUrl, {
        method: 'POST',
        body: offer.sdp ?? '',
        headers: {
          Authorization: `Bearer ${ephemeral}`,
          'Content-Type': 'application/sdp',
        },
      })
      const answerSdp = await sdpRes.text()
      if (generation !== this.connectGeneration) {
        return
      }
      if (!sdpRes.ok) {
        throw new VoiceRealtimeError(
          'WEBRTC_NEGOTIATION_FAILED',
          `Realtime calls HTTP ${sdpRes.status}: ${answerSdp}`
        )
      }

      await pc.setRemoteDescription({ type: 'answer', sdp: answerSdp })

      await new Promise<void>((resolve, reject) => {
        if (dc.readyState === 'open') {
          resolve()
          return
        }
        const t = window.setTimeout(
          () => reject(new VoiceRealtimeError('DATA_CHANNEL_FAILED', 'Data channel open timeout')),
          30_000
        )
        dc.addEventListener(
          'open',
          () => {
            clearTimeout(t)
            resolve()
          },
          { once: true }
        )
        dc.addEventListener(
          'error',
          () => {
            clearTimeout(t)
            reject(new VoiceRealtimeError('DATA_CHANNEL_FAILED', 'Data channel error'))
          },
          { once: true }
        )
      })

      if (generation !== this.connectGeneration) {
        return
      }

      this.emitConnection('connected')
      this.setSessionState('listening')
    } catch (e) {
      if (generation !== this.connectGeneration) {
        return
      }
      let err: VoiceRealtimeError
      if (e instanceof VoiceRealtimeError) {
        err = e
      } else {
        const msg = e instanceof Error ? e.message : 'Voice connection failed'
        err = new VoiceRealtimeError('WEBRTC_NEGOTIATION_FAILED', msg, { cause: e })
      }
      this.emitError(err)
      this.cleanupTracksAndPc()
      throw err
    }
  }

  disconnect(): void {
    this.connectGeneration++
    this.cleanupTracksAndPc()
    this.emitConnection('disconnected')
    this.setSessionState('idle')
  }

  /** Internal: release resources without emitting idle (used before reconnect). */
  private disconnectWithoutNotifyingIdle(): void {
    this.connectGeneration++
    this.cleanupTracksAndPc()
  }

  private cleanupTracksAndPc(): void {
    this.localStream?.getTracks().forEach((t) => t.stop())
    this.localStream = null

    this.dc?.close()
    this.dc = null

    this.pc?.close()
    this.pc = null

    if (this.remoteAudio) {
      this.remoteAudio.srcObject = null
      this.remoteAudio.remove()
      this.remoteAudio = null
    }

    this.assistantOutputActive = false
    this.activeResponseId = null
  }

  sendAudioChunk(chunk: ArrayBuffer | Uint8Array): void {
    /* WebRTC sends mic audio via the added MediaStreamTrack; chunk APIs are for future/non-WebRTC paths. */
    if (chunk.byteLength < 0) return
  }

  abortAssistant(): void {
    const dc = this.dc
    if (!dc || dc.readyState !== 'open') {
      return
    }
    const cancel: Record<string, unknown> = { type: 'response.cancel' }
    if (this.activeResponseId) {
      cancel.response_id = this.activeResponseId
    }
    try {
      dc.send(JSON.stringify(cancel))
    } catch (e) {
      const err =
        e instanceof Error ? e : new Error(`Failed to send response.cancel: ${String(e)}`)
      this.emitError(err)
    }
  }

  private handleServerEvent(raw: string): void {
    let parsed: unknown
    try {
      parsed = JSON.parse(raw) as unknown
    } catch {
      return
    }
    if (!parsed || typeof parsed !== 'object' || !('type' in parsed)) {
      return
    }
    const type = (parsed as { type: string }).type
    const now = Date.now()

    switch (type) {
      case 'input_audio_buffer.speech_started':
        this.emit('user_speech_started', { timestamp: now })
        if (this.currentSessionState === 'speaking' || this.currentSessionState === 'thinking') {
          this.setSessionState('interrupted')
        } else {
          this.setSessionState('listening')
        }
        break

      case 'input_audio_buffer.speech_stopped':
        this.emit('user_speech_stopped', { timestamp: now })
        this.setSessionState('listening')
        break

      case 'response.created': {
        const rid = (parsed as { response?: { id?: string } }).response?.id
        if (rid) {
          this.activeResponseId = rid
        }
        this.setSessionState('thinking')
        break
      }

      case 'response.output_audio.delta':
        if (!this.assistantOutputActive) {
          this.assistantOutputActive = true
          this.emit('assistant_audio_started', { timestamp: now })
          this.setSessionState('speaking')
        }
        break

      case 'response.done': {
        const wasActive = this.assistantOutputActive
        this.assistantOutputActive = false
        this.activeResponseId = null
        if (wasActive) {
          this.emit('assistant_audio_stopped', { timestamp: now })
        }
        this.setSessionState('listening')
        break
      }

      case 'response.cancelled': {
        const wasActive = this.assistantOutputActive
        this.assistantOutputActive = false
        this.activeResponseId = null
        if (wasActive) {
          this.emit('assistant_audio_stopped', { timestamp: now })
        }
        this.setSessionState('interrupted')
        break
      }

      case 'error': {
        const msg =
          (parsed as { error?: { message?: string } }).error?.message ??
          (parsed as { message?: string }).message ??
          'Realtime error event'
        this.emitError(new Error(msg))
        break
      }

      default:
        break
    }
  }
}

/**
 * LLM-backed expansion of {@link BranchCandidate}s for the Tree-of-Thoughts engine.
 *
 * @module reasoning/branchGenerator
 */

import OpenAI from 'openai'

import { buildScratchpadSummary } from './cotScratchpad'
import { scratchpadStore } from './scratchpadStore'
import {
  TOT_DEFAULTS,
  createTree,
  getNodePath,
  type BranchCandidate,
  type ThoughtNode,
  type ToTTree,
} from './totTypes'

const LOG = '[BranchGenerator]'

const STOP_WORDS = new Set([
  'the',
  'a',
  'an',
  'and',
  'or',
  'for',
  'to',
  'of',
  'in',
  'on',
  'with',
  'this',
  'that',
  'from',
  'by',
  'as',
  'is',
  'are',
  'was',
  'were',
  'be',
  'been',
  'being',
  'have',
  'has',
  'had',
  'do',
  'does',
  'did',
  'will',
  'would',
  'could',
  'should',
  'may',
  'might',
  'must',
  'not',
  'but',
  'if',
  'then',
  'than',
  'so',
  'such',
  'at',
  'it',
  'its',
  'we',
  'you',
  'they',
  'their',
  'our',
  'your',
])

function extractJsonObject(text: string): string {
  const t = text.trim()
  if (!t.startsWith('```')) {
    return t
  }
  const firstNl = t.indexOf('\n')
  const close = firstNl >= 0 ? t.indexOf('```', firstNl + 1) : -1
  if (firstNl >= 0 && close > firstNl) {
    return t.slice(firstNl + 1, close).trim()
  }
  return t
}

function tokenizeForOverlap(text: string): Set<string> {
  const words = text
    .toLowerCase()
    .split(/[^a-z0-9]+/)
    .map((w) => w.trim())
    .filter((w) => w.length > 2 && !STOP_WORDS.has(w))
  return new Set(words)
}

/** Jaccard similarity on word sets from approach + thought. */
function candidateSimilarity(a: BranchCandidate, b: BranchCandidate): number {
  const ta = tokenizeForOverlap(`${a.approach} ${a.thought}`)
  const tb = tokenizeForOverlap(`${b.approach} ${b.thought}`)
  if (ta.size === 0 && tb.size === 0) return 1
  if (ta.size === 0 || tb.size === 0) return 0
  let inter = 0
  for (const w of ta) {
    if (tb.has(w)) inter++
  }
  const union = ta.size + tb.size - inter
  return union === 0 ? 0 : inter / union
}

function normalizeCandidate(raw: unknown): BranchCandidate | null {
  if (raw === null || typeof raw !== 'object') return null
  const o = raw as Record<string, unknown>
  const approach = typeof o.approach === 'string' ? o.approach.trim() : ''
  const thought = typeof o.thought === 'string' ? o.thought.trim() : ''
  if (approach.length === 0 || thought.length === 0) return null

  const keyAssumptions: string[] = []
  if (Array.isArray(o.keyAssumptions)) {
    for (const x of o.keyAssumptions) {
      if (typeof x === 'string' && x.trim().length > 0) keyAssumptions.push(x.trim())
    }
  }

  const riskFactors: string[] = []
  if (Array.isArray(o.riskFactors)) {
    for (const x of o.riskFactors) {
      if (typeof x === 'string' && x.trim().length > 0) riskFactors.push(x.trim())
    }
  }

  let estimatedSteps = 1
  if (typeof o.estimatedSteps === 'number' && Number.isFinite(o.estimatedSteps)) {
    estimatedSteps = Math.max(1, Math.min(5, Math.round(o.estimatedSteps)))
  }

  return {
    approach,
    thought,
    keyAssumptions,
    estimatedSteps,
    riskFactors,
  }
}

function parseBranchCandidates(content: string, expectedMax: number): BranchCandidate[] {
  try {
    const raw = extractJsonObject(content)
    const parsed: unknown = JSON.parse(raw)

    let rows: unknown[]
    if (Array.isArray(parsed)) {
      rows = parsed
    } else if (parsed !== null && typeof parsed === 'object') {
      const o = parsed as Record<string, unknown>
      const b = o.branches ?? o.candidates
      rows = Array.isArray(b) ? b : []
    } else {
      return []
    }

    const out: BranchCandidate[] = []
    for (const row of rows) {
      const c = normalizeCandidate(row)
      if (c !== null) out.push(c)
      if (out.length >= expectedMax) break
    }
    return out
  } catch {
    return []
  }
}

function fallbackCandidate(taskDescription: string): BranchCandidate {
  return {
    approach: 'Direct execution',
    thought: taskDescription,
    keyAssumptions: [],
    estimatedSteps: 1,
    riskFactors: [],
  }
}

/**
 * Calls OpenAI to propose distinct {@link BranchCandidate} lines for ToT expansion.
 */
export default class BranchGenerator {
  private readonly openai: OpenAI
  private readonly model: string

  /**
   * @param model - Chat model id (default `gpt-4o`).
   */
  constructor(model: string = 'gpt-4o') {
    this.openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY ?? '' })
    this.model = model
  }

  /**
   * Produces up to `count` diverse branch candidates below `parentNode` (root when `null`).
   */
  async generateBranches(
    taskDescription: string,
    taskType: string,
    parentNode: ThoughtNode | null,
    tree: ToTTree,
    sessionId: string,
    count: number = TOT_DEFAULTS.BRANCH_FACTOR,
  ): Promise<BranchCandidate[]> {
    const pathContext = parentNode
      ? getNodePath(tree, parentNode.id)
          .map((n) => `Depth ${String(n.depth)}: ${n.approach}`)
          .join('\n')
      : 'Root ÔÇö no prior path'

    const pad = scratchpadStore.getForSession(sessionId)
    const padContext = pad !== null ? buildScratchpadSummary(pad) : ''

    const deadEnds =
      pad !== null && pad.deadEnds.length > 0
        ? pad.deadEnds.map((d) => `AVOID: ${d.approach} (${d.avoidanceHint})`).join('\n')
        : ''

    const pathBlock = parentNode !== null ? `Current path:\n${pathContext}\n` : ''
    const deadBlock = deadEnds.length > 0 ? `FAILED APPROACHES TO AVOID:\n${deadEnds}\n` : ''

    const system = `You are a strategic planning agent. Generate ${String(count)} DISTINCT candidate approaches to solve a task.

Rules:
- Each approach must be genuinely different (different strategy, not just different wording)
- Each approach must be specific enough to execute
- Acknowledge real trade-offs honestly
- If prior approaches failed, do NOT repeat them

Task type: ${taskType}
${pathBlock}${deadBlock}
Return ONLY valid JSON with this exact shape (array may have up to ${String(count)} items):
{"branches":[
  {
    "approach": "short label e.g. 'Direct implementation with X'",
    "thought": "2ÔÇô4 sentence reasoning for this approach",
    "keyAssumptions": ["assumption 1", "assumption 2"],
    "estimatedSteps": 1,
    "riskFactors": ["risk 1", "risk 2"]
  }
]}
estimatedSteps must be an integer from 1 to 5.`

    const userParts = [`Task: ${taskDescription}`, '']
    if (padContext.length > 0) {
      userParts.push(padContext, '')
    }
    userParts.push(`Generate ${String(count)} distinct approaches.`)

    const user = userParts.join('\n')

    let candidates: BranchCandidate[] = []
    try {
      const response = await this.openai.chat.completions.create({
        model: this.model,
        temperature: 0.5,
        response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: user },
        ],
      })

      const text = response.choices[0]?.message?.content?.trim() ?? ''
      candidates = parseBranchCandidates(text, count)
    } catch (err: unknown) {
      console.warn(`${LOG} Generation failed, returning fallback branch`, err)
      return [fallbackCandidate(taskDescription)]
    }

    if (candidates.length === 0) {
      console.warn(`${LOG} Generation failed, returning fallback branch`)
      return [fallbackCandidate(taskDescription)]
    }

    const beforeDedup = candidates.length
    candidates = this._filterDuplicateApproaches(candidates, TOT_DEFAULTS.MIN_NOVELTY)
    const removed = beforeDedup - candidates.length
    if (removed > 0) {
      console.log(`${LOG} Removed ${String(removed)} duplicate branches`)
    }

    if (candidates.length === 0) {
      console.warn(`${LOG} Generation failed, returning fallback branch`)
      return [fallbackCandidate(taskDescription)]
    }

    const depth = parentNode !== null ? parentNode.depth + 1 : 0
    console.log(`${LOG} Generated ${String(candidates.length)} branches for depth ${String(depth)}`)

    return candidates.slice(0, count)
  }

  /**
   * Root-level branch generation (empty path, ephemeral {@link ToTTree} shell for API consistency).
   */
  async generateRootBranches(
    taskDescription: string,
    taskType: string,
    sessionId: string,
    count: number,
  ): Promise<BranchCandidate[]> {
    const tree = createTree(sessionId, taskType, taskDescription)
    return this.generateBranches(taskDescription, taskType, null, tree, sessionId, count)
  }

  /**
   * Drops candidates whose approach+thought text is too similar to an earlier kept candidate (Jaccard on tokens).
   */
  private _filterDuplicateApproaches(
    candidates: BranchCandidate[],
    noveltyThreshold: number,
  ): BranchCandidate[] {
    const cutoff = 1 - noveltyThreshold
    const kept: BranchCandidate[] = []

    for (const c of candidates) {
      let duplicate = false
      for (const k of kept) {
        if (candidateSimilarity(c, k) > cutoff) {
          duplicate = true
          break
        }
      }
      if (!duplicate) {
        kept.push(c)
      }
    }

    return kept
  }
}

/**
 * Tree-of-Thoughts value function: scores {@link ThoughtNode} branches for search.
 *
 * @module reasoning/branchScorer
 */

import OpenAI from 'openai'

import type { Lesson } from './lessonsStore'
import { lessonsStore } from './lessonsStore'
import { getNodePath, type ThoughtNode, type ToTTree } from './totTypes'
import { scratchpadStore } from './scratchpadStore'

const LOG = '[BranchScorer]'

const ALIGN_STOP = new Set([
  'the',
  'and',
  'for',
  'that',
  'this',
  'with',
  'from',
  'have',
  'has',
  'are',
  'was',
  'were',
  'not',
  'but',
  'can',
  'should',
  'must',
  'will',
  'all',
  'any',
  'use',
  'your',
  'into',
  'than',
  'then',
  'also',
  'only',
  'such',
  'each',
  'which',
  'their',
  'when',
  'what',
  'how',
  'does',
  'did',
  'been',
  'being',
  'about',
  'there',
  'here',
  'some',
  'more',
  'very',
  'just',
  'like',
  'make',
  'sure',
  'always',
  'never',
])

/**
 * Inputs needed to score a branch against the live task.
 */
export interface ScoringContext {
  taskDescription: string
  taskType: string
  sessionId: string
  requirements: string[]
  /** RAG or other retrieved snippets. */
  availableContext: string[]
}

/**
 * Per-dimension scores plus weighted aggregate from {@link BranchScorer}.
 */
export interface ScoreBreakdown {
  feasibility: number
  completeness: number
  novelty: number
  lessonAlignment: number
  composite: number
  rationale: string
}

/** Weights for {@link ScoreBreakdown.composite}. Sum is `1`. */
export const SCORE_WEIGHTS = {
  feasibility: 0.35,
  completeness: 0.35,
  novelty: 0.15,
  lessonAlignment: 0.15,
} as const

function clamp01(n: number): number {
  if (Number.isNaN(n)) return 0
  return Math.max(0, Math.min(1, n))
}

function tokenize(text: string): string[] {
  return text
    .toLowerCase()
    .split(/[^a-z0-9]+/)
    .map((w) => w.trim())
    .filter((w) => w.length > 3 && !ALIGN_STOP.has(w))
}

function tokenSet(text: string): Set<string> {
  return new Set(tokenize(text))
}

/** Max Jaccard similarity between this node and any sibling (approach + thought). */
function maxSiblingOverlap(node: ThoughtNode, siblings: ThoughtNode[]): number {
  const a = tokenSet(`${node.approach} ${node.thought}`)
  if (a.size === 0) return 0
  let maxSim = 0
  for (const sib of siblings) {
    if (sib.id === node.id) continue
    const b = tokenSet(`${sib.approach} ${sib.thought}`)
    if (b.size === 0) continue
    let inter = 0
    for (const w of a) {
      if (b.has(w)) inter++
    }
    const union = a.size + b.size - inter
    const j = union === 0 ? 0 : inter / union
    if (j > maxSim) maxSim = j
  }
  return maxSim
}

function computeNovelty(node: ThoughtNode, siblings: ThoughtNode[]): number {
  const maxOv = maxSiblingOverlap(node, siblings)
  return clamp01(1 - maxOv)
}

/**
 * Fraction of salient lesson tokens that appear in the branch text (proxy for ÔÇ£follows lessonÔÇØ).
 */
function lessonMatchesBranch(lesson: Lesson, branchLower: string): boolean {
  const words = tokenize(lesson.lesson)
  if (words.length === 0) return true
  let hits = 0
  for (const w of words) {
    if (branchLower.includes(w)) hits++
  }
  return hits / words.length >= 0.35 || hits >= 2
}

async function computeLessonAlignment(node: ThoughtNode, context: ScoringContext): Promise<number> {
  const lessons = await lessonsStore.getRelevantLessons({
    sessionId: context.sessionId,
    taskType: context.taskType,
    currentOutput: `${node.approach}\n${node.thought}`.slice(0, 500),
  })
  if (lessons.length === 0) return 1
  const branchLower = `${node.approach} ${node.thought}`.toLowerCase()
  let match = 0
  for (const L of lessons) {
    if (lessonMatchesBranch(L, branchLower)) match++
  }
  return clamp01(match / lessons.length)
}

function extractJsonObject(text: string): string {
  const t = text.trim()
  if (!t.startsWith('```')) {
    return t
  }
  const firstNl = t.indexOf('\n')
  const close = firstNl >= 0 ? t.indexOf('```', firstNl + 1) : -1
  if (firstNl >= 0 && close > firstNl) {
    return t.slice(firstNl + 1, close).trim()
  }
  return t
}

function asStringArrayMeta(v: unknown): string[] {
  if (!Array.isArray(v)) return []
  return v.filter((x): x is string => typeof x === 'string' && x.trim().length > 0).map((s) => s.trim())
}

function compositeScore(
  feasibility: number,
  completeness: number,
  novelty: number,
  lessonAlignment: number,
): number {
  return clamp01(
    feasibility * SCORE_WEIGHTS.feasibility +
      completeness * SCORE_WEIGHTS.completeness +
      novelty * SCORE_WEIGHTS.novelty +
      lessonAlignment * SCORE_WEIGHTS.lessonAlignment,
  )
}

/**
 * OpenAI-backed feasibility/completeness plus local novelty and lesson heuristics.
 */
export default class BranchScorer {
  private readonly openai: OpenAI
  private readonly model: string

  /**
   * @param model - Small chat model (default `gpt-4o-mini`) for high call volume.
   */
  constructor(model: string = 'gpt-4o-mini') {
    this.openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY ?? '' })
    this.model = model
  }

  /**
   * Scores one node, mutates {@link ThoughtNode.score}, feasibility fields, and `status`.
   */
  async scoreNode(
    node: ThoughtNode,
    siblings: ThoughtNode[],
    tree: ToTTree,
    context: ScoringContext,
  ): Promise<ScoreBreakdown> {
    const pad = scratchpadStore.getForSession(context.sessionId)
    const approachNorm = node.approach.trim()
    if (pad !== null) {
      for (const d of pad.deadEnds) {
        if (d.approach.trim() === approachNorm) {
          const breakdown: ScoreBreakdown = {
            feasibility: 0,
            completeness: 0,
            novelty: computeNovelty(node, siblings),
            lessonAlignment: await computeLessonAlignment(node, context),
            composite: 0,
            rationale: 'Approach matches a recorded dead end; branch pre-screened.',
          }
          node.score = 0
          node.feasibility = 0
          node.completeness = 0
          node.novelty = breakdown.novelty
          node.status = 'scored'
          console.log(`${LOG} Node pre-screened ÔÇö matches dead end`)
          return breakdown
        }
      }
    }

    const novelty = computeNovelty(node, siblings)
    const lessonAlignment = await computeLessonAlignment(node, context)

    const keyAssumptions = asStringArrayMeta(node.metadata.keyAssumptions)
    const riskFactors = asStringArrayMeta(node.metadata.riskFactors)

    const pathLine = getNodePath(tree, node.id)
      .map((n) => n.approach)
      .join(' ÔåÆ ')

    const contextBlock =
      context.availableContext.length > 0
        ? `\nContext snippets:\n${context.availableContext.map((c) => c.slice(0, 800)).join('\n---\n')}`
        : ''

    const user = `Task: ${context.taskDescription}
Requirements: ${context.requirements.join(', ')}
Path from root: ${pathLine || '(single node)'}${contextBlock}

Approach: ${node.approach}
Reasoning: ${node.thought}

Key assumptions: ${keyAssumptions.length > 0 ? keyAssumptions.join(', ') : '(none listed)'}
Risk factors: ${riskFactors.length > 0 ? riskFactors.join(', ') : '(none listed)'}`

    const system = `You are evaluating a reasoning branch for a task.
Score TWO dimensions only:

feasibility (0.0-1.0): Can this approach realistically succeed?
  1.0 = straightforward, clear path
  0.5 = uncertain, requires assumptions
  0.0 = likely to fail or impossible

completeness (0.0-1.0): Does it fully address ALL requirements?
  1.0 = addresses everything
  0.5 = addresses main goal, misses some requirements
  0.0 = only addresses part of the task

Return ONLY valid JSON:
{"feasibility": 0.0, "completeness": 0.0, "rationale": "brief reason"}`

    let feasibility = 0.5
    let completeness = 0.5
    let rationale = 'LLM scoring failed; using default feasibility/completeness.'

    try {
      const response = await this.openai.chat.completions.create({
        model: this.model,
        temperature: 0.2,
        response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: user },
        ],
      })

      const text = response.choices[0]?.message?.content?.trim() ?? ''
      const raw = extractJsonObject(text)
      const parsed: unknown = JSON.parse(raw)
      if (parsed !== null && typeof parsed === 'object') {
        const o = parsed as Record<string, unknown>
        if (typeof o.feasibility === 'number' && Number.isFinite(o.feasibility)) {
          feasibility = clamp01(o.feasibility)
        }
        if (typeof o.completeness === 'number' && Number.isFinite(o.completeness)) {
          completeness = clamp01(o.completeness)
        }
        if (typeof o.rationale === 'string' && o.rationale.trim().length > 0) {
          rationale = o.rationale.trim()
        }
      }
    } catch (err: unknown) {
      console.warn(`${LOG} LLM scoring failed, using defaults`, err)
    }

    const composite = compositeScore(feasibility, completeness, novelty, lessonAlignment)

    node.score = composite
    node.feasibility = feasibility
    node.completeness = completeness
    node.novelty = novelty
    node.status = 'scored'

    console.log(
      `${LOG} Node ${node.id.slice(0, 8)} scored: ${composite.toFixed(2)} (F:${feasibility.toFixed(2)} C:${completeness.toFixed(2)})`,
    )

    return {
      feasibility,
      completeness,
      novelty,
      lessonAlignment,
      composite,
      rationale,
    }
  }

  /**
   * Scores many nodes concurrently; novelty for each uses same-depth peers in `nodes`.
   */
  async scoreBatch(
    nodes: ThoughtNode[],
    tree: ToTTree,
    context: ScoringContext,
  ): Promise<Map<string, ScoreBreakdown>> {
    const entries = await Promise.all(
      nodes.map(async (node) => {
        const siblings = nodes.filter((n) => n.id !== node.id && n.depth === node.depth)
        const breakdown = await this.scoreNode(node, siblings, tree, context)
        return [node.id, breakdown] as const
      }),
    )
    console.log(`${LOG} Batch scored ${String(nodes.length)} nodes`)
    return new Map(entries)
  }
}

/**
 * System 1 ÔÇö Uncertainty-Aware Memory (UAM) for the Dual-Process AUQ pipeline
 * (arXiv:2601.15703): fast extraction or a single cheap elicitation call.
 * Does not block the main pipeline on failure (neutral fallbacks).
 *
 * @module reasoning/confidenceElicitor
 */

import OpenAI from 'openai'
import { v4 as uuidv4 } from 'uuid'

import type { ConfidenceScore, ConfidenceVector, PreTaskEstimate } from './confidenceTypes'
import {
  CONFIDENCE_THRESHOLDS,
  ELICITATION_INSTRUCTION,
  scoreToAction,
  scoreToLevel,
} from './confidenceTypes'

const LOG = '[ConfidenceElicitor]'

/** Fixed model for {@link ConfidenceElicitor.estimatePreTask} (fast / low cost). */
const PRE_TASK_MODEL = 'gpt-4o-mini'

/** As specified for simple flat JSON objects (fallback when brace-balanced parse fails). */
const CONFIDENCE_FLAT_REGEX = /\{[^{}]*"confidence"\s*:\s*([\d.]+)[^{}]*\}/g

function clamp01(n: number): number {
  if (!Number.isFinite(n)) return 0
  return Math.min(1, Math.max(0, n))
}

function asStringArray(v: unknown): string[] {
  if (!Array.isArray(v)) return []
  return v.filter((x): x is string => typeof x === 'string')
}

/**
 * Extracts a `{ ... }` substring starting at `start` with balanced braces,
 * respecting strings and escapes.
 */
function sliceBalancedJson(s: string, start: number): string | null {
  if (s[start] !== '{') return null
  let depth = 0
  let inString = false
  let escape = false
  for (let i = start; i < s.length; i++) {
    const c = s[i]!
    if (escape) {
      escape = false
      continue
    }
    if (c === '\\' && inString) {
      escape = true
      continue
    }
    if (c === '"') {
      inString = !inString
      continue
    }
    if (inString) continue
    if (c === '{') depth++
    else if (c === '}') {
      depth--
      if (depth === 0) return s.slice(start, i + 1)
    }
  }
  return null
}

/**
 * Finds the last JSON object in `text` that contains `"key":` and parses it.
 */
function parseLastJsonObjectWithKey(
  text: string,
  key: 'confidence' | 'scalar',
): Record<string, unknown> | null {
  const needle = `"${key}"`
  let searchEnd = text.length
  for (;;) {
    const keyIdx = text.lastIndexOf(needle, searchEnd)
    if (keyIdx < 0) return null
    const open = text.lastIndexOf('{', keyIdx)
    if (open < 0) {
      searchEnd = keyIdx - 1
      continue
    }
    const slice = sliceBalancedJson(text, open)
    if (slice === null) {
      searchEnd = keyIdx - 1
      continue
    }
    try {
      const obj = JSON.parse(slice) as unknown
      if (obj !== null && typeof obj === 'object' && !Array.isArray(obj) && key in obj) {
        return obj as Record<string, unknown>
      }
    } catch {
      // try earlier
    }
    searchEnd = keyIdx - 1
  }
}

function parseVote(text: string): 'YES' | 'PARTIAL' | 'NO' {
  const u = text.trim().toUpperCase()
  if (u.startsWith('YES')) return 'YES'
  if (u.startsWith('PARTIAL')) return 'PARTIAL'
  if (u.startsWith('NO')) return 'NO'
  if (u.includes('PARTIAL')) return 'PARTIAL'
  if (u.includes('NO')) return 'NO'
  if (u.includes('YES')) return 'YES'
  return 'PARTIAL'
}

/**
 * System 1 UAM: extract verbalized confidence from prior output or elicit with one cheap call.
 */
export default class ConfidenceElicitor {
  private readonly openai: OpenAI
  private readonly model: string

  /**
   * @param model - Fast chat model for elicitation / consistency (default `gpt-4o-mini`).
   */
  constructor(model: string = 'gpt-4o-mini') {
    this.openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY ?? '' })
    this.model = model
  }

  /**
   * Attempts to read a confidence object appended to model output (zero LLM cost).
   * Prefers `"confidence"`; falls back to `"scalar"` for {@link ELICITATION_INSTRUCTION} payloads.
