  extractFromOutput(
    output: string,
    sessionId: string,
    taskType: string,
    turnIndex: number,
  ): ConfidenceScore | null {
    let obj =
      parseLastJsonObjectWithKey(output, 'confidence') ??
      parseLastJsonObjectWithKey(output, 'scalar')

    let scalar: number | undefined
    let explanation = ''
    let uncertaintyFactors: string[] = []
    let knowledgeGaps: string[] = []

    if (obj !== null) {
      const raw =
        typeof obj.confidence === 'number'
          ? obj.confidence
          : typeof obj.scalar === 'number'
            ? obj.scalar
            : Number(obj.confidence ?? obj.scalar)
      if (Number.isFinite(raw)) scalar = clamp01(raw)
      explanation = typeof obj.explanation === 'string' ? obj.explanation : ''
      uncertaintyFactors = asStringArray(obj.uncertaintyFactors)
      knowledgeGaps = asStringArray(obj.knowledgeGaps)
    }

    if (scalar === undefined) {
      const matches = [...output.matchAll(CONFIDENCE_FLAT_REGEX)]
      if (matches.length === 0) {
        console.log(`${LOG} No confidence JSON found in output`)
        return null
      }
      const m = matches[matches.length - 1]!
      try {
        obj = JSON.parse(m[0]!) as Record<string, unknown>
        const raw = typeof obj.confidence === 'number' ? obj.confidence : Number(m[1])
        if (Number.isFinite(raw)) scalar = clamp01(raw)
        explanation = typeof obj.explanation === 'string' ? obj.explanation : ''
        uncertaintyFactors = asStringArray(obj.uncertaintyFactors)
        knowledgeGaps = asStringArray(obj.knowledgeGaps)
      } catch {
        const raw = Number(m[1])
        if (Number.isFinite(raw)) scalar = clamp01(raw)
      }
    }

    if (scalar === undefined) {
      console.log(`${LOG} No confidence JSON found in output`)
      return null
    }

    const level = scoreToLevel(scalar)
    const recommendedAction = scoreToAction(scalar, 0.5, 0)

    console.log(`${LOG} Extracted verbalized confidence: ${String(scalar)}`)

    return {
      id: uuidv4(),
      sessionId,
      turnIndex,
      scalar,
      level,
      source: 'verbalized',
      explanation: explanation.length > 0 ? explanation : 'Parsed from appended confidence JSON',
      uncertaintyFactors,
      knowledgeGaps,
      recommendedAction,
      taskType,
      timestamp: new Date().toISOString(),
    }
  }

  /**
   * UAM path: reuse embedded JSON if present; otherwise one short completion for verbalized confidence.
   */
  async elicit(
    output: string,
    taskDescription: string,
    taskType: string,
    sessionId: string,
    turnIndex: number,
  ): Promise<ConfidenceScore> {
    const extracted = this.extractFromOutput(output, sessionId, taskType, turnIndex)
    if (extracted !== null) return extracted

    const userMessage = `Rate your confidence in this output (0.0ÔÇô1.0).
Be calibrated: 1.0 = certain, 0.5 = genuinely unsure.

Task: ${taskDescription.slice(0, 200)}
Task type: ${taskType}
Output snippet: ${output.slice(0, 600)}

Return ONLY JSON:
{"confidence": 0.0-1.0, "explanation": "why", 
 "uncertaintyFactors": ["factor"], "knowledgeGaps": ["gap"]}`

    try {
      const completion = await this.openai.chat.completions.create({
        model: this.model,
        messages: [{ role: 'user', content: userMessage }],
        temperature: 0.2,
        max_tokens: 400,
        response_format: { type: 'json_object' },
        stream: false,
      })

      const text = completion.choices[0]?.message?.content?.trim() ?? ''
      const parsed = JSON.parse(text) as Record<string, unknown>
      const raw = typeof parsed.confidence === 'number' ? parsed.confidence : Number(parsed.confidence)
      const scalar = clamp01(raw)
      const explanation = typeof parsed.explanation === 'string' ? parsed.explanation : ''
      const uncertaintyFactors = asStringArray(parsed.uncertaintyFactors)
      const knowledgeGaps = asStringArray(parsed.knowledgeGaps)
      const level = scoreToLevel(scalar)
      const recommendedAction = scoreToAction(scalar, 0.5, 0)

      return {
        id: uuidv4(),
        sessionId,
        turnIndex,
        scalar,
        level,
        source: 'verbalized',
        explanation,
        uncertaintyFactors,
        knowledgeGaps,
        recommendedAction,
        taskType,
        timestamp: new Date().toISOString(),
      }
    } catch {
      console.warn(`${LOG} Elicitation failed, returning neutral`)
      const scalar = 0.7
      return {
        id: uuidv4(),
        sessionId,
        turnIndex,
        scalar,
        level: scoreToLevel(scalar),
        source: 'verbalized',
        explanation: 'Confidence elicitation failed ÔÇö neutral default',
        uncertaintyFactors: [],
        knowledgeGaps: [],
        recommendedAction: 'proceed_with_flag',
        taskType,
        timestamp: new Date().toISOString(),
      }
    }
  }

  /**
   * Proactive pre-task confidence (CoCA / confidence-first): estimates likelihood of a high-quality
   * response **before** spending full task budget, using session context and past uncertainty signals.
   *
   * @param taskDescription - Natural-language task the worker is about to run.
   * @param taskType - Intent route (e.g. `code_instruction`).
   * @param sessionId - Session id for logs / downstream correlation.
   * @param context - Optional scratchpad summary, recent uncertainty factors, and lesson snippets.
   */
  async estimatePreTask(
    taskDescription: string,
    taskType: string,
    sessionId: string,
    context?: {
      scratchpadSummary?: string
      recentUncertaintyFactors?: string[]
      relevantLessons?: string[]
    },
  ): Promise<PreTaskEstimate> {
    const contextBlock = [
      context?.scratchpadSummary
        ? `Session context: ${context.scratchpadSummary}`
        : '',
      context?.recentUncertaintyFactors?.length
        ? `Recent uncertainty: ${context.recentUncertaintyFactors.join(', ')}`
        : '',
      context?.relevantLessons?.length
        ? `Relevant lessons: ${context.relevantLessons.slice(0, 3).join('; ')}`
        : '',
    ]
      .filter(Boolean)
      .join('\n')

    const system = `You are a pre-task confidence estimator.
Before any task is attempted, estimate the probability of producing a high-quality response.

Be calibrated and honest. Consider:
- How well-defined is the task?
- Are there missing details that would significantly change the approach?
- Does the session context reveal relevant uncertainties?
- Are there lessons from past failures that apply here?

Return ONLY valid JSON ÔÇö no other text:
{
  "confidence": 0.0-1.0,
  "explanation": "why this confidence level",
  "missingInfo": ["info that would help"],
  "clarifyingQuestions": ["question if confidence < 0.70"],
  "suggestedApproach": "brief approach hint if confidence >= 0.70",
  "shouldProceed": true|false
}

shouldProceed = false only when missingInfo is so critical that proceeding would likely produce wrong output.`

    const user = `Task: ${taskDescription}
Task type: ${taskType}
${contextBlock.length > 0 ? `${contextBlock}\n` : ''}
Estimate confidence BEFORE attempting this task.`

    const elicitedAt = new Date().toISOString()

    const fallback = (): PreTaskEstimate => ({
      confidence: 0.65,
      explanation: 'Pre-task estimation failed ÔÇö neutral default',
      missingInfo: [],
      clarifyingQuestions: [],
      suggestedApproach: '',
      shouldProceed: true,
      elicitedAt,
      taskType,
    })

    try {
      const completion = await this.openai.chat.completions.create({
        model: PRE_TASK_MODEL,
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: user },
        ],
        temperature: 0.2,
        max_tokens: 500,
        response_format: { type: 'json_object' },
        stream: false,
      })

      const text = completion.choices[0]?.message?.content?.trim() ?? ''
      const parsed = JSON.parse(text) as unknown
      if (parsed === null || typeof parsed !== 'object' || Array.isArray(parsed)) {
        console.warn(`${LOG} Pre-task estimate: invalid JSON shape (session ${sessionId})`)
        return fallback()
      }
      const o = parsed as Record<string, unknown>
      const raw =
        typeof o.confidence === 'number' ? o.confidence : Number(o.confidence)
      const confidence = clamp01(raw)
      const explanation = typeof o.explanation === 'string' ? o.explanation : ''
      const missingInfo = asStringArray(o.missingInfo)
      const clarifyingQuestions = asStringArray(o.clarifyingQuestions)
      const suggestedApproach =
        typeof o.suggestedApproach === 'string' ? o.suggestedApproach : ''
      const shouldProceed = o.shouldProceed !== false

      console.log(
        `${LOG} Pre-task estimate session=${sessionId} type=${taskType} conf=${String(confidence)} proceed=${String(shouldProceed)}`,
      )

      return {
        confidence,
        explanation,
        missingInfo,
        clarifyingQuestions,
        suggestedApproach,
        shouldProceed,
        elicitedAt,
        taskType,
      }
    } catch (err: unknown) {
      console.warn(`${LOG} Pre-task estimation failed (session ${sessionId})`, err)
      return fallback()
    }
  }

  /**
   * Fuses heterogeneous signals into a {@link ConfidenceVector} (overall is a fixed weighted sum).
   * `verbalized` is accepted for forward compatibility; Phase 6 does not yet fold it into the vector.
   */
  computeVector(scores: {
    critique?: number
    observation?: boolean
    verbalized?: number
    ragHits?: number
  }): ConfidenceVector {
    void scores.verbalized
    const factual = scores.ragHits !== undefined ? clamp01(scores.ragHits) : 0.7
    let reasoning = 0.7
    if (scores.observation === true) reasoning = 0.85
    else if (scores.observation === false) reasoning = 0.45
    const completeness = scores.critique !== undefined ? clamp01(scores.critique) : 0.7
    const safety = 1.0
    const overall =
      factual * 0.25 + reasoning * 0.3 + completeness * 0.3 + safety * 0.15

    return {
      overall: clamp01(overall),
      factual,
      reasoning,
      completeness,
      safety,
    }
  }

  /**
   * Runs `n` independent stochastic checks (temperature 0.8). Expensive ÔÇö gate at call site.
   */
  async checkConsistency(
    taskDescription: string,
    output: string,
    taskType: string,
    n: number = CONFIDENCE_THRESHOLDS.CONSISTENCY_SAMPLES,
  ): Promise<{ consistent: boolean; agreementScore: number; variance: string }> {
    void taskType
    const prompt = `In one sentence, is this output correct and complete for the task?
Task: ${taskDescription.slice(0, 200)}
Output: ${output.slice(0, 500)}
Answer YES, PARTIAL, or NO with brief reason.`

    const votes: Array<'YES' | 'PARTIAL' | 'NO'> = []
    const count = Math.max(1, Math.floor(n))

    for (let i = 0; i < count; i++) {
      try {
        const completion = await this.openai.chat.completions.create({
          model: this.model,
          messages: [{ role: 'user', content: prompt }],
          temperature: 0.8,
          max_tokens: 80,
          stream: false,
        })
        const text = completion.choices[0]?.message?.content ?? ''
        votes.push(parseVote(text))
      } catch {
        votes.push('PARTIAL')
      }
    }

    let yes = 0
    let partial = 0
    let no = 0
    for (const v of votes) {
      if (v === 'YES') yes++
      else if (v === 'NO') no++
      else partial++
    }
    const maxVote = Math.max(yes, partial, no)
    const agreementScore = maxVote / count
    const variance = `YES:${String(yes)} PARTIAL:${String(partial)} NO:${String(no)}`
    const consistent = agreementScore >= 0.67

    return { consistent, agreementScore, variance }
  }
}

export type { PreTaskEstimate } from './confidenceTypes'

/**
 * Per-session LLM spend tracking, budget checks, and warning telemetry.
 *
 * @module reasoning/costTracker
 */

import { v4 as uuidv4 } from 'uuid'

import { telemetry } from '@/lib/observability/telemetryCollector'

import type { ModelTier } from './modelRegistry'
import { MODEL_REGISTRY, estimateCost } from './modelRegistry'

const LOG = '[CostTracker]'

const TURNS_PER_DAY_ESTIMATE = 50
const DAYS_PER_MONTH_ESTIMATE = 30

/** One billed API call attributed to a session. */
export interface CostRecord {
  id: string
  sessionId: string
  tier: ModelTier
  model: string
  actualInputTokens: number
  actualOutputTokens: number
  actualCostUSD: number
  taskType: string
  timestamp: string
}

/** Aggregated spend for a single session. */
export interface SessionCostSummary {
  sessionId: string
  totalCostUSD: number
  byTier: Record<
    ModelTier,
    {
      calls: number
      costUSD: number
      inputTokens: number
      outputTokens: number
    }
  >
  premiumCallCount: number
  reasoningCallCount: number
  /** Rough monthly projection: `(totalCost / calls) * 50 * 30` using this sessionÔÇÖs call count. */
  estimatedMonthlyCostUSD: number
}

/** Default soft caps for logging / routing (not hard enforcement here). */
export const DEFAULT_BUDGET = {
  MAX_SESSION_COST_USD: 2.0,
  MAX_PREMIUM_COST_USD: 1.0,
  WARN_THRESHOLD_USD: 1.5,
} as const

function emptyTierBucket(): SessionCostSummary['byTier'][ModelTier] {
  return { calls: 0, costUSD: 0, inputTokens: 0, outputTokens: 0 }
}

function emptyByTier(): SessionCostSummary['byTier'] {
  return {
    nano: emptyTierBucket(),
    standard: emptyTierBucket(),
    reasoning: emptyTierBucket(),
    premium: emptyTierBucket(),
  }
}

function emptyByTierSystem(): Record<ModelTier, { calls: number; costUSD: number }> {
  return {
    nano: { calls: 0, costUSD: 0 },
    standard: { calls: 0, costUSD: 0 },
    reasoning: { calls: 0, costUSD: 0 },
    premium: { calls: 0, costUSD: 0 },
  }
}

/**
 * In-memory cost ledger keyed by session.
 */
export default class CostTracker {
  private readonly records = new Map<string, CostRecord[]>()
  /** Sessions that have already emitted {@link TelemetryEventType} `cost_warning` after crossing the warn threshold. */
  private readonly warnedSessions = new Set<string>()

  /**
   * Records actual token usage, updates aggregates, and may emit a one-time cost warning per session.
   */
  record(
    sessionId: string,
    tier: ModelTier,
    model: string,
    actualInputTokens: number,
    actualOutputTokens: number,
    taskType: string,
  ): CostRecord {
    void MODEL_REGISTRY[tier]
    const actualCostUSD = estimateCost(tier, actualInputTokens, actualOutputTokens)
    const beforeTotal = this.getSessionTotalUSD(sessionId)

    const row: CostRecord = {
      id: uuidv4(),
      sessionId,
      tier,
      model,
      actualInputTokens,
      actualOutputTokens,
      actualCostUSD,
      taskType,
      timestamp: new Date().toISOString(),
    }

    const list = this.records.get(sessionId) ?? []
    list.push(row)
    this.records.set(sessionId, list)

    const summary = this.getSessionSummary(sessionId)

    if (
      summary.totalCostUSD >= DEFAULT_BUDGET.WARN_THRESHOLD_USD &&
      beforeTotal < DEFAULT_BUDGET.WARN_THRESHOLD_USD &&
      !this.warnedSessions.has(sessionId)
    ) {
      this.warnedSessions.add(sessionId)
      telemetry.record('cost_warning', sessionId, {
        totalCostUSD: summary.totalCostUSD,
        threshold: DEFAULT_BUDGET.WARN_THRESHOLD_USD,
        tier,
      })
      console.warn(`${LOG} ÔÜá Session ${sessionId} cost: ${summary.totalCostUSD.toFixed(4)}`)
    }

    return row
  }

  private getSessionTotalUSD(sessionId: string): number {
    const rows = this.records.get(sessionId) ?? []
    return rows.reduce((s, r) => s + r.actualCostUSD, 0)
  }

  /** Full rollup for one session (empty tiers zeroed). */
  getSessionSummary(sessionId: string): SessionCostSummary {
    const rows = this.records.get(sessionId) ?? []
    const byTier = emptyByTier()
    let totalCostUSD = 0
    let premiumCallCount = 0
    let reasoningCallCount = 0

    for (const r of rows) {
      totalCostUSD += r.actualCostUSD
      const b = byTier[r.tier]
      b.calls++
      b.costUSD += r.actualCostUSD
      b.inputTokens += r.actualInputTokens
      b.outputTokens += r.actualOutputTokens
      if (r.tier === 'premium') premiumCallCount++
      if (r.tier === 'reasoning') reasoningCallCount++
    }

    const n = rows.length
    const estimatedMonthlyCostUSD =
      n > 0 ? (totalCostUSD / n) * TURNS_PER_DAY_ESTIMATE * DAYS_PER_MONTH_ESTIMATE : 0

    return {
      sessionId,
      totalCostUSD,
      byTier,
      premiumCallCount,
      reasoningCallCount,
      estimatedMonthlyCostUSD,
    }
  }

  /** Number of `premium` tier records in the session. */
  getPremiumCallCount(sessionId: string): number {
    return this.getSessionSummary(sessionId).premiumCallCount
  }

  /** Number of `reasoning` tier records in the session. */
  getReasoningCallCount(sessionId: string): number {
    return this.getSessionSummary(sessionId).reasoningCallCount
  }

  /** True when total session spend meets or exceeds {@link DEFAULT_BUDGET.MAX_SESSION_COST_USD}. */
  isOverBudget(sessionId: string): boolean {
    return this.getSessionSummary(sessionId).totalCostUSD >= DEFAULT_BUDGET.MAX_SESSION_COST_USD
  }

  /** True when premium-tier spend alone meets or exceeds {@link DEFAULT_BUDGET.MAX_PREMIUM_COST_USD}. */
  isPremiumCapReached(sessionId: string): boolean {
    const premiumUSD = this.getSessionSummary(sessionId).byTier.premium.costUSD
    return premiumUSD >= DEFAULT_BUDGET.MAX_PREMIUM_COST_USD
  }

  /** Cross-session totals for dashboards. */
  getSystemCostStats(): {
    totalSessions: number
    totalCostUSD: number
    byTier: Record<ModelTier, { calls: number; costUSD: number }>
    avgCostPerSession: number
    estimatedMonthlyCostUSD: number
  } {
    const byTier = emptyByTierSystem()
    let totalCostUSD = 0
    let totalCalls = 0

    for (const [, rows] of this.records) {
      for (const r of rows) {
        totalCostUSD += r.actualCostUSD
        totalCalls++
        byTier[r.tier].calls++
        byTier[r.tier].costUSD += r.actualCostUSD
      }
    }

    const totalSessions = this.records.size
    const avgCostPerSession = totalSessions > 0 ? totalCostUSD / totalSessions : 0
    const estimatedMonthlyCostUSD =
      totalCalls > 0
        ? (totalCostUSD / totalCalls) * TURNS_PER_DAY_ESTIMATE * DAYS_PER_MONTH_ESTIMATE
        : 0

    return {
      totalSessions,
      totalCostUSD,
      byTier,
      avgCostPerSession,
      estimatedMonthlyCostUSD,
    }
  }

  /** Drops all {@link CostRecord}s and warning state for a session. */
  clearSession(sessionId: string): void {
    this.records.delete(sessionId)
    this.warnedSessions.delete(sessionId)
  }
}

/** Process-wide {@link CostTracker} singleton. */
export const costTracker = new CostTracker()

/**
 * Session-scoped Reflexion memory: persists verbal lessons from the Critic
 * and related signals so later turns can inject them into prompts.
 * Cross-session durability via {@link lessonsAdapter}.
 *
 * @module reasoning/lessonsStore
 */

import { v4 as uuidv4 } from 'uuid'

import {
  lessonsAdapter,
  type PersistedLesson,
} from '@/lib/persistence/lessonsPersistenceAdapter'

import type { Critique, CritiqueIssue } from './criticAgent'

const LOG = '[LessonsStore]'

const SEVERITY_ORDER: Record<Lesson['severity'], number> = {
  critical: 3,
  major: 2,
  minor: 1,
}

const STOP_WORDS = new Set([
  'the',
  'and',
  'for',
  'that',
  'this',
  'with',
  'from',
  'have',
  'has',
  'are',
  'was',
  'were',
  'not',
  'but',
  'can',
  'should',
  'must',
  'will',
  'all',
  'any',
  'use',
  'using',
  'when',
  'what',
  'your',
  'into',
  'than',
  'then',
  'also',
  'only',
  'such',
  'each',
  'which',
  'their',
])

/** Stopwords for {@link LessonsStore.extractTags} (keyword extraction). */
const EXTRACT_TAG_STOPWORDS = new Set([
  'that',
  'this',
  'with',
  'from',
  'have',
  'when',
  'will',
  'been',
  'were',
  'they',
  'them',
  'then',
  'than',
  'what',
  'your',
  'into',
  'also',
  'more',
])

/** Provenance of a stored lesson. */
export type LessonSource = 'critique' | 'dead_end' | 'assumption_violation' | 'user_correction'

/**
 * One generalizable insight tied to a session and optional task route.
 */
export interface Lesson {
  id: string
  sessionId: string
  /** Intent route that produced this lesson, or `all` when route-agnostic. */
  taskType: string
  /** Generalizable insight text. */
  lesson: string
  source: LessonSource
  severity: 'critical' | 'major' | 'minor'
  /** Number of times injected or applied in downstream logic. */
  appliedCount: number
  /** Whether applying the lesson correlated with a better outcome. */
  confirmedEffective: boolean
  createdAt: string
  lastAppliedAt?: string
}

/**
 * Parameters for selecting lessons to inject into a prompt.
 */
export interface LessonContext {
  sessionId: string
  taskType: string
  /** When set, narrows lessons via keyword / heuristic overlap with output. */
  currentOutput?: string
}

function nowIso(): string {
  return new Date().toISOString()
}

function escapeXml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
}

function mapPersistedSourceToLessonSource(s: PersistedLesson['source']): LessonSource {
  if (s === 'uar') {
    return 'user_correction'
  }
  if (s === 'manual') {
    return 'user_correction'
  }
  return 'critique'
}

/**
 * Hydrate an in-memory {@link Lesson} from disk row (severity defaults to `minor` ÔÇö not stored).
 */
function persistedToLesson(p: PersistedLesson): Lesson {
  return {
    id: p.id,
    sessionId: p.sessionId,
    taskType: p.taskType,
    lesson: p.content,
    source: mapPersistedSourceToLessonSource(p.source),
    severity: 'minor',
    appliedCount: p.appliedCount,
    confirmedEffective: p.successRate >= 0.5,
    createdAt: p.createdAt,
    lastAppliedAt: p.lastAppliedAt ?? undefined,
  }
}

function baseLesson(
  sessionId: string,
  taskType: string,
  lessonText: string,
  source: LessonSource,
  severity: Lesson['severity'],
): Lesson {
  return {
    id: uuidv4(),
    sessionId,
    taskType,
    lesson: lessonText.trim(),
    source,
    severity,
    appliedCount: 0,
    confirmedEffective: false,
    createdAt: nowIso(),
  }
}

function isMajorWithClearPattern(issue: CritiqueIssue): boolean {
  if (issue.severity !== 'major') return false
  if (issue.suggestion.trim().length >= 30) return true
  return issue.category === 'correctness' || issue.category === 'completeness' || issue.category === 'safety'
}

/**
 * Heuristic overlap between lesson text and current output (plus error-handling example).
 */
function lessonRelevantToOutput(lesson: Lesson, output: string): boolean {
  const l = lesson.lesson.toLowerCase()
  const o = output.toLowerCase()

  if (/\b(error handling|exception handling)\b/i.test(l) || /try\s*/i.test(l) || /\bcatch\b/i.test(l)) {
    if (/\btry\s*\{/.test(o) || /\bcatch\s*\(/.test(o)) {
      return true
    }
  }

  const words = l
    .split(/[^a-z0-9_]+/)
    .map((w) => w.trim())
    .filter((w) => w.length > 3 && !STOP_WORDS.has(w))

  if (words.length === 0) {
    return true
  }

  for (const w of words) {
    if (o.includes(w)) return true
  }
  return false
}

function sortLessons(a: Lesson, b: Lesson): number {
  const sev = SEVERITY_ORDER[b.severity] - SEVERITY_ORDER[a.severity]
  if (sev !== 0) return sev
  return a.appliedCount - b.appliedCount
}

/**
 * LessonsStore ÔÇö Cross-Session Reasoning Memory
 *
 * Stores distilled lessons from Reflexion failures and UAR resolutions.
 * Persists to disk via {@link lessonsAdapter} (`lessonsPersistenceAdapter`: JSON in dev, SQLite in prod).
 * Loaded lazily on first access ÔÇö does not block startup (constructor pre-warm is non-blocking).
 *
 * Lesson lifecycle:
 * 1. Reflexion critique produces lessons ÔåÆ {@link ReflexionController} calls {@link LessonsStore.recordFromCritique}
 * 2. UAR resolves uncertainty ÔåÆ {@link UncertaintyResolver} calls {@link LessonsStore.recordManual}
 * 3. Lesson tagged, persisted (fire-and-forget), and indexed by `taskType` for retrieval
 * 4. Next session: {@link LessonsStore.loadFromPersistence} merges rows into memory (via {@link LessonsStore.ensureLoaded})
 * 5. {@link BranchScorer} uses {@link LessonsStore.getRelevantLessons} for lesson alignment in ToT
 * 6. {@link ReflexionController} injects lessons into enriched brief on retry
 * 7. When a lesson is applied: {@link LessonsStore.recordApplied} updates rolling `successRate` in persistence
 * 8. Lessons with successRate &lt; 0.3 after 5+ applications are candidates
 *    for pruning (not yet implemented ÔÇö future enhancement)
 *
 * Contrast with {@link ScratchpadStore} / scratchpad `deadEnds`:
 * - Dead ends: raw, session-scoped, approach-specific
 * - Lessons: distilled, cross-session, generalised
 *
 * **Loading**
 *
 * Pre-warmed at singleton construction time (non-blocking).
 * All public methods await {@link LessonsStore.ensureLoaded} / {@link LessonsStore._ensureLoaded}
 * before use, so concurrent first callers share one load and never double-merge.
 */
export default class LessonsStore {
  /** sessionId ÔåÆ ordered list of lessons (append-only per record call). */
  private readonly lessons: Map<string, Lesson[]> = new Map()

  /**
   * Rolling success rate from persistence / {@link recordApplied} (not on {@link Lesson} interface).
   */
  private readonly successRateByLessonId = new Map<string, number>()

  /** True after a successful full merge from persistence (idempotent guard for {@link loadFromPersistence}). */
  private diskMerged = false

  /**
   * In-flight load; cleared in `finally` so a failed load releases the lock and the next
   * public method call can retry. Prevents parallel duplicate loads while allowing retries after errors.
   */
  private _loadPromise: Promise<void> | null = null

  constructor() {
    // PRE-WARM: Schedule persistence load at singleton construction (import time).
    // void = non-blocking; correctness still guaranteed via _ensureLoaded() on every entrypoint.
    void this.ensureLoaded()
  }

  /**
   * Public alias for {@link LessonsStore._ensureLoaded} (tests / external pre-warm).
   */
  async ensureLoaded(): Promise<void> {
    await this._ensureLoaded()
  }

  /**
   * Single-flight load: concurrent awaiters share one {@link loadFromPersistence} call until it settles.
   */
  private async _ensureLoaded(): Promise<void> {
    if (this.diskMerged) return
    if (this._loadPromise === null) {
      this._loadPromise = this.loadFromPersistence()
        .catch((err: unknown) => {
          console.error(`${LOG} Load failed:`, err)
        })
        .finally(() => {
          this._loadPromise = null
        })
    }
    await this._loadPromise
  }

  /**
   * Merge {@link lessonsAdapter} rows into memory (once per process); skips duplicate ids per bucket.
   */
  async loadFromPersistence(): Promise<void> {
    if (this.diskMerged) {
      return
    }
    const rows = await lessonsAdapter.getAll()
    for (const p of rows) {
      const lesson = persistedToLesson(p)
      const bucket = this.getBucket(lesson.sessionId)
      if (bucket.some((l) => l.id === lesson.id)) {
        continue
      }
      bucket.push(lesson)
      this.successRateByLessonId.set(lesson.id, p.successRate)
    }
    this.diskMerged = true
    console.log(`${LOG} Loaded ${String(rows.length)} lessons from persistence`)
  }

  private inferPersistedSource(lesson: Lesson): PersistedLesson['source'] {
    if (lesson.source === 'user_correction') {
      return 'uar'
    }
    return 'reflexion'
  }

  /**
   * Simple keyword extraction for persisted tags (length ÔëÑ 4, stopword-filtered).
   */
  private extractTags(content: string): string[] {
    const lower = content.toLowerCase()
    const tokens = lower
      .split(/[^a-z0-9_]+/)
      .map((w) => w.trim())
      .filter((w) => w.length >= 4 && !EXTRACT_TAG_STOPWORDS.has(w))
    const seen = new Set<string>()
    const out: string[] = []
    for (const t of tokens) {
      if (seen.has(t)) continue
      seen.add(t)
      out.push(t)
      if (out.length >= 10) break
    }
    return out
  }

  /**
   * Write a new lesson snapshot to disk (appliedCount / successRate start at 0 per spec).
   */
  async persistLesson(lesson: Lesson): Promise<void> {
    const persisted: PersistedLesson = {
      id: lesson.id,
      content: lesson.lesson,
      taskType: lesson.taskType,
      sessionId: lesson.sessionId,
      appliedCount: 0,
      successRate: 0,
      createdAt: lesson.createdAt,
      lastAppliedAt: lesson.lastAppliedAt ?? null,
      tags: this.extractTags(lesson.lesson),
      source: this.inferPersistedSource(lesson),
    }
    await lessonsAdapter.save(persisted)
    this.successRateByLessonId.set(lesson.id, 0)
    console.log(`${LOG} Persisted lesson ${lesson.id}`)
  }

  private getBucket(sessionId: string): Lesson[] {
    let bucket = this.lessons.get(sessionId)
    if (bucket === undefined) {
      bucket = []
      this.lessons.set(sessionId, bucket)
    }
    return bucket
  }

  private findLesson(sessionId: string, lessonId: string): Lesson | undefined {
    const bucket = this.lessons.get(sessionId)
    if (bucket === undefined) return undefined
    return bucket.find((x) => x.id === lessonId)
  }

  private findLessonByIdAcrossSessions(lessonId: string): Lesson | undefined {
    for (const bucket of this.lessons.values()) {
      const hit = bucket.find((l) => l.id === lessonId)
      if (hit !== undefined) {
        return hit
      }
    }
    return undefined
  }

  /**
   * Records lessons distilled from a Reflexion critique ({@link Critique.lessonsForFuture}
   * and high-signal issue suggestions).
   *
   * Persists non-blocking (fire-and-forget via {@link LessonsStore.persistLesson}).
   *
   * Called by: {@link ReflexionController.reflect} after each full Critic pass (whether the
   * critique passed or failed).
   */
  async recordFromCritique(sessionId: string, critique: Critique): Promise<Lesson[]> {
    await this.ensureLoaded()
    const bucket = this.getBucket(sessionId)
    const created: Lesson[] = []
    const taskType = critique.taskType

    for (const text of critique.lessonsForFuture) {
      const t = text.trim()
      if (t.length === 0) continue
      const row = baseLesson(sessionId, taskType, t, 'critique', 'minor')
      bucket.push(row)
      created.push(row)
    }

    for (const issue of critique.issues) {
      if (issue.severity === 'critical') {
        const s = issue.suggestion.trim()
        if (s.length === 0) continue
        const row = baseLesson(sessionId, taskType, s, 'critique', 'critical')
        bucket.push(row)
        created.push(row)
      } else if (isMajorWithClearPattern(issue)) {
        const s = issue.suggestion.trim()
        if (s.length === 0) continue
        const row = baseLesson(sessionId, taskType, s, 'critique', 'major')
        bucket.push(row)
        created.push(row)
      }
    }

    console.log(`${LOG} Recorded ${String(created.length)} lessons from critique (session: ${sessionId})`)

    for (const row of created) {
      this.persistLesson(row).catch((err: unknown) => {
        console.error(`${LOG} Persist failed:`, err)
      })
    }

    return created
  }

  /**
   * Records a manually specified or UAR-derived lesson outside the Reflexion critique path.
   *
   * Persists non-blocking (fire-and-forget via {@link LessonsStore.persistLesson}).
   *
   * Called by: {@link UncertaintyResolver} (UAR lesson extraction) and any manual lesson injection.
   */
  async recordManual(
    sessionId: string,
    lesson: string,
    taskType: string,
    severity: Lesson['severity'],
    source: Lesson['source'],
  ): Promise<Lesson> {
    await this.ensureLoaded()
    const row = baseLesson(sessionId, taskType, lesson.trim(), source, severity)
    this.getBucket(sessionId).push(row)
    this.persistLesson(row).catch((err: unknown) => {
      console.error(`${LOG} Persist failed:`, err)
    })
    return row
  }

  /**
   * Returns up to five lessons for the session, prioritized by severity and reuse.
   */
  async getRelevantLessons(context: LessonContext): Promise<Lesson[]> {
    await this.ensureLoaded()
    const bucket = this.lessons.get(context.sessionId)
    if (bucket === undefined || bucket.length === 0) {
      return []
    }

    let candidates = bucket.filter(
      (l) => l.taskType === context.taskType || l.taskType === 'all',
    )

    candidates = [...candidates].sort(sortLessons)

    const outputTrim = context.currentOutput?.trim() ?? ''
    if (outputTrim.length > 0) {
      candidates = candidates.filter((l) => lessonRelevantToOutput(l, outputTrim))
    }

    return candidates.slice(0, 5)
  }

  /**
   * Serializes lessons into an XML fragment for Worker / thought prompts.
   */
  formatForPrompt(lessons: Lesson[]): string {
    if (lessons.length === 0) return ''
    const inner = lessons
      .map((l) => {
        const body = escapeXml(l.lesson)
        return `<lesson severity="${escapeXml(l.severity)}">\n${body}\n</lesson>`
      })
      .join('\n')
    return `<lessons_learned>\n${inner}\n</lessons_learned>`
  }

  /**
   * Call when a lesson was injected or acted on.
   */
  async markApplied(lessonId: string, sessionId: string): Promise<void> {
    await this.ensureLoaded()
    const lesson = this.findLesson(sessionId, lessonId)
    if (lesson === undefined) return
    lesson.appliedCount += 1
    lesson.lastAppliedAt = nowIso()
  }

  /**
   * Updates outcome tracking after a follow-up verification or user signal.
   */
  async markEffective(lessonId: string, sessionId: string, effective: boolean): Promise<void> {
    await this.ensureLoaded()
    const lesson = this.findLesson(sessionId, lessonId)
    if (lesson === undefined) return
    lesson.confirmedEffective = effective
    console.log(`${LOG} Lesson ${effective ? 'confirmed' : 'refuted'}: ${lessonId}`)
  }

  /**
   * Persisted rolling average update + in-memory mirror.
   * UNCERTAIN: {@link Lesson} has no `successRate` field ÔÇö `confirmedEffective` is set to the latest `improved`
   * flag; rolling average is kept in {@link successRateByLessonId} only.
   */
  async recordApplied(lessonId: string, improved: boolean): Promise<void> {
    await this.ensureLoaded()
    await lessonsAdapter.updateApplied(lessonId, improved)
    const lesson = this.findLessonByIdAcrossSessions(lessonId)
    if (lesson !== undefined) {
      const prevN = lesson.appliedCount
      const prevR = this.successRateByLessonId.get(lessonId) ?? 0
      const n = prevN + 1
      const newR = ((prevR * (n - 1)) + (improved ? 1 : 0)) / n
      lesson.appliedCount = n
      lesson.lastAppliedAt = nowIso()
      this.successRateByLessonId.set(lessonId, newR)
      lesson.confirmedEffective = improved
    }
    console.log(`${LOG} Applied lesson ${lessonId} ÔÇö improved: ${String(improved)}`)
  }

  /**
   * Row count in persistence (may differ from in-memory while async writes are in flight).
   */
  async getPersistedCount(): Promise<number> {
    return lessonsAdapter.count()
  }

  /**
   * Aggregate counts for dashboards or telemetry.
   */
  async getSessionStats(sessionId: string): Promise<{
    totalLessons: number
    byTaskType: Record<string, number>
    bySeverity: Record<string, number>
    appliedLessons: number
    effectiveLessons: number
  }> {
    await this.ensureLoaded()
    const bucket = this.lessons.get(sessionId) ?? []
    const byTaskType: Record<string, number> = {}
    const bySeverity: Record<string, number> = {}
    let appliedLessons = 0
    let effectiveLessons = 0

    for (const l of bucket) {
      byTaskType[l.taskType] = (byTaskType[l.taskType] ?? 0) + 1
      bySeverity[l.severity] = (bySeverity[l.severity] ?? 0) + 1
      if (l.appliedCount > 0) appliedLessons += 1
      if (l.confirmedEffective) effectiveLessons += 1
    }

    return {
      totalLessons: bucket.length,
      byTaskType,
      bySeverity,
      appliedLessons,
      effectiveLessons,
    }
  }

  /**
   * Drops all lessons for a session (e.g. new chat).
   */
  clearSession(sessionId: string): void {
    this.lessons.delete(sessionId)
  }

  /**
   * Finds a lesson by exact stored text (e.g. to mark effectiveness after a passing reflexion).
   */
  async findLessonByExactContent(sessionId: string, lessonText: string): Promise<Lesson | undefined> {
    await this.ensureLoaded()
    const norm = lessonText.trim()
    if (norm.length === 0) return undefined
    return (this.lessons.get(sessionId) ?? []).find((l) => l.lesson === norm)
  }
}

/** Shared {@link LessonsStore} for the app runtime. */
export const lessonsStore = new LessonsStore()

/**
 * Single entry point for model selection: classifies route, applies budget guardrails, records spend.
 *
 * @module reasoning/modelRouter
 */

import { telemetry } from '@/lib/observability/telemetryCollector'

import { costTracker, DEFAULT_BUDGET, type SessionCostSummary } from './costTracker'
import type { ModelTier } from './modelRegistry'
import { ROUTING_RULES, estimateCost, getModelSpec } from './modelRegistry'
import RoutingClassifier, {
  type RoutingDecision,
  type RoutingSignals,
} from './routingClassifier'
import { scratchpadStore } from './scratchpadStore'

const LOG = '[ModelRouter]'

/** Inputs needed to classify and optionally downgrade by spend. */
export interface ModelRouterConfig {
  sessionId: string
  taskType: string
  taskDescription: string
  /** From {@link ComplexityDetector} (0ÔÇô1). */
  complexityScore: number
  /** Reflexion iteration (default 0). */
  iterationNumber?: number
  hasVisionContent?: boolean
  estimatedOutputLength?: RoutingSignals['estimatedOutputLength']
  requiresStructuredOutput?: boolean
}

/** Resolved model + audit fields for callers and telemetry. */
export interface RouterResult {
  model: string
  tier: ModelTier
  reasoningEffort?: string
  decision: RoutingDecision
  costEstimateUSD: number
  sessionCostToDateUSD: number
  isApproachingBudget: boolean
}

function outputTokensForLength(length: RoutingSignals['estimatedOutputLength']): number {
  switch (length) {
    case 'short':
      return 200
    case 'medium':
      return 500
    case 'long':
      return 1000
    case 'very_long':
      return 2000
    default:
      return 500
  }
}

/**
 * Combines {@link RoutingClassifier}, {@link costTracker}, and scratchpad signals.
 */
export default class ModelRouter {
  private readonly classifier: RoutingClassifier

  constructor() {
    this.classifier = new RoutingClassifier()
  }

  private reestimateDecision(
    base: RoutingDecision,
    tier: ModelTier,
    config: ModelRouterConfig,
    rationale: string,
    wasOverridden: boolean,
    overrideReason: string,
    extraSignals: string[],
  ): RoutingDecision {
    const spec = getModelSpec(tier)
    const inputTokens = Math.max(1, Math.floor(config.taskDescription.length / 4))
    const outLen = config.estimatedOutputLength ?? 'medium'
    const outputTokens = outputTokensForLength(outLen)
    const estimatedCostUSD = estimateCost(tier, inputTokens, outputTokens)

    let reasoningEffort: RoutingDecision['reasoningEffort']
    if (tier === 'premium') {
      reasoningEffort = 'high'
    } else if (tier === 'reasoning') {
      reasoningEffort = (config.iterationNumber ?? 0) >= 2 ? 'high' : 'medium'
    } else {
      reasoningEffort = undefined
    }

    return {
      ...base,
      tier,
      model: spec.id,
      rationale,
      estimatedCostUSD,
      reasoningEffort,
      signals: [...base.signals, ...extraSignals],
      wasOverridden,
      overrideReason,
    }
  }

  /**
   * Produces a tier/model for the next LLM call and records routing telemetry.
   */
  async route(config: ModelRouterConfig): Promise<RouterResult> {
    void ROUTING_RULES

    const pad = scratchpadStore.getForSession(config.sessionId)

    const signals: RoutingSignals = {
      taskType: config.taskType,
      taskDescription: config.taskDescription,
      complexityScore: config.complexityScore,
      hasVisionContent: config.hasVisionContent ?? false,
      estimatedOutputLength: config.estimatedOutputLength ?? 'medium',
      requiresStructuredOutput: config.requiresStructuredOutput ?? false,
      iterationNumber: config.iterationNumber ?? 0,
      priorFailures: pad?.deadEnds.length ?? 0,
      sessionPremiumCallCount: costTracker.getPremiumCallCount(config.sessionId),
      sessionReasoningCallCount: costTracker.getReasoningCallCount(config.sessionId),
      scratchpad: pad,
    }

    const decision = await this.classifier.classify(signals)
    let finalDecision: RoutingDecision = decision

    /**
     * NOTE: There are two independent premium caps ÔÇö both must pass
     * for o3 to be used:
     *
     * Cap 1 (RoutingClassifier): MAX_PREMIUM_CALLS_PER_SESSION (default 3)
     *   ÔÇö counts number of o3 API calls in the session
     *   ÔÇö hard override: RoutingClassifier.classify() returns reasoning tier
     *     before even checking complexity if call count is reached
     *
     * Cap 2 (ModelRouter): MAX_PREMIUM_COST_USD (default $1.00)
     *   ÔÇö tracks actual dollar spend on o3 calls via CostTracker
     *   ÔÇö hard override: ModelRouter.route() downgrades premium ÔåÆ reasoning
     *     if dollar spend cap is reached
     *
     * These are different knobs. Cap 1 limits frequency. Cap 2 limits spend.
     * Either cap alone can block premium usage. Both can trigger independently.
     */
    if (decision.tier === 'premium' && costTracker.isPremiumCapReached(config.sessionId)) {
      finalDecision = this.reestimateDecision(
        decision,
        'reasoning',
        config,
        'Budget guardrail: o3 cap reached',
        true,
        'Premium budget cap reached ÔÇö using reasoning tier',
        ['PREMIUM_BUDGET_CAP'],
      )
      console.warn(`${LOG} ÔÜá Premium downgraded ÔÇö cap reached (session: ${config.sessionId})`)
    }

    if (costTracker.isOverBudget(config.sessionId)) {
      if (finalDecision.tier !== 'nano') {
        finalDecision = this.reestimateDecision(
          finalDecision,
          'standard',
          config,
          `${finalDecision.rationale} (session budget guardrail)`,
          true,
          'Session budget limit reached',
          ['SESSION_BUDGET_CAP'],
        )
        console.warn(`${LOG} ÔÜá Downgraded to standard ÔÇö over budget (session: ${config.sessionId})`)
      }
    }

    telemetry.record('model_routed', config.sessionId, {
      tier: finalDecision.tier,
      model: finalDecision.model,
      taskType: config.taskType,
      complexityScore: config.complexityScore,
      wasOverridden: finalDecision.wasOverridden,
      estimatedCostUSD: finalDecision.estimatedCostUSD,
    })

    console.log(
      `${LOG} Routed to ${finalDecision.tier} (${finalDecision.model}) complexity: ${config.complexityScore.toFixed(2)} cost estimate: $${finalDecision.estimatedCostUSD.toFixed(5)}`,
    )

    const sessionSummary = costTracker.getSessionSummary(config.sessionId)
    return {
      model: finalDecision.model,
      tier: finalDecision.tier,
      reasoningEffort: finalDecision.reasoningEffort,
      decision: finalDecision,
      costEstimateUSD: finalDecision.estimatedCostUSD,
      sessionCostToDateUSD: sessionSummary.totalCostUSD,
      isApproachingBudget: sessionSummary.totalCostUSD >= DEFAULT_BUDGET.WARN_THRESHOLD_USD * 0.8,
    }
  }

  /**
   * Persists actual token usage after an API call (updates budgets / caps).
   */
  recordActualUsage(
    sessionId: string,
    tier: ModelTier,
    model: string,
    actualInputTokens: number,
    actualOutputTokens: number,
    taskType: string,
  ): void {
    const rec = costTracker.record(sessionId, tier, model, actualInputTokens, actualOutputTokens, taskType)
    console.log(`${LOG} Recorded ${rec.actualCostUSD.toFixed(5)} for ${tier} call`)
  }

  /** @returns Same shape as {@link costTracker.getSessionSummary}. */
  getSessionCostSummary(sessionId: string): SessionCostSummary {
    return costTracker.getSessionSummary(sessionId)
  }
}

/** Shared {@link ModelRouter} instance. */
export const modelRouter = new ModelRouter()

/**
 * Orchestrates the Reflexion loop: quick critique, full Critic pass, lesson memory,
 * scratchpad updates, telemetry, and enriched retry briefs.
 *
 * @module reasoning/reflexionController
 */

import { v4 as uuidv4 } from 'uuid'

import CriticAgent, { type CritiqueRequest, type Critique } from './criticAgent'
import { lessonsStore } from './lessonsStore'
import type { Lesson } from './lessonsStore'
import { scratchpadStore } from './scratchpadStore'
import { telemetry } from '@/lib/observability/telemetryCollector'

const LOG = '[ReflexionController]'

/** Maximum critique-driven retries before accepting the best attempt. */
export const MAX_REFLEXION_ITERATIONS = 3

/**
 * Outcome of one {@link ReflexionController.reflect} pass.
 */
export interface ReflexionResult {
  critique: Critique
  /** New lesson texts recorded from this critique. */
  lessons: string[]
  shouldRetry: boolean
  /** Worker brief for the next attempt when {@link shouldRetry}; otherwise unchanged. */
  enrichedBrief: string
  /** Highest-priority fix from the critic. */
  retryInstruction: string
  /** Post-reflexion confidence estimate (also written to scratchpad when present). */
  confidenceAfterReflexion: number
  /**
   * Lesson ids selected as relevant this cycle ({@link lessonsStore.getRelevantLessons}).
   * UNCERTAIN: May differ from lessons literally embedded in the worker brief; used as the
   * active set for {@link lessonsStore.recordApplied} feedback.
   */
  activeLessonIds?: string[]
}

function escapeXml(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
}

/**
 * Runs Critic + lesson store + scratchpad hooks for a single Jarvis output attempt.
 */
export default class ReflexionController {
  private readonly sessionId: string
  private readonly criticAgent: CriticAgent
  private readonly iterationHistory: Critique[] = []
  /** Parallel to {@link iterationHistory} when full critique runs; includes quick-pass snapshots. */
  private readonly attemptOutputs: string[] = []
  private readonly attemptScores: number[] = []

  constructor(sessionId: string) {
    this.sessionId = sessionId
    this.criticAgent = new CriticAgent()
  }

  /**
   * Quick check, optional fast-path, full critique, persistence, telemetry, and brief assembly.
   */
  async reflect(
    originalBrief: string,
    output: string,
    request: Omit<CritiqueRequest, 'priorCritiques' | 'iterationNumber'>,
  ): Promise<ReflexionResult> {
    const quick = await this.criticAgent.quickCritique(output, request.taskType)

    if (quick.passed && this.iterationHistory.length === 0 && quick.score >= 0.92) {
      this.attemptOutputs.push(output)
      this.attemptScores.push(quick.score)
      telemetry.record('reflexion_critique', this.sessionId, {
        score: quick.score,
        passed: true,
        issueCount: 0,
        criticalCount: 0,
        iteration: 1,
        taskType: request.taskType,
        lessonsLearnedCount: 0,
        quickCritiqueOnly: true,
      })
      return this._buildHighScoreResult(originalBrief, output, quick.score, request.taskType)
    }

    const critique = await this.criticAgent.critique({
      ...request,
      output,
      priorCritiques: this.iterationHistory,
      iterationNumber: this.iterationHistory.length + 1,
    })

    this.iterationHistory.push(critique)
    this.attemptOutputs.push(output)
    this.attemptScores.push(critique.overallScore)

    const newLessons = await lessonsStore.recordFromCritique(this.sessionId, critique)

    const pad = scratchpadStore.getForSession(this.sessionId)
    if (pad !== null) {
      if (!critique.passed) {
        scratchpadStore.recordDeadEnd(pad.scratchpadId, {
          approach: `Iteration ${String(critique.iterationNumber)}: ${output.slice(0, 100)}`,
          whyItFailed: critique.rootCause,
          avoidanceHint: critique.specificNextAction,
        })
      } else {
        scratchpadStore.addInsight(
          pad.scratchpadId,
          `Output passed critique (score: ${critique.overallScore.toFixed(2)}): ${critique.strengths[0] ?? ''}`,
          'medium',
        )
      }
    }

    telemetry.record('reflexion_critique', this.sessionId, {
      score: critique.overallScore,
      passed: critique.passed,
      issueCount: critique.issues.length,
      criticalCount: critique.issues.filter((i) => i.severity === 'critical').length,
      iteration: critique.iterationNumber,
      taskType: request.taskType,
      lessonsLearnedCount: newLessons.length,
    })

    const shouldRetry = !critique.passed && this.iterationHistory.length < MAX_REFLEXION_ITERATIONS

    const relevantLessons = await lessonsStore.getRelevantLessons({
      sessionId: this.sessionId,
      taskType: request.taskType,
      currentOutput: output,
    })
    for (const l of relevantLessons) {
      await lessonsStore.markApplied(l.id, this.sessionId)
    }

    const activeLessonIds = relevantLessons.map((l) => l.id)

    if (critique.passed) {
      for (const id of activeLessonIds) {
        void lessonsStore.recordApplied(id, true).catch((err: unknown) => {
          console.error(`${LOG} recordApplied failed`, err)
        })
      }
    } else if (!shouldRetry) {
      for (const id of activeLessonIds) {
        void lessonsStore.recordApplied(id, false).catch((err: unknown) => {
          console.error(`${LOG} recordApplied failed`, err)
        })
      }
    }

    const enrichedBrief = shouldRetry
      ? this._buildRetryBrief(originalBrief, output, critique, relevantLessons)
      : originalBrief

    const confidenceAfterReflexion = critique.passed
      ? Math.min(critique.overallScore + 0.1, 1.0)
      : Math.max(critique.overallScore - 0.1, 0.1)

    if (pad !== null) {
      scratchpadStore.updateConfidence(pad.scratchpadId, confidenceAfterReflexion)
    }

    return {
      critique,
      lessons: newLessons.map((l) => l.lesson),
      shouldRetry,
      enrichedBrief,
      retryInstruction: critique.specificNextAction,
      confidenceAfterReflexion,
      activeLessonIds,
    }
  }

  private _buildRetryBrief(
    originalBrief: string,
    failedOutput: string,
    critique: Critique,
    relevantLessons: Lesson[],
  ): string {
    const criticalBlock = critique.issues
      .filter((i) => i.severity === 'critical')
      .map((i) => {
        const loc = i.location != null ? `\n      Location: ${escapeXml(i.location)}` : ''
        return `- [${escapeXml(i.category)}] ${escapeXml(i.description)}\n      Fix: ${escapeXml(i.suggestion)}${loc}`
      })
      .join('\n')

    const majorBlock = critique.issues
      .filter((i) => i.severity === 'major')
      .map((i) => `- ${escapeXml(i.description)} ÔåÆ ${escapeXml(i.suggestion)}`)
      .join('\n')

    const lessonsXml = lessonsStore.formatForPrompt(relevantLessons)

    return `${originalBrief}

<reflexion_context>
<iteration>${String(critique.iterationNumber)}</iteration>

<critique_summary>
Score: ${critique.overallScore.toFixed(2)}/1.0
Root cause: ${escapeXml(critique.rootCause)}
Most important fix: ${escapeXml(critique.specificNextAction)}
</critique_summary>

<critical_issues>
${criticalBlock}
</critical_issues>

<major_issues>
${majorBlock}
</major_issues>

${lessonsXml}

<previous_attempt>
${escapeXml(failedOutput.slice(0, 1500))}
</previous_attempt>

<instruction>
Address ALL critical issues above. Then address major issues.
Do not repeat the previous attempt ÔÇö produce a completely corrected version. Return COMPLETE output, not just the fixed parts.
</instruction>
</reflexion_context>
`
  }

  /**
   * Fast path when the first quick critique is very high; skips full LLM critique.
   */
  private _buildHighScoreResult(
    originalBrief: string,
    _output: string,
    score: number,
    taskType: string,
  ): ReflexionResult {
    const confidenceAfterReflexion = Math.min(score + 0.1, 1.0)
    const pad = scratchpadStore.getForSession(this.sessionId)
    if (pad !== null) {
      scratchpadStore.updateConfidence(pad.scratchpadId, confidenceAfterReflexion)
    }

    const critique: Critique = {
      id: uuidv4(),
      taskType,
      iterationNumber: 1,
      overallScore: score,
      passed: true,
      issues: [],
      strengths: ['Quick critique score very high; full critique skipped.'],
      rootCause: 'N/A ÔÇö output met high quick-critique threshold.',
      specificNextAction: 'None required.',
      lessonsForFuture: [],
      timestamp: new Date().toISOString(),
    }

    return {
      critique,
      lessons: [],
      shouldRetry: false,
      enrichedBrief: originalBrief,
      retryInstruction: 'None required.',
      confidenceAfterReflexion,
    }
  }

  /**
   * Picks the stored attempt whose critique score was highest among the given output strings.
   */
  getBestOutput(outputs: string[]): string {
    if (outputs.length === 0) {
      return ''
    }
    let bestScore = -Infinity
    let bestText: string | undefined
    for (let i = 0; i < this.attemptOutputs.length; i++) {
      const text = this.attemptOutputs[i]
      const sc = this.attemptScores[i]
      if (text === undefined || sc === undefined) continue
      if (!outputs.includes(text)) continue
      if (sc > bestScore) {
        bestScore = sc
        bestText = text
      }
    }
    return bestText ?? outputs[outputs.length - 1]!
  }

  /**
   * Critiques recorded across reflexion iterations (copy).
   */
  getIterationHistory(): Critique[] {
    return [...this.iterationHistory]
  }

  /** Clears iteration state for a new task. */
  reset(): void {
    this.iterationHistory.length = 0
    this.attemptOutputs.length = 0
    this.attemptScores.length = 0
    console.log(`${LOG} Reset for new task`)
  }
}

/**
 * Maps task signals to a {@link ModelTier} using free rules first, then a tiny LLM gate for premium.
 *
 * @module reasoning/routingClassifier
 */

import OpenAI from 'openai'

import type { ComplexityAssessment } from './complexityDetector'
import type { CoTScratchpad } from './cotScratchpad'
import type { ModelSpec, ModelTier } from './modelRegistry'
import { MODEL_REGISTRY, ROUTING_RULES, estimateCost, getModelSpec } from './modelRegistry'

const LOG = '[RoutingClassifier]'

const PREMIUM_CONFIRM_TIMEOUT_MS = 3000

/** Inputs collected upstream (complexity, session usage, media, etc.). */
export interface RoutingSignals {
  taskType: string
  taskDescription: string
  /** Typically aligned with {@link ComplexityAssessment.score}. */
  complexityScore: number
  hasVisionContent: boolean
  estimatedOutputLength: 'short' | 'medium' | 'long' | 'very_long'
  requiresStructuredOutput: boolean
  iterationNumber: number
  priorFailures: number
  sessionPremiumCallCount: number
  sessionReasoningCallCount: number
  scratchpad?: CoTScratchpad | null
}

/** Resolved tier, model id, cost estimate, and audit trail. */
export interface RoutingDecision {
  tier: ModelTier
  /** Same shape as {@link ModelSpec.id} for the chosen tier. */
  model: string
  reasoningEffort?: 'low' | 'medium' | 'high'
  rationale: string
  estimatedCostUSD: number
  signals: string[]
  wasOverridden: boolean
  overrideReason?: string
}

function outputTokensForLength(length: RoutingSignals['estimatedOutputLength']): number {
  switch (length) {
    case 'short':
      return 200
    case 'medium':
      return 500
    case 'long':
      return 1000
    case 'very_long':
      return 2000
    default:
      return 500
  }
}

function clamp01(n: number): number {
  if (Number.isNaN(n) || !Number.isFinite(n)) return 0
  return Math.max(0, Math.min(1, n))
}

/**
 * Picks an OpenAI model tier for a task without blocking the pipeline on failures.
 */
export default class RoutingClassifier {
  private readonly openai: OpenAI
  private readonly model: string

  /**
   * @param model - Fast model for borderline premium confirmation (default `gpt-4o-mini`).
   */
  constructor(model: string = 'gpt-4o-mini') {
    this.openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY ?? '' })
    this.model = model
  }

  /**
   * Applies hard routes, adjusts complexity heuristically, then optionally confirms premium via LLM.
   */
  async classify(signals: RoutingSignals): Promise<RoutingDecision> {
    try {
      return await this.classifyInner(signals)
    } catch (err: unknown) {
      console.warn(`${LOG} Classification failed, defaulting to standard`, err)
      return this._buildDecision(
        'standard',
        'Classifier error ÔÇö safe default',
        signals,
        true,
        'classification threw',
        ['error_fallback'],
      )
    }
  }

  private async classifyInner(signals: RoutingSignals): Promise<RoutingDecision> {
    /**
     * NOTE: ALWAYS_NANO routes (conversational, clarification_needed) return
     * immediately from the RULE-BASED section of classify() ÔÇö before the
     * complexity score bands and before _confirmPremiumNeeded().
     * They DO enter classify() itself, but exit before any LLM call.
     * "Never reach LLM classification" means they never reach the
     * _confirmPremiumNeeded LLM gate ÔÇö not that they bypass classify().
     */
    if (ROUTING_RULES.ALWAYS_NANO.includes(signals.taskType)) {
      return this._buildDecision(
        'nano',
        'Hard rule: always nano for this route',
        signals,
        true,
        `taskType ${signals.taskType} always uses nano`,
        ['ALWAYS_NANO'],
      )
    }

    if (ROUTING_RULES.ALWAYS_STANDARD.includes(signals.taskType)) {
      return this._buildDecision(
        'standard',
        'Hard rule: always standard for this route',
        signals,
        true,
        `taskType ${signals.taskType} always uses standard`,
        ['ALWAYS_STANDARD'],
      )
    }

    if (signals.hasVisionContent && signals.taskType !== 'image_task') {
      return this._buildDecision(
        'standard',
        'Vision content detected ÔÇö gpt-4o required',
        signals,
        true,
        'Vision requires standard or premium tier',
        ['VISION_CONTENT'],
      )
    }

    const premiumCappedByCount =
      signals.sessionPremiumCallCount >= ROUTING_RULES.MAX_PREMIUM_CALLS_PER_SESSION
    const neverPremiumRoute = ROUTING_RULES.NEVER_PREMIUM.includes(signals.taskType)
    const preventPremium = premiumCappedByCount || neverPremiumRoute

    const ruleSignals: string[] = []
    let complexityScore = clamp01(signals.complexityScore)

    if (signals.priorFailures >= 2) {
      complexityScore = Math.min(complexityScore + 0.2, 1)
      ruleSignals.push(`${String(signals.priorFailures)} prior failures ÔåÆ escalate`)
    }

    if (signals.iterationNumber >= 2) {
      complexityScore = Math.min(complexityScore + 0.15, 1)
      ruleSignals.push(`Reflexion iteration ${String(signals.iterationNumber)} ÔåÆ escalate`)
    }

    if (signals.estimatedOutputLength === 'very_long') {
      complexityScore = Math.min(complexityScore + 0.1, 1)
      ruleSignals.push('Very long output required ÔåÆ escalate')
    }

    if (premiumCappedByCount) {
      ruleSignals.push(
        `Premium session cap (${String(ROUTING_RULES.MAX_PREMIUM_CALLS_PER_SESSION)})`,
      )
    }
    if (neverPremiumRoute) {
      ruleSignals.push('NEVER_PREMIUM route')
    }

    if (signals.requiresStructuredOutput) {
      ruleSignals.push('Structured output requested')
    }

    if (complexityScore <= ROUTING_RULES.NANO_MAX_COMPLEXITY) {
      return this._buildDecision('nano', 'Low complexity', signals, false, undefined, ruleSignals)
    }

    if (complexityScore <= ROUTING_RULES.STANDARD_MAX_COMPLEXITY) {
      return this._buildDecision('standard', 'Moderate complexity', signals, false, undefined, ruleSignals)
    }

    if (complexityScore <= ROUTING_RULES.REASONING_MAX_COMPLEXITY) {
      return this._reasoningOrStandardDowngrade(
        'High complexity',
        signals,
        false,
        undefined,
        ruleSignals,
      )
    }

    let premiumJustified = false
    try {
      premiumJustified = await this._confirmPremiumNeeded(signals)
    } catch (err: unknown) {
      console.warn(`${LOG} Premium confirmation failed, defaulting to reasoning tier`, err)
      premiumJustified = false
    }

    if (premiumJustified && !preventPremium) {
      return this._buildDecision(
        'premium',
        'Very high complexity ÔÇö premium justified',
        signals,
        false,
        undefined,
        ruleSignals,
      )
    }

    if (premiumJustified && preventPremium) {
      return this._reasoningOrStandardDowngrade(
        'Very high complexity ÔÇö premium disallowed by guardrail',
        signals,
        true,
        premiumCappedByCount
          ? `Premium cap (${String(ROUTING_RULES.MAX_PREMIUM_CALLS_PER_SESSION)} calls)`
          : 'Route may not use premium',
        ruleSignals,
      )
    }

    return this._reasoningOrStandardDowngrade(
      'High complexity but premium not confirmed',
      signals,
      false,
      undefined,
      ruleSignals,
    )
  }

  /** When reasoning tier is chosen but session reasoning calls are exhausted, use standard. */
  private _reasoningOrStandardDowngrade(
    rationale: string,
    signals: RoutingSignals,
    wasOverridden: boolean,
    overrideReason: string | undefined,
    ruleSignals: string[],
  ): RoutingDecision {
    if (signals.sessionReasoningCallCount >= ROUTING_RULES.MAX_REASONING_CALLS_PER_SESSION) {
      return this._buildDecision(
        'standard',
        `${rationale} (reasoning tier capped)`,
        signals,
        true,
        overrideReason ?? `reasoning calls >= ${String(ROUTING_RULES.MAX_REASONING_CALLS_PER_SESSION)}`,
        [...ruleSignals, 'REASONING_SESSION_CAP'],
      )
    }
    return this._buildDecision('reasoning', rationale, signals, wasOverridden, overrideReason, ruleSignals)
  }

  private async _confirmPremiumNeeded(signals: RoutingSignals): Promise<boolean> {
    const user = `Answer YES or NO only.
Is this task complex enough to require o3 (the most powerful reasoning model available)? o3 should only be used for tasks where GPT-4o would likely fail due to reasoning complexity.

Task: ${signals.taskDescription.slice(0, 300)}
Complexity score: ${String(signals.complexityScore)}
Prior failures: ${String(signals.priorFailures)}
Task type: ${signals.taskType}`

    const completionPromise = this.openai.chat.completions.create({
      model: this.model,
      temperature: 0,
      max_tokens: 8,
      messages: [{ role: 'user', content: user }],
    })

    const result = await Promise.race([
      completionPromise.then((r) => ({ kind: 'ok' as const, r })),
      new Promise<{ kind: 'timeout' }>((resolve) =>
        setTimeout(() => resolve({ kind: 'timeout' }), PREMIUM_CONFIRM_TIMEOUT_MS),
      ),
    ])

    if (result.kind === 'timeout') {
      console.warn(`${LOG} Premium confirmation timed out`)
      return false
    }

    const text = result.r.choices[0]?.message?.content?.trim() ?? ''
    return text.toUpperCase().startsWith('YES')
  }

  private _buildDecision(
    tier: ModelTier,
    rationale: string,
    signals: RoutingSignals,
    wasOverridden: boolean,
    overrideReason?: string,
    extraSignals: string[] = [],
  ): RoutingDecision {
    void MODEL_REGISTRY[tier]
    const spec = getModelSpec(tier)
    const inputTokens = Math.max(1, Math.floor(signals.taskDescription.length / 4))
    const outputTokens = outputTokensForLength(signals.estimatedOutputLength)

    let reasoningEffort: 'low' | 'medium' | 'high' | undefined
    if (tier === 'premium') {
      reasoningEffort = 'high'
    } else if (tier === 'reasoning') {
      reasoningEffort = signals.iterationNumber >= 2 ? 'high' : 'medium'
    }

    const estimatedCostUSD = estimateCost(tier, inputTokens, outputTokens)
    const outSignals = [...extraSignals]

    return {
      tier,
      model: spec.id,
      reasoningEffort,
      rationale,
      estimatedCostUSD,
      signals: outSignals,
      wasOverridden,
      overrideReason,
    }
  }
}

/**
 * System 2 ÔÇö Uncertainty-Aware Reflection (UAR) for the Dual-Process AUQ pipeline
 * (arXiv:2601.15703). Activates when verbalized confidence ─ë_t falls below ¤ä
 * ({@link CONFIDENCE_THRESHOLDS.UAR_TRIGGER}), using uncertainty explanations ├¬_t
 * as cues for targeted meta-reasoning.
 *
 * @module reasoning/uncertaintyResolver
 */

import OpenAI from 'openai'

import type { ConfidenceScore, ConfidenceVector, ConfidenceAction } from './confidenceTypes'
import { CONFIDENCE_THRESHOLDS } from './confidenceTypes'
import { lessonsStore } from './lessonsStore'
import { modelRouter } from './modelRouter'
import type { ModelTier } from './modelRegistry'
import { scratchpadStore } from './scratchpadStore'

const LOG = '[UncertaintyResolver]'

const DIAGNOSE_MODEL = 'gpt-4o-mini'
const REEVAL_MODEL = 'gpt-4o-mini'

/** Outcome of a UAR cycle (clarification, escalation, or self-resolution). */
export interface UARResult {
  triggered: boolean
  originalScore: number
  /** Confidence after resolution attempt. */
  resolvedScore: number
  /** Human-readable strategy label. */
  resolutionStrategy: string
  /** Updated output when UAR rewrote the answer. */
  resolvedContent?: string
  /** Populated when {@link resolutionStrategy} is `request_clarification`. */
  clarificationQuestion?: string
  /** Populated when {@link resolutionStrategy} is `escalate_model`. */
  modelEscalation?: boolean
  /** Audit trail of UAR steps. */
  resolutionSteps: string[]
  /** Lessons persisted for future turns. */
  lessonsExtracted: string[]
}

/** Parsed diagnosis from {@link UncertaintyResolver._diagnose}. */
export interface UARDiagnosis {
  rootCause: string
  resolutionPath: string
  canSelfResolve: boolean
  resolutionSteps: string[]
}

function asStringArray(v: unknown): string[] {
  if (!Array.isArray(v)) return []
  return v.filter((x): x is string => typeof x === 'string' && x.trim().length > 0)
}

function parseDiagnosisJson(text: string): UARDiagnosis {
  const raw = text.trim()
  const parsed = JSON.parse(raw) as Record<string, unknown>
  return {
    rootCause: typeof parsed.rootCause === 'string' ? parsed.rootCause : 'Unknown root cause',
    resolutionPath:
      typeof parsed.resolutionPath === 'string' ? parsed.resolutionPath : 'No path specified',
    canSelfResolve: parsed.canSelfResolve === true,
    resolutionSteps: asStringArray(parsed.resolutionSteps),
  }
}

function parseConfidenceNumber(text: string): number {
  const m = text.match(/-?\d+(?:\.\d+)?(?:e[+-]?\d+)?/i)
  if (m === null || m[0] === undefined) return Number.NaN
  return Number(m[0])
}

/**
 * Targeted reflection and repair when System 1 confidence is below ¤ä.
 */
export default class UncertaintyResolver {
  private readonly openai: OpenAI
  private readonly model: string

  /**
   * @param model - Primary model for self-resolution (default `gpt-4o`).
   */
  constructor(model: string = 'gpt-4o') {
    this.openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY ?? '' })
    this.model = model
  }

  /**
   * Runs diagnosis ÔåÆ optional self-resolve ÔåÆ re-score ÔåÆ lessons ÔåÆ scratchpad updates.
   */
  async resolve(
    confidence: ConfidenceScore,
    originalOutput: string,
    taskDescription: string,
    sessionId: string,
    taskType: string,
  ): Promise<UARResult> {
    if (confidence.scalar >= CONFIDENCE_THRESHOLDS.UAR_TRIGGER) {
      return {
        triggered: false,
        originalScore: confidence.scalar,
        resolvedScore: confidence.scalar,
        resolutionStrategy: 'no_action',
        resolutionSteps: [],
        lessonsExtracted: [],
      }
    }

    console.log(
      `${LOG} UAR triggered ÔÇö confidence ${String(confidence.scalar)} below threshold ${String(CONFIDENCE_THRESHOLDS.UAR_TRIGGER)}`,
    )

    const diagnosis = await this._diagnose(confidence, taskDescription, taskType, sessionId)

    if (confidence.scalar < CONFIDENCE_THRESHOLDS.HARD_BLOCK) {
      return await this._buildClarificationResult(confidence, diagnosis, sessionId, taskType)
    }

    if (!diagnosis.canSelfResolve) {
      return await this._buildEscalationResult(confidence, diagnosis, sessionId, taskType)
    }

    const resolvedOutput = await this._selfResolve(
      confidence,
      originalOutput,
      taskDescription,
      taskType,
      diagnosis,
      sessionId,
    )

    const newConfidence = await this._quickReEvaluate(resolvedOutput, taskDescription, sessionId)
    const { lessonsExtracted: lessons, lessonIds } = await this._extractLessons(
      confidence,
      diagnosis,
      sessionId,
      taskType,
    )
    const confidenceImproved = newConfidence > confidence.scalar + 0.1
    for (const id of lessonIds) {
      void lessonsStore.recordApplied(id, confidenceImproved).catch((err: unknown) => {
        console.error(`${LOG} recordApplied failed`, err)
      })
    }

    const pad = scratchpadStore.getForSession(sessionId)
    if (pad !== null) {
      scratchpadStore.addInsight(
        pad.scratchpadId,
        `UAR resolved uncertainty: ${diagnosis.rootCause} ÔåÆ ${diagnosis.resolutionPath}`,
        'high',
      )
      for (const gap of confidence.knowledgeGaps) {
        if (gap.trim().length > 0) {
          scratchpadStore.addOpenQuestion(pad.scratchpadId, gap)
        }
      }
    }

    return {
      triggered: true,
      originalScore: confidence.scalar,
      resolvedScore: newConfidence,
      resolutionStrategy: 'self_resolved',
      resolvedContent: resolvedOutput,
      resolutionSteps: diagnosis.resolutionSteps,
      lessonsExtracted: lessons,
    }
  }

  private async _diagnose(
    confidence: ConfidenceScore,
    taskDescription: string,
    taskType: string,
    sessionId: string,
  ): Promise<UARDiagnosis> {
    const system = `Diagnose why an AI agent has low confidence in its output.
Determine if it can self-resolve or needs user input.

Return JSON only:
{"rootCause": "...", "resolutionPath": "...",
 "canSelfResolve": true or false, "resolutionSteps": ["step1", ...]}`

    const user = `Task: ${taskDescription}
Task type: ${taskType}
Confidence: ${String(confidence.scalar)}
Uncertainty factors: ${confidence.uncertaintyFactors.join(', ')}
Knowledge gaps: ${confidence.knowledgeGaps.join(', ')}`

    try {
      const completion = await this.openai.chat.completions.create({
        model: DIAGNOSE_MODEL,
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: user },
        ],
        temperature: 0.2,
        max_tokens: 500,
        response_format: { type: 'json_object' },
        stream: false,
      })
      modelRouter.recordActualUsage(
        sessionId,
        'nano' as ModelTier,
        DIAGNOSE_MODEL,
        completion.usage?.prompt_tokens ?? 0,
        completion.usage?.completion_tokens ?? 0,
        'uar_resolution',
      )
      const text = completion.choices[0]?.message?.content?.trim() ?? '{}'
      return parseDiagnosisJson(text)
    } catch (err: unknown) {
      console.warn(`${LOG} Diagnosis failed, using safe defaults`, err)
      return {
        rootCause: 'Diagnosis unavailable',
        resolutionPath: 'Request clarification or escalate',
        canSelfResolve: false,
        resolutionSteps: ['diagnosis_failed'],
      }
    }
  }

  private async _selfResolve(
    confidence: ConfidenceScore,
    originalOutput: string,
    taskDescription: string,
    taskType: string,
    diagnosis: UARDiagnosis,
    sessionId: string,
  ): Promise<string> {
    const system = `You are resolving uncertainty in a previous output.
Focus specifically on the uncertainty factors identified.
Do NOT rewrite parts that were already confident.
Only address the specific gaps and uncertainties.`

    const factors =
      confidence.uncertaintyFactors.length > 0
        ? confidence.uncertaintyFactors.map((f) => `- ${f}`).join('\n')
        : '- (none listed)'
    const gaps =
      confidence.knowledgeGaps.length > 0
        ? confidence.knowledgeGaps.map((g) => `- ${g}`).join('\n')
        : '- (none listed)'

    const user = `Task type: ${taskType}
Task: ${taskDescription.slice(0, 800)}

Original output:
${originalOutput.slice(0, 2000)}

Uncertainty factors to address:
${factors}

Knowledge gaps to fill:
${gaps}

Resolution path: ${diagnosis.resolutionPath}

Produce an improved output that addresses these uncertainties.`

    try {
      const completion = await this.openai.chat.completions.create({
        model: this.model,
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: user },
        ],
        temperature: 0.3,
        max_tokens: 4096,
        stream: false,
      })
      modelRouter.recordActualUsage(
        sessionId,
        'standard' as ModelTier,
        this.model,
        completion.usage?.prompt_tokens ?? 0,
        completion.usage?.completion_tokens ?? 0,
        'uar_resolution',
      )
      return completion.choices[0]?.message?.content?.trim() ?? originalOutput
    } catch (err: unknown) {
      console.warn(`${LOG} Self-resolve failed, returning original output`, err)
      return originalOutput
    }
  }

  private async _quickReEvaluate(
    output: string,
    taskDescription: string,
    sessionId?: string,
  ): Promise<number> {
    const user = `Rate confidence in the following output for the task (0.0 = none, 1.0 = fully confident).
Return only a number between 0 and 1, no other text.

Task: ${taskDescription.slice(0, 400)}
Output: ${output.slice(0, 1200)}`

    try {
      const completion = await this.openai.chat.completions.create({
        model: REEVAL_MODEL,
        messages: [{ role: 'user', content: user }],
        temperature: 0,
        max_tokens: 16,
        stream: false,
      })
      if (sessionId !== undefined && sessionId.length > 0) {
        modelRouter.recordActualUsage(
          sessionId,
          'nano' as ModelTier,
          REEVAL_MODEL,
          completion.usage?.prompt_tokens ?? 0,
          completion.usage?.completion_tokens ?? 0,
          'uar_resolution',
        )
      }
      const text = completion.choices[0]?.message?.content?.trim() ?? ''
      const n = parseConfidenceNumber(text)
      if (!Number.isFinite(n)) return 0.75
      return Math.min(1, Math.max(0, n))
    } catch {
      return 0.75
    }
  }

  private async _buildClarificationResult(
    confidence: ConfidenceScore,
    diagnosis: UARDiagnosis,
    sessionId: string,
    taskType: string,
  ): Promise<UARResult> {
    const gaps = confidence.knowledgeGaps.filter((g) => g.trim().length > 0)
    const top = gaps.slice(0, 2)
    const clarificationQuestion =
      top.length > 0
        ? `To complete this accurately, I need to know: ${top.join(' and ')}`
        : `To complete this accurately, I need more detail: ${diagnosis.rootCause}`

    const { lessonsExtracted: lessons } = await this._extractLessons(
      confidence,
      diagnosis,
      sessionId,
      taskType,
    )

    return {
      triggered: true,
      originalScore: confidence.scalar,
      resolvedScore: confidence.scalar,
      resolutionStrategy: 'request_clarification',
      clarificationQuestion,
      resolutionSteps: [
        `Diagnosed: ${diagnosis.rootCause}`,
        `Planned path: ${diagnosis.resolutionPath}`,
        'Blocked: confidence below hard threshold ÔÇö clarification required',
      ],
      lessonsExtracted: lessons,
    }
  }

  private async _buildEscalationResult(
    confidence: ConfidenceScore,
    diagnosis: UARDiagnosis,
    sessionId: string,
    taskType: string,
  ): Promise<UARResult> {
    const { lessonsExtracted: lessons } = await this._extractLessons(
      confidence,
      diagnosis,
      sessionId,
      taskType,
    )
    return {
      triggered: true,
      originalScore: confidence.scalar,
      resolvedScore: confidence.scalar,
      resolutionStrategy: 'escalate_model',
      modelEscalation: true,
      resolutionSteps: [
        `Diagnosed: ${diagnosis.rootCause}`,
        `Cannot self-resolve: ${diagnosis.resolutionPath}`,
        'Recommend model tier upgrade on retry',
      ],
      lessonsExtracted: lessons,
    }
  }

  private async _extractLessons(
    confidence: ConfidenceScore,
    diagnosis: UARDiagnosis,
    sessionId: string,
    taskType: string,
  ): Promise<{ lessonsExtracted: string[]; lessonIds: string[] }> {
    const lessonsExtracted: string[] = []
    const lessonIds: string[] = []
    const factors =
      confidence.uncertaintyFactors.length > 0
        ? confidence.uncertaintyFactors
        : [diagnosis.rootCause]

    for (const factor of factors) {
      const t = factor.trim()
      if (t.length === 0) continue
      const lesson = `When handling ${taskType}, be explicit about ${t}`
      const row = await lessonsStore.recordManual(sessionId, lesson, taskType, 'minor', 'user_correction')
      lessonsExtracted.push(lesson)
      lessonIds.push(row.id)
    }

    return { lessonsExtracted, lessonIds }
  }
}
